"""
Parameterized generator for GH1203_wandb_11226.

Source PR:    https://github.com/wandb/wandb/pull/11226
Source Issue: N/A

Seed varies: renames 'agent' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH1203_wandb_11226'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH1203_wandb_11226'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('agent', 'agent' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH1203_wandb_11226',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'wandb/wandb',
                "pr_number": 11226,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/wandb/wandb/pull/11226",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'CHANGELOG.unreleased.md': '# Unreleased changes\n\nAdd here any changes made in a PR that are relevant to end users. Allowed sections:\n\n- Added - for new features.\n- Changed - for changes in existing functionality.\n- Deprecated - for soon-to-be removed features.\n- Removed - for now removed features.\n- Fixed - for any bug fixes.\n- Security - in case of vulnerabilities.\n\nSection headings should be at level 3 (e.g. `### Added`).\n\n## Unreleased\n',
            'tests/system_tests/test_sweep/test_sweep_scheduler.py': '"""Sweep tests."""\n\nimport asyncio\nfrom typing import Dict\nfrom unittest.mock import Mock, patch\n\nimport pytest\nimport wandb\nfrom wandb.apis import internal, public\nfrom wandb.errors import CommError\nfrom wandb.sdk.launch.sweeps import SchedulerError, load_scheduler\nfrom wandb.sdk.launch.sweeps.scheduler import (\n    RunState,\n    Scheduler,\n    SchedulerState,\n    SweepRun,\n)\nfrom wandb.sdk.launch.sweeps.scheduler_sweep import SweepScheduler\nfrom wandb.sdk.launch.sweeps.utils import construct_scheduler_args\n\nfrom .test_wandb_sweep import SWEEP_CONFIG_RANDOM\n\n\ndef test_sweep_scheduler_load():\n    _scheduler = load_scheduler("wandb")\n    assert _scheduler == SweepScheduler\n    with pytest.raises(SchedulerError):\n        load_scheduler("unknown")\n\n\ndef _patch_wandb_run(monkeypatch, config=None):\n    if not config:\n        config = {"launch": {"overrides": {"run_config": {}}}}\n    mocked_run = Mock(["finish", "id"])\n    mocked_run.config = config\n    mocked_run.id = "sweep-scheduler"\n    monkeypatch.setattr(\n        "wandb.sdk.launch.sweeps.scheduler.Scheduler._init_wandb_run",\n        lambda _x: mocked_run,\n    )\n\n\n@patch.multiple(Scheduler, __abstractmethods__=set())\ndef test_sweep_scheduler_entity_project_sweep_id(\n    user,\n    monkeypatch,\n):\n    sweep_config = SWEEP_CONFIG_RANDOM\n    _patch_wandb_run(monkeypatch)\n    _entity = user\n    _project = "test-project"\n    api = internal.Api()\n    # Entity, project, and sweep should be everything you need to create a scheduler\n    sweep_id = wandb.sweep(sweep_config, entity=_entity, project=_project)\n    _ = Scheduler(\n        api, sweep_id=sweep_id, entity=_entity, project=_project, num_workers=1\n    )\n    # Bogus sweep id should result in error\n    with pytest.raises(SchedulerError):\n        _ = Scheduler(\n            api,\n            sweep_id="foo-sweep-id",\n            entity=_entity,\n            project=_project,\n        )\n\n\ndef test_sweep_scheduler_start_failed(user, monkeypatch):\n    _patch_wandb_run(monkeypatch)\n    sweep_config = SWEEP_CONFIG_RANDOM\n    _entity = user\n    _project = "test-project"\n    api = internal.Api()\n    # Entity, project, and sweep should be everything you need to create a scheduler\n    sweep_id = wandb.sweep(sweep_config, entity=_entity, project=_project)\n\n    api.stop_run = lambda run_id: True\n    scheduler = SweepScheduler(api, sweep_id=sweep_id, entity=_entity, project=_project)\n\n    # also test stop run\n    assert scheduler._stop_run("nonexistent-run") is False\n    scheduler._runs["existing-run-no-queued"] = SweepRun(\n        id="existing-run-no-queued", state=RunState.RUNNING, worker_id=0\n    )\n    assert scheduler._stop_run("existing-run-no-queued") is False\n    scheduler._runs["existing-run-dead"] = SweepRun(\n        id="existing-run-dead",\n        state=RunState.CRASHED,\n        worker_id=1,\n        queued_run=Mock(spec=public.QueuedRun),\n    )\n    assert scheduler._stop_run("existing-run-dead") is True\n    scheduler._runs["existing-run"] = SweepRun(\n        id="existing-run",\n        worker_id=2,\n        queued_run=Mock(spec=public.QueuedRun),\n    )\n    assert scheduler._stop_run("existing-run")\n\n    scheduler.state = SchedulerState.CANCELLED\n    scheduler.start()\n    # should not be able to start a cancelled scheduler\n    assert scheduler.state == SchedulerState.CANCELLED\n\n\ndef test_sweep_scheduler_runcap(user, monkeypatch):\n    launch_config = {"launch": {}}\n    _patch_wandb_run(monkeypatch, launch_config)\n    sweep_config = SWEEP_CONFIG_RANDOM  # 3 total runs\n    sweep_config["run_cap"] = 2\n    _entity = user\n    _project = "test-project"\n\n    def mock_launch_add(*args, **kwargs):\n        mock = Mock(spec=public.QueuedRun)\n        mock.args = Mock(return_value=args)\n        return mock\n\n    monkeypatch.setattr(\n        "wandb.sdk.launch._launch_add._launch_add",\n        mock_launch_add,\n    )\n\n    def mock_run_add_to_launch_queue(self, *args, **kwargs):\n        self._runs["foo_run"] = SweepRun(\n            id="foo_run",\n            state=RunState.PENDING,\n            worker_id=0,\n            args={"foo": {"value": 1}},\n        )\n        self._add_to_launch_queue(self._runs["foo_run"])\n        self.state = SchedulerState.COMPLETED\n        self.exit()\n\n    monkeypatch.setattr(\n        "wandb.sdk.launch.sweeps.scheduler.Scheduler._get_next_sweep_run",\n        mock_run_add_to_launch_queue,\n    )\n\n    def mock_get_run_state(*args, **kwargs):\n        if args[2] == "sweep-scheduler":\n            return "running"\n        return "finished"\n\n    # Entity, project, and sweep should be everything you need to create a scheduler\n    api = internal.Api()\n    api.get_run_state = mock_get_run_state\n    sweep_id = wandb.sweep(sweep_config, entity=_entity, project=_project)\n    scheduler = SweepScheduler(\n        api,\n        sweep_id=sweep_id,\n        entity=_entity,\n        project=_project,\n        image_uri="fake-image:latest",\n        queue="queue",\n        num_workers=1,\n    )\n\n    assert scheduler.at_runcap is False\n    scheduler.start()\n    assert scheduler.at_runcap\n    assert scheduler._num_runs_launched == 2\n\n\ndef test_sweep_scheduler_sweep_id_no_job(user, monkeypatch):\n    _patch_wandb_run(monkeypatch)\n    sweep_config = SWEEP_CONFIG_RANDOM\n\n    def mock_run_complete_scheduler(self, *args, **kwargs):\n        self.state = SchedulerState.COMPLETED\n\n    monkeypatch.setattr(\n        "wandb.sdk.launch.sweeps.scheduler.Scheduler.run",\n        mock_run_complete_scheduler,\n    )\n    _entity = user\n    _project = "test-project"\n    api = internal.Api()\n    # Entity, project, and sweep\n    sweep_id = wandb.sweep(sweep_config, entity=_entity, project=_project)\n    # No job\n    scheduler = SweepScheduler(\n        api, sweep_id=sweep_id, entity=_entity, project=_project, num_workers=1\n    )\n    scheduler.start()  # should raise no job found\n    assert scheduler.state == SchedulerState.FAILED\n\n\ndef test_sweep_scheduler_sweep_id_with_job(user, monkeypatch):\n    _patch_wandb_run(monkeypatch)\n    sweep_config = SWEEP_CONFIG_RANDOM\n\n    # make a job\n    run = wandb.init()\n    job_artifact = run._log_job_artifact_with_image("ljadnfakehbbr", args=[])\n    job_name = job_artifact.wait().name\n    sweep_config["job"] = job_name\n    run.finish()\n\n    def mock_run_complete_scheduler(self, *args, **kwargs):\n        self.state = SchedulerState.COMPLETED\n\n    monkeypatch.setattr(\n        "wandb.sdk.launch.sweeps.scheduler.Scheduler.run",\n        mock_run_complete_scheduler,\n    )\n\n    _entity = user\n    _project = "test-project"\n    api = internal.Api()\n    # Entity, project, and sweep\n    sweep_id = wandb.sweep(sweep_config, entity=_entity, project=_project)\n    # Yes job\n    scheduler = SweepScheduler(\n        api, sweep_id=sweep_id, entity=_entity, project=_project, num_workers=1\n    )\n    scheduler.start()  # should raise no job found\n    assert scheduler.state == SchedulerState.FAILED\n\n\n@patch.multiple(Scheduler, __abstractmethods__=set())\ndef test_sweep_scheduler_base_scheduler_states(user, monkeypatch):\n    sweep_config = SWEEP_CONFIG_RANDOM\n    _patch_wandb_run(monkeypatch)\n    _entity = user\n    _project = "test-project"\n    api = internal.Api()\n    sweep_id = wandb.sweep(sweep_config, entity=_entity, project=_project)\n\n    def mock_run_complete_scheduler(self, *args, **kwargs):\n        self.state = SchedulerState.COMPLETED\n\n    def mock_get_run_state(*args, **kwargs):\n        if args[2] == "sweep-scheduler":\n            return "running"\n        return "finished"\n\n    api.get_run_state = mock_get_run_state\n\n    monkeypatch.setattr(\n        "wandb.sdk.launch.sweeps.scheduler.Scheduler._update_run_states",\n        mock_run_complete_scheduler,\n    )\n\n    monkeypatch.setattr(\n        "wandb.sdk.launch.sweeps.scheduler.Scheduler._try_load_executable",\n        lambda _: True,\n    )\n\n    _scheduler = Scheduler(\n        api, sweep_id=sweep_id, entity=_entity, project=_project, num_workers=1\n    )\n    assert _scheduler.state == SchedulerState.PENDING\n    assert _scheduler.is_alive is True\n    _scheduler.start()\n    assert _scheduler.state == SchedulerState.COMPLETED\n    assert _scheduler.is_alive is False\n\n    def mock_run_raise_keyboard_interrupt(*args, **kwargs):\n        raise KeyboardInterrupt\n\n    monkeypatch.setattr(\n        "wandb.sdk.launch.sweeps.scheduler.Scheduler._update_run_states",\n        mock_run_raise_keyboard_interrupt,\n    )\n\n    sweep_id = wandb.sweep(sweep_config, entity=_entity, project=_project)\n    _scheduler = Scheduler(\n        api, sweep_id=sweep_id, entity=_entity, project=_project, num_workers=1\n    )\n    _scheduler.start()\n    assert _scheduler.state == SchedulerState.STOPPED\n    assert _scheduler.is_alive is False\n\n    def mock_run_raise_exception(*args, **kwargs):\n        raise Exception("Generic exception")\n\n    sweep_id = wandb.sweep(sweep_config, entity=_entity, project=_project)\n    _scheduler = Scheduler(\n        api, sweep_id=sweep_id, entity=_entity, project=_project, num_workers=1\n    )\n    _scheduler._update_run_states = mock_run_raise_exception\n    with pytest.raises(Exception) as e:\n        _scheduler.start()\n    assert "Generic exception" in str(e.value)\n    assert _scheduler.state == SchedulerState.FAILED\n    assert _scheduler.is_alive is False\n\n    def mock_run_exit(self, *args, **kwargs):\n        self.exit()\n\n    monkeypatch.setattr(\n        "wandb.sdk.launch.sweeps.scheduler.Scheduler._update_run_states",\n        mock_run_exit,\n    )\n\n    def mock_get_run_state(*args, **kwargs):\n        if args[0] == "sweep-scheduler":\n            return "running"\n        return "finished"\n\n    sweep_id = wandb.sweep(sweep_config, entity=_entity, project=_project)\n    _scheduler = Scheduler(\n        api, sweep_id=sweep_id, entity=_entity, project=_project, num_workers=1\n    )\n    _scheduler._get_run_state = mock_get_run_state\n    _scheduler.start()\n    assert _scheduler.state == SchedulerState.FAILED\n    assert _scheduler.is_alive is False\n\n\n@patch.multiple(Scheduler, __abstractmethods__=set())\ndef test_sweep_scheduler_base_run_states(user, monkeypatch):\n    sweep_config = SWEEP_CONFIG_RANDOM\n    _patch_wandb_run(monkeypatch)\n    _entity = user\n    _project = "test-project"\n    api = internal.Api()\n    sweep_id = wandb.sweep(sweep_config, entity=_entity, project=_project)\n\n    # Mock api.get_run_state() to return crashed and running runs\n    mock_run_states: Dict[str, RunState] = {\n        "run1": RunState.CRASHED,\n        "run2": RunState.FAILED,\n        "run3": RunState.KILLED,\n        "run4": RunState.FINISHED,\n        "run5": RunState.RUNNING,\n        "run6": RunState.PENDING,\n        "run7": RunState.PREEMPTED,\n        "run8": RunState.PREEMPTING,\n        "run9": RunState.UNKNOWN,\n        "run10": "?????",\n    }\n\n    def mock_get_run_state(entity, project, run_id, *args, **kwargs):\n        if run_id not in mock_run_states:  # is scheduler\n            return RunState.RUNNING\n        return mock_run_states[run_id]\n\n    api.get_run_state = mock_get_run_state\n    _scheduler = Scheduler(\n        api, sweep_id=sweep_id, entity=_entity, project=_project, num_workers=1\n    )\n    # Load up the runs into the Scheduler run dict\n    for i, run_id in enumerate(mock_run_states.keys()):\n        _scheduler._runs[run_id] = SweepRun(\n            id=run_id, state=RunState.RUNNING, worker_id=i\n        )\n    _scheduler._update_run_states()\n    for run_id, _state in mock_run_states.items():\n        if _state == "?????":  # unknown state should be considered alive, but unknown\n            assert _scheduler._runs[run_id].state == RunState.UNKNOWN\n            continue\n        if not _state.is_alive:\n            # Dead runs should be removed from the run dict\n            assert run_id not in _scheduler._runs.keys()\n        else:\n            assert _scheduler._runs[run_id].state == _state\n\n    # ---- If get_run_state errors out, runs should have the state UNKNOWN\n    def mock_get_run_state_raise_exception(*args, **kwargs):\n        raise CommError("Generic Exception")\n\n    api.get_run_state = mock_get_run_state_raise_exception\n    sweep_id = wandb.sweep(sweep_config, entity=_entity, project=_project)\n    _scheduler = Scheduler(\n        api, sweep_id=sweep_id, entity=_entity, project=_project, num_workers=1\n    )\n    _scheduler._runs["foo_run_1"] = SweepRun(\n        id="foo_run_1", state=RunState.RUNNING, worker_id=1\n    )\n    _scheduler._runs["foo_run_2"] = SweepRun(\n        id="foo_run_2", state=RunState.RUNNING, worker_id=2\n    )\n    _scheduler._update_run_states()\n    assert _scheduler._runs["foo_run_1"].state == RunState.UNKNOWN\n    assert _scheduler._runs["foo_run_2"].state == RunState.UNKNOWN\n\n\n@patch.multiple(Scheduler, __abstractmethods__=set())\ndef test_sweep_scheduler_base_add_to_launch_queue(user, monkeypatch):\n    sweep_config = SWEEP_CONFIG_RANDOM\n    _patch_wandb_run(monkeypatch)\n    api = internal.Api()\n\n    _project = "test-project"\n    _job = "test-job:latest"\n    sweep_id = wandb.sweep(sweep_config, entity=user, project=_project)\n\n    def mock_launch_add(*args, **kwargs):\n        mock = Mock(spec=public.QueuedRun)\n        mock.args = Mock(return_value=args)\n        return mock\n\n    monkeypatch.setattr(\n        "wandb.sdk.launch._launch_add._launch_add",\n        mock_launch_add,\n    )\n\n    def mock_get_run_state(*args, **kwargs):\n        if args[2] == "sweep-scheduler":\n            return "running"\n        return "finished"\n\n    api.get_run_state = mock_get_run_state\n\n    def mock_run_add_to_launch_queue(self, *args, **kwargs):\n        self._runs["foo_run"] = SweepRun(\n            id="foo_run",\n            worker_id=0,\n            args={"foo": {"value": 1}},\n        )\n        self._add_to_launch_queue(self._runs["foo_run"])\n        self.state = SchedulerState.COMPLETED\n        self.exit()\n\n    monkeypatch.setattr(\n        "wandb.sdk.launch.sweeps.scheduler.Scheduler._get_next_sweep_run",\n        mock_run_add_to_launch_queue,\n    )\n\n    monkeypatch.setattr(\n        "wandb.sdk.launch.sweeps.scheduler.Scheduler._try_load_executable",\n        lambda _: True,\n    )\n\n    def mock_stop_run(self, run_id):\n        self._runs[run_id].state = RunState.CRASHED\n        return True\n\n    monkeypatch.setattr(\n        "wandb.sdk.launch.sweeps.scheduler.Scheduler._stop_run",\n        mock_stop_run,\n    )\n\n    _scheduler = Scheduler(\n        api,\n        sweep_id=sweep_id,\n        entity=user,\n        project=_project,\n        project_queue=_project,\n        polling_sleep=0,\n        num_workers=1,\n        job=_job,\n    )\n    assert _scheduler.state == SchedulerState.PENDING\n    assert _scheduler.is_alive is True\n    assert _scheduler._project_queue == _project\n    _scheduler.start()\n    assert _scheduler.state == SchedulerState.COMPLETED\n    assert _scheduler.is_alive is False\n    assert len(_scheduler._runs) == 1\n    assert isinstance(_scheduler._runs["foo_run"].queued_run, public.QueuedRun)\n    _scheduler._runs["foo_run"].queued_run.state = RunState.FINISHED\n    assert _scheduler._runs["foo_run"].queued_run.args()[-2] == _project\n\n    sweep_id2 = wandb.sweep(sweep_config, entity=user, project=_project)\n    _project_queue = "test-project-queue"\n    _scheduler2 = Scheduler(\n        api,\n        sweep_id=sweep_id2,\n        entity=user,\n        project=_project,\n        project_queue=_project_queue,\n        polling_sleep=0,\n        job=_job,\n        num_workers=1,\n    )\n    _scheduler2.start()\n    assert len(_scheduler2.busy_workers) == 1\n    assert len(_scheduler2.available_workers) == 0\n    assert _scheduler2._runs["foo_run"].queued_run.args()[-2] == _project_queue\n\n\ndef test_sweep_scheduler_sweeps_stop_agent_heartbeat(user, monkeypatch):\n    sweep_config = SWEEP_CONFIG_RANDOM\n    _patch_wandb_run(monkeypatch)\n    monkeypatch.setattr(\n        "wandb.sdk.launch.sweeps.scheduler.Scheduler._try_load_executable",\n        lambda _: True,\n    )\n\n    api = internal.Api()\n\n    def mock_agent_heartbeat(*args, **kwargs):\n        return [{"type": "stop"}]\n\n    api.agent_heartbeat = mock_agent_heartbeat\n\n    def mock_get_run_state(*args, **kwargs):\n        if args[2] == "sweep-scheduler":\n            return "running"\n        return "finished"\n\n    api.get_run_state = mock_get_run_state\n\n    _project = "test-project"\n    _job = "test-job:latest"\n    sweep_id = wandb.sweep(sweep_config, entity=user, project=_project)\n    scheduler = SweepScheduler(\n        api,\n        sweep_id=sweep_id,\n        entity=user,\n        project=_project,\n        num_workers=1,\n        polling_sleep=0,\n        job=_job,\n    )\n    scheduler.start()\n    assert scheduler.state == SchedulerState.STOPPED\n\n\ndef test_sweep_scheduler_sweeps_invalid_agent_heartbeat(user, monkeypatch):\n    sweep_config = SWEEP_CONFIG_RANDOM\n    _patch_wandb_run(monkeypatch)\n    monkeypatch.setattr(\n        "wandb.sdk.launch.sweeps.scheduler.Scheduler._try_load_executable",\n        lambda _: True,\n    )\n\n    api = internal.Api()\n    _project = "test-project"\n    sweep_id = wandb.sweep(sweep_config, entity=user, project=_project)\n\n    def mock_agent_heartbeat(*args, **kwargs):\n        return [{"type": "foo"}]\n\n    api.agent_heartbeat = mock_agent_heartbeat\n\n    def mock_get_run_state(*args, **kwargs):\n        if args[2] == "sweep-scheduler":\n            return "running"\n        return "finished"\n\n    api.get_run_state = mock_get_run_state\n\n    with pytest.raises(SchedulerError) as e:\n        _scheduler = SweepScheduler(\n            api,\n            sweep_id=sweep_id,\n            entity=user,\n            project=_project,\n            polling_sleep=0,\n            num_workers=1,\n        )\n        _scheduler.start()\n\n    assert "unknown command" in str(e.value)\n    assert _scheduler.state == SchedulerState.FAILED\n    assert _scheduler.is_alive is False\n\n    def mock_agent_heartbeat(*args, **kwargs):\n        return [{"type": "run"}]  # No run_id should throw error\n\n    api.agent_heartbeat = mock_agent_heartbeat\n    api.get_run_state = mock_get_run_state\n\n    sweep_id = wandb.sweep(sweep_config, entity=user, project=_project)\n    with pytest.raises(SchedulerError) as e:\n        _scheduler = SweepScheduler(\n            api,\n            sweep_id=sweep_id,\n            entity=user,\n            project=_project,\n            polling_sleep=0,\n            num_workers=1,\n        )\n        _scheduler.start()\n\n    assert "No run id in agent heartbeat: {\'type\': \'run\'}" in str(e.value)\n    assert _scheduler.state == SchedulerState.FAILED\n    assert _scheduler.is_alive is False\n\n\ndef test_sweep_scheduler_sweeps_run_and_heartbeat(user, monkeypatch):\n    sweep_config = SWEEP_CONFIG_RANDOM\n    _patch_wandb_run(monkeypatch)\n    monkeypatch.setattr(\n        "wandb.sdk.launch.sweeps.scheduler.Scheduler._try_load_executable",\n        lambda _: True,\n    )\n\n    api = internal.Api()\n    # Mock agent heartbeat stops after 10 heartbeats\n    api.agent_heartbeat = Mock(\n        side_effect=[\n            [\n                {\n                    "type": "run",\n                    "run_id": "mock-run-id-1",\n                    "args": {"foo_arg": {"value": 1}},\n                    "program": "train.py",\n                }\n            ]\n        ]\n        * 10\n        + [[{"type": "stop", "run_cap": 7}]]\n    )\n\n    def mock_launch_add(*args, **kwargs):\n        return Mock(spec=public.QueuedRun)\n\n    monkeypatch.setattr(\n        "wandb.sdk.launch._launch_add._launch_add",\n        mock_launch_add,\n    )\n\n    def mock_get_run_state(*args, **kwargs):\n        if args[2] == "sweep-scheduler":\n            return "running"\n        return "finished"\n\n    api.get_run_state = mock_get_run_state\n\n    def mock_stop_run(*args, **kwargs):\n        return False\n\n    api.stop_run = mock_stop_run\n\n    _project = "test-project"\n    _job = "test-job:latest"\n    sweep_id = wandb.sweep(sweep_config, entity=user, project=_project)\n\n    _scheduler = SweepScheduler(\n        api,\n        sweep_id=sweep_id,\n        entity=user,\n        project=_project,\n        num_workers=1,\n        polling_sleep=0,\n        job=_job,\n    )\n    assert _scheduler.state == SchedulerState.PENDING\n    assert _scheduler.is_alive is True\n    _scheduler.start()\n    assert "mock-run-id-1" not in _scheduler._runs\n\n\ndef test_launch_sweep_scheduler_try_executable_works(user, test_settings, monkeypatch):\n    _patch_wandb_run(monkeypatch)\n    _project = "test-project"\n    settings = test_settings({"project": _project})\n    run = wandb.init(settings=settings)\n    job_artifact = run._log_job_artifact_with_image("lala-docker-123", args=[])\n    job_name = f"{user}/{_project}/{job_artifact.wait().name}"\n\n    run.finish()\n    sweep_id = wandb.sweep(SWEEP_CONFIG_RANDOM, entity=user, project=_project)\n\n    _scheduler = SweepScheduler(\n        internal.Api(),\n        sweep_id=sweep_id,\n        entity=user,\n        project=_project,\n        num_workers=1,\n        polling_sleep=0,\n        job=job_name,\n    )\n\n    assert _scheduler._try_load_executable()\n\n\ndef test_launch_sweep_scheduler_try_executable_fails(user, monkeypatch):\n    _patch_wandb_run(monkeypatch)\n    _project = "test-project"\n    job_name = "nonexistent"\n    sweep_id = wandb.sweep(SWEEP_CONFIG_RANDOM, entity=user, project=_project)\n\n    _scheduler = SweepScheduler(\n        internal.Api(),\n        sweep_id=sweep_id,\n        entity=user,\n        project=_project,\n        num_workers=1,\n        polling_sleep=0,\n        job=job_name,\n    )\n\n    _scheduler.start()\n\n    assert _scheduler.state == SchedulerState.FAILED\n\n\ndef test_launch_sweep_scheduler_try_executable_image(user, monkeypatch):\n    _patch_wandb_run(monkeypatch)\n    _project = "test-project"\n    _image_uri = "some-image-wow"\n    sweep_id = wandb.sweep(SWEEP_CONFIG_RANDOM, entity=user, project=_project)\n\n    _scheduler = SweepScheduler(\n        internal.Api(),\n        sweep_id=sweep_id,\n        entity=user,\n        project=_project,\n        num_workers=1,\n        polling_sleep=0,\n        image_uri=_image_uri,\n    )\n\n    assert _scheduler._try_load_executable()\n\n\n@pytest.mark.parametrize(\n    "sweep_config",\n    [{"job": "job:v9"}, {"image_uri": "image:latest"}],\n)\ndef test_launch_sweep_scheduler_construct_entrypoint(sweep_config):\n    queue = "queue"\n    project = "test"\n\n    args = construct_scheduler_args(\n        return_job=False,\n        sweep_config=sweep_config,\n        queue=queue,\n        project=project,\n        author="author",\n    )\n\n    gold_args = [\n        "--queue",\n        f"{queue!r}",\n        "--project",\n        f"{project!r}",\n        "--author",\n        "\'author\'",\n    ]\n    if sweep_config.get("job"):\n        gold_args += ["--job", "\'job:v9\'"]\n    else:\n        gold_args += ["--image_uri", "image:latest"]\n\n    assert args == gold_args\n\n\n@pytest.mark.parametrize(\n    "command",\n    [\n        [],\n        ["python", "train.py", "${args_no_hyphens}"],\n        ["python", "train.py", "${args_append_hydra}"],\n        ["python", "train.py", "${args_override_hydra}"],\n        ["python", "train.py", "${args_no_equals}"],\n        ["${env}", "python", "train.py", "${args}", "--another", "param"],\n        ["python", "train.py", "--float", 1.99999, "${args_json}"],\n    ],\n)\ndef test_launch_sweep_scheduler_macro_args(user, monkeypatch, command):\n    _patch_wandb_run(monkeypatch)\n\n    def mock_launch_add(*args, **kwargs):\n        mock = Mock(spec=public.QueuedRun)\n        mock.args = Mock(return_value=args)\n        return mock\n\n    monkeypatch.setattr(\n        "wandb.sdk.launch._launch_add._launch_add",\n        mock_launch_add,\n    )\n\n    sweep_config = {\n        "job": "job:latest",\n        "program": "program-override.py",\n        "method": "grid",\n        "parameters": {\n            "foo-1": {"values": [1, 2]},\n            "bool_2": {"values": [True, False]},\n        },\n        "command": command,\n    }\n    # Entity, project, and sweep should be everything you need to create a scheduler\n    api = internal.Api()\n    s = wandb.sweep(sweep_config, entity=user, project="t")\n    scheduler = SweepScheduler(\n        api, sweep_id=s, entity=user, project="t", queue="q", num_workers=1\n    )\n    asyncio.run(scheduler._register_agents())\n    srun2 = scheduler._get_next_sweep_run(0)\n    scheduler._add_to_launch_queue(srun2)\n',
            'tests/system_tests/test_sweep/test_wandb_agent.py': '"""Agent tests."""\n\nimport os\nimport platform\nimport signal\nimport subprocess\nimport sys\nimport textwrap\nfrom pathlib import Path\nfrom unittest import mock\n\nimport pytest\nfrom wandb.sdk.launch.sweeps.utils import (\n    create_sweep_command,\n    create_sweep_command_args,\n)\nfrom wandb.wandb_agent import Agent\n\n\ndef test_agent_create_command_args():\n    mock_command = {\n        "args": {\n            "a": {"value": True},\n            "b": {"value": False},\n            "c": {"value": 1},\n            "d": {"value": None},\n        }\n    }\n\n    _return = create_sweep_command_args(mock_command)\n    # test has all the required fields\n    assert "args" in _return\n    assert "args_no_hyphens" in _return\n    assert "args_append_hydra" in _return\n    assert "args_override_hydra" in _return\n    assert "args_no_boolean_flags" in _return\n    assert "args_json" in _return\n    # test fields are correct\n    assert _return["args"] == ["--a=True", "--b=False", "--c=1", "--d=None"]\n    assert _return["args_no_hyphens"] == ["a=True", "b=False", "c=1", "d=None"]\n    assert _return["args_no_boolean_flags"] == ["--a", "--c=1", "--d=None"]\n    assert _return["args_json"] == [\'{"a": true, "b": false, "c": 1, "d": null}\']\n    assert _return["args_append_hydra"] == ["+a=True", "+b=False", "+c=1", "+d=None"]\n    assert _return["args_override_hydra"] == [\n        "++a=True",\n        "++b=False",\n        "++c=1",\n        "++d=None",\n    ]\n\n\ndef test_agent_create_command_args_bad_command():\n    mock_command_no_args = {"foo": None}\n    with pytest.raises(ValueError):\n        _ = create_sweep_command_args(mock_command_no_args)\n    mock_command_missing_value = {"args": {"a": {"foo": True}}}\n    with pytest.raises(ValueError):\n        _ = create_sweep_command_args(mock_command_missing_value)\n\n\n@mock.patch.dict(\n    os.environ,\n    {\n        "FOO_DIR": "foo_dir",\n        "FOO_DIR_TWO": "foo_dir_two",\n        "FOO_VAR": "foo_var",\n    },\n)\ndef test_agent_create_sweep_command():\n    # Given no command, function should return default\n    _command = create_sweep_command()\n    assert _command == Agent.DEFAULT_SWEEP_COMMAND\n\n    # Environment variable macros should be replaced in mock command\n    _command = create_sweep_command(\n        [\n            "${env}",\n            "${interpreter}",\n            "--output_dir",\n            "fake/path/${envvar:FOO_DIR}/${envvar:FOO_DIR}/${envvar:FOO_DIR_TWO}",\n            "--foovar",\n            "${envvar:FOO_VAR}",\n        ]\n    )\n    assert _command == [\n        "${env}",\n        "${interpreter}",\n        "--output_dir",\n        "fake/path/foo_dir/foo_dir/foo_dir_two",\n        "--foovar",\n        "foo_var",\n    ]\n\n\ndef _write_signal_child_script(path: Path) -> Path:\n    script = path / "child_signal.py"\n    script.write_text(\n        textwrap.dedent(\n            """\n            import pathlib\n            import signal\n            import sys\n            import time\n\n            marker = pathlib.Path(sys.argv[1])\n\n            def _handle(signum, frame):\n                marker.write_text(str(signum))\n                sys.exit(0)\n\n            signal.signal(signal.SIGTERM, _handle)\n            signal.signal(signal.SIGINT, _handle)\n\n            while True:\n                time.sleep(0.1)\n            """\n        ).strip()\n    )\n    return script\n\n\ndef _write_signal_parent_script(path: Path) -> Path:\n    script = path / "parent_signal.py"\n    script.write_text(\n        textwrap.dedent(\n            """\n            import os\n            import signal\n            import sys\n            import time\n            from pathlib import Path\n\n            from wandb.wandb_agent import AgentProcess\n\n            marker = Path(sys.argv[1])\n            child_script = Path(sys.argv[2])\n\n            signal.signal(signal.SIGTERM, lambda s, f: None)\n\n            proc = AgentProcess(\n                env=dict(os.environ),\n                command=[sys.executable, str(child_script), str(marker)],\n                forward_signals=True,\n            )\n\n            time.sleep(0.5)\n            os.kill(os.getpid(), signal.SIGTERM)\n\n            deadline = time.time() + 10\n            while proc.poll() is None and time.time() < deadline:\n                time.sleep(0.1)\n\n            if proc.poll() is None:\n                proc.terminate()\n                sys.exit(2)\n\n            if not marker.exists():\n                sys.exit(3)\n            """\n        ).strip()\n    )\n    return script\n\n\n@pytest.mark.skipif(\n    platform.system() == "Windows", reason="POSIX signals required for this test"\n)\ndef test_agent_process_forwards_signals_end_to_end(tmp_path):\n    marker = tmp_path / "signal.txt"\n    child_script = _write_signal_child_script(tmp_path)\n    parent_script = _write_signal_parent_script(tmp_path)\n\n    repo_root = Path(__file__).resolve().parents[3]\n    env = os.environ.copy()\n    env["PYTHONPATH"] = (\n        f"{repo_root}{os.pathsep}{env[\'PYTHONPATH\']}"\n        if "PYTHONPATH" in env and env["PYTHONPATH"]\n        else str(repo_root)\n    )\n\n    result = subprocess.run(\n        [sys.executable, str(parent_script), str(marker), str(child_script)],\n        capture_output=True,\n        text=True,\n        env=env,\n    )\n\n    assert result.returncode == 0, f"stderr:\\n{result.stderr}"\n    assert marker.exists()\n    assert marker.read_text().strip() == str(int(signal.SIGTERM))\n',
            'tests/system_tests/test_sweep/test_wandb_agent_full.py': '"""Agent tests."""\n\nimport contextlib\nimport io\nimport pathlib\n\nimport wandb\nfrom wandb.apis.public import Api\n\n\ndef test_agent_basic(user):\n    sweep_ids = []\n    sweep_configs = []\n    sweep_resumed = []\n\n    sweep_config = {\n        "name": "My Sweep",\n        "method": "grid",\n        "parameters": {"a": {"values": [1, 2, 3]}},\n    }\n\n    def train():\n        run = wandb.init()\n        sweep_ids.append(run.sweep_id)\n        sweep_configs.append(dict(run.config))\n        sweep_resumed.append(run.resumed)\n        run.finish()\n\n    sweep_id = wandb.sweep(sweep_config)\n\n    wandb.agent(sweep_id, function=train, count=1)\n\n    assert len(sweep_ids) == len(sweep_configs) == 1\n    assert sweep_ids[0] == sweep_id\n    assert sweep_configs[0] == {"a": 1}\n    assert sweep_resumed[0] is False\n\n\ndef test_agent_config_merge(user, monkeypatch):\n    sweep_configs = []\n\n    def train():\n        run = wandb.init(config={"extra": 2})\n        sweep_configs.append(dict(run.config))\n        run.finish()\n\n    sweep_config = {\n        "name": "My Sweep",\n        "method": "grid",\n        "parameters": {"a": {"values": [1, 2, 3]}},\n    }\n\n    monkeypatch.setenv("WANDB_CONSOLE", "off")\n    sweep_id = wandb.sweep(sweep_config)\n    wandb.agent(sweep_id, function=train, count=1)\n\n    assert len(sweep_configs) == 1\n    assert sweep_configs[0] == {"a": 1, "extra": 2}\n\n\ndef test_agent_config_ignore(user):\n    sweep_configs = []\n\n    def train():\n        run = wandb.init(config={"a": "ignored", "extra": 2})\n        sweep_configs.append(dict(run.config))\n        run.finish()\n\n    sweep_config = {\n        "name": "My Sweep",\n        "method": "grid",\n        "parameters": {"a": {"values": [1, 2, 3]}},\n    }\n\n    sweep_id = wandb.sweep(sweep_config)\n    wandb.agent(sweep_id, function=train, count=1)\n\n    assert len(sweep_configs) == 1\n    assert sweep_configs[0] == {"a": 1, "extra": 2}\n\n\ndef test_agent_ignore_project_entity_run_id(user):\n    sweep_entities = []\n    sweep_projects = []\n    sweep_run_ids = []\n\n    project_name = "actual"\n    public_api = Api()\n    public_api.create_project(project_name, user)\n\n    def train():\n        run = wandb.init(entity="ign", project="ignored", id="also_ignored")\n        sweep_projects.append(run.project)\n        sweep_entities.append(run.entity)\n        sweep_run_ids.append(run.id)\n        run.finish()\n\n    sweep_config = {\n        "name": "My Sweep",\n        "method": "grid",\n        "parameters": {"a": {"values": [1, 2, 3]}},\n    }\n    sweep_id = wandb.sweep(sweep_config, project=project_name)\n    wandb.agent(sweep_id, function=train, count=1, project=project_name)\n\n    assert len(sweep_projects) == len(sweep_entities) == 1\n    assert sweep_projects[0] == "actual"\n    assert sweep_entities[0] == user\n    assert sweep_run_ids[0] != "also_ignored"\n\n\ndef test_agent_exception(user):\n    sweep_config = {\n        "name": "My Sweep",\n        "method": "grid",\n        "parameters": {"a": {"values": [1, 2, 3]}},\n    }\n\n    def train():\n        wandb.init()\n        raise Exception("Unexpected error")\n\n    sweep_id = wandb.sweep(sweep_config)\n\n    captured_stderr = io.StringIO()\n    with contextlib.redirect_stderr(captured_stderr):\n        wandb.agent(sweep_id, function=train, count=1)\n\n    stderr_lines = captured_stderr.getvalue().splitlines()\n\n    # Traceback with exception should appear before we finish the run.\n    patterns = ["Traceback", "Exception: Unexpected error", "wandb: Find logs at:"]\n    current_pattern = 0\n\n    for line in stderr_lines:\n        if line.startswith(patterns[current_pattern]):\n            current_pattern += 1\n            if current_pattern == len(patterns):\n                break\n\n    # Verify all patterns were found in order\n    assert current_pattern == len(patterns), (\n        f"Not found in stderr: \'{patterns[current_pattern]}\'"\n    )\n\n\ndef test_agent_subprocess_with_import_readline(user, monkeypatch):\n    """Test that wandb.agent works safely when subprocess imports readline."""\n    script_path = pathlib.Path(__file__).parent / "train_with_import_readline.py"\n\n    project = "train-with-import-readline"\n    sweep_config = {\n        "name": "Train with import readline",\n        "method": "grid",\n        "parameters": {"test_param": {"values": [1]}},\n        "command": ["python", str(script_path)],\n    }\n    sweep_id = wandb.sweep(sweep_config, project=project)\n\n    monkeypatch.setenv("WANDB_AGENT_MAX_INITIAL_FAILURES", "1")\n    wandb.agent(sweep_id, count=1)\n    # We\'ll just rely on the default pytest 60s timeout if it deadlocks.\n\n    runs = Api().runs(project, {"sweep": sweep_id})\n    assert len(runs) == 1\n    history = runs[0].history(pandas=False)\n    assert history[0]["got_eof"]\n    assert history[0]["test_param"] == 1\n',
            'tests/unit_tests/test_internal_api.py': 'import base64\nimport hashlib\nimport os\nimport pathlib\nimport tempfile\nfrom itertools import chain\nfrom pathlib import Path\nfrom typing import Callable, Mapping, Optional, Sequence, Tuple, Type, TypeVar, Union\nfrom unittest.mock import Mock, call, patch\n\nimport pytest\nimport requests\nimport wandb.errors\nimport wandb.sdk.internal.internal_api\nimport wandb.sdk.internal.progress\nfrom pytest_mock import MockerFixture\nfrom responses import RequestsMock\nfrom wandb.apis import internal\nfrom wandb.errors import CommError\nfrom wandb.proto.wandb_internal_pb2 import ServerFeature\nfrom wandb.sdk.internal.internal_api import (\n    _match_org_with_fetched_org_entities,\n    _OrgNames,\n)\nfrom wandb.sdk.lib import retry\n\nfrom .test_retry import MockTime, mock_time  # noqa: F401\n\n_T = TypeVar("_T")\n\n\n@pytest.fixture\ndef mock_responses():\n    with RequestsMock() as rsps:\n        yield rsps\n\n\ndef test_agent_heartbeat_with_no_agent_id_fails():\n    a = internal.Api()\n    with pytest.raises(ValueError):\n        a.agent_heartbeat(None, {}, {})\n\n\ndef test_get_run_state_invalid_kwargs():\n    with pytest.raises(CommError) as e:\n        _api = internal.Api()\n\n        def _mock_gql(*args, **kwargs):\n            return dict()\n\n        _api.api.gql = _mock_gql\n        _api.get_run_state("test_entity", None, "test_run")\n\n    assert "Error fetching run state" in str(e.value)\n\n\n@pytest.mark.parametrize(\n    "existing_contents,expect_download",\n    [\n        (None, True),\n        ("outdated contents", True),\n        ("current contents", False),\n    ],\n)\ndef test_download_write_file_fetches_iff_file_checksum_mismatched(\n    mock_responses: RequestsMock,\n    existing_contents: Optional[str],\n    expect_download: bool,\n):\n    url = "https://example.com/path/to/file.txt"\n    current_contents = "current contents"\n    with tempfile.TemporaryDirectory() as tmpdir:\n        filepath = os.path.join(tmpdir, "file.txt")\n\n        if expect_download:\n            mock_responses.get(url, body=current_contents)\n\n        if existing_contents is not None:\n            with open(filepath, "w") as f:\n                f.write(existing_contents)\n\n        _, response = internal.InternalApi().download_write_file(\n            metadata={\n                "name": filepath,\n                "md5": base64.b64encode(\n                    hashlib.md5(current_contents.encode()).digest()\n                ).decode(),\n                "url": url,\n            },\n            out_dir=tmpdir,\n        )\n\n        if expect_download:\n            assert response is not None\n        else:\n            assert response is None\n\n\ndef test_internal_api_with_no_write_global_config_dir(\n    tmp_path: pathlib.Path,\n    monkeypatch: pytest.MonkeyPatch,\n):\n    config_dir = tmp_path / "test-config"\n    monkeypatch.setenv("WANDB_CONFIG_DIR", str(config_dir))\n    config_dir.mkdir(0o511)  # read and list only\n\n    try:\n        internal.InternalApi()\n    finally:\n        config_dir.chmod(0o711)  # allow test to clean up\n\n\n@pytest.fixture\ndef mock_gql():\n    with patch("wandb.sdk.internal.internal_api.Api.gql") as mock:\n        mock.return_value = None\n        yield mock\n\n\ndef test_fetch_orgs_from_team_entity(mock_gql):\n    """Test fetching organization entities from a team entity."""\n    api = internal.InternalApi()\n    mock_gql.return_value = {\n        "entity": {\n            "organization": {\n                "name": "test-org",\n                "orgEntity": {"name": "test-org-entity"},\n            },\n            "user": None,\n        }\n    }\n    result = api._fetch_orgs_and_org_entities_from_entity("team-entity")\n    assert result == [_OrgNames(entity_name="test-org-entity", display_name="test-org")]\n\n\ndef test_fetch_orgs_from_personal_entity_single_org(mock_gql):\n    """Test fetching organization entities from a personal entity with single org."""\n    api = internal.InternalApi()\n    mock_gql.return_value = {\n        "entity": {\n            "organization": None,\n            "user": {\n                "organizations": [\n                    {\n                        "name": "personal-org",\n                        "orgEntity": {"name": "personal-org-entity"},\n                    }\n                ]\n            },\n        }\n    }\n    result = api._fetch_orgs_and_org_entities_from_entity("personal-entity")\n    assert result == [\n        _OrgNames(entity_name="personal-org-entity", display_name="personal-org")\n    ]\n\n\ndef test_fetch_orgs_from_personal_entity_multiple_orgs(mock_gql):\n    """Test fetching organization entities from a personal entity with multiple orgs."""\n    api = internal.InternalApi()\n    mock_gql.return_value = {\n        "entity": {\n            "organization": None,\n            "user": {\n                "organizations": [\n                    {\n                        "name": "org1",\n                        "orgEntity": {"name": "org1-entity"},\n                    },\n                    {\n                        "name": "org2",\n                        "orgEntity": {"name": "org2-entity"},\n                    },\n                ]\n            },\n        }\n    }\n    result = api._fetch_orgs_and_org_entities_from_entity("personal-entity")\n    assert result == [\n        _OrgNames(entity_name="org1-entity", display_name="org1"),\n        _OrgNames(entity_name="org2-entity", display_name="org2"),\n    ]\n\n\ndef test_fetch_orgs_from_personal_entity_no_orgs(mock_gql):\n    """Test fetching organization entities from a personal entity with no orgs."""\n    api = internal.InternalApi()\n    mock_gql.return_value = {\n        "entity": {\n            "organization": None,\n            "user": {"organizations": []},\n        }\n    }\n    with pytest.raises(\n        ValueError,\n        match="Unable to resolve an organization associated with personal entity",\n    ):\n        api._fetch_orgs_and_org_entities_from_entity("personal-entity")\n\n\ndef test_fetch_orgs_from_nonexistent_entity(mock_gql):\n    """Test fetching organization entities from a nonexistent entity."""\n    api = internal.InternalApi()\n    mock_gql.return_value = {\n        "entity": {\n            "organization": None,\n            "user": None,\n        }\n    }\n    with pytest.raises(\n        ValueError,\n        match="Unable to find an organization under entity",\n    ):\n        api._fetch_orgs_and_org_entities_from_entity("potato-entity")\n\n\ndef test_fetch_orgs_with_invalid_response_structure(mock_gql):\n    """Test fetching organization entities with invalid response structure."""\n    api = internal.InternalApi()\n    mock_gql.return_value = {\n        "entity": {\n            "organization": {\n                "name": "hello",\n                "orgEntity": None,\n            },\n            "user": None,\n        }\n    }\n    with pytest.raises(ValueError, match="Unable to find an organization under entity"):\n        api._fetch_orgs_and_org_entities_from_entity("invalid-entity")\n\n\ndef test_match_org_single_org_display_name_match():\n    assert (\n        _match_org_with_fetched_org_entities(\n            "org-display",\n            [_OrgNames(entity_name="org-entity", display_name="org-display")],\n        )\n        == "org-entity"\n    )\n\n\ndef test_match_org_single_org_entity_name_match():\n    assert (\n        _match_org_with_fetched_org_entities(\n            "org-entity",\n            [_OrgNames(entity_name="org-entity", display_name="org-display")],\n        )\n        == "org-entity"\n    )\n\n\ndef test_match_org_multiple_orgs_successful_match():\n    assert (\n        _match_org_with_fetched_org_entities(\n            "org-display-2",\n            [\n                _OrgNames(entity_name="org-entity", display_name="org-display"),\n                _OrgNames(entity_name="org-entity-2", display_name="org-display-2"),\n            ],\n        )\n        == "org-entity-2"\n    )\n\n\ndef test_match_org_single_org_no_match():\n    with pytest.raises(\n        ValueError, match="Expecting the organization name or entity name to match"\n    ):\n        _match_org_with_fetched_org_entities(\n            "wrong-org",\n            [_OrgNames(entity_name="org-entity", display_name="org-display")],\n        )\n\n\ndef test_match_org_multiple_orgs_no_match():\n    with pytest.raises(\n        ValueError, match="Personal entity belongs to multiple organizations"\n    ):\n        _match_org_with_fetched_org_entities(\n            "wrong-org",\n            [\n                _OrgNames(entity_name="org1-entity", display_name="org1-display"),\n                _OrgNames(entity_name="org2-entity", display_name="org2-display"),\n            ],\n        )\n\n\n@pytest.fixture\ndef api_with_single_org():\n    api = internal.InternalApi()\n    api.server_organization_type_introspection = Mock(return_value=["orgEntity"])\n    api._fetch_orgs_and_org_entities_from_entity = Mock(\n        return_value=[_OrgNames(entity_name="org-entity", display_name="org-display")]\n    )\n    return api\n\n\n@pytest.mark.parametrize(\n    "entity, input_org, expected_org_entity",\n    [\n        ("entity", "org-display", "org-entity"),\n        ("entity", "org-entity", "org-entity"),\n        ("entity", None, "org-entity"),\n    ],\n)\ndef test_resolve_org_entity_name_with_single_org_success(\n    api_with_single_org, entity, input_org, expected_org_entity\n):\n    assert (\n        api_with_single_org._resolve_org_entity_name(entity, input_org)\n        == expected_org_entity\n    )\n\n\n@pytest.mark.parametrize(\n    "entity,input_org,error_message",\n    [\n        (\n            "entity",\n            "potato-org",\n            "Expecting the organization name or entity name to match",\n        ),\n        (None, None, "Entity name is required to resolve org entity name."),\n        ("", None, "Entity name is required to resolve org entity name."),\n    ],\n)\ndef test_resolve_org_entity_name_with_single_org_errors(\n    api_with_single_org, entity, input_org, error_message\n):\n    with pytest.raises(ValueError, match=error_message):\n        api_with_single_org._resolve_org_entity_name(entity, input_org)\n\n\n@pytest.fixture\ndef api_with_multiple_orgs():\n    api = internal.InternalApi()\n    api.server_organization_type_introspection = Mock(return_value=["orgEntity"])\n    api._fetch_orgs_and_org_entities_from_entity = Mock(\n        return_value=[\n            _OrgNames(entity_name="org1-entity", display_name="org1-display"),\n            _OrgNames(entity_name="org2-entity", display_name="org2-display"),\n            _OrgNames(entity_name="org3-entity", display_name="org3-display"),\n        ]\n    )\n    return api\n\n\ndef test_resolve_org_entity_name_with_multiple_orgs_no_org_specified(\n    api_with_multiple_orgs,\n):\n    """Test that error is raised when no org is specified for entity with multiple orgs."""\n    with pytest.raises(ValueError, match="belongs to multiple organizations"):\n        api_with_multiple_orgs._resolve_org_entity_name("entity")\n\n\ndef test_resolve_org_entity_name_with_multiple_orgs_display_name(\n    api_with_multiple_orgs,\n):\n    """Test resolving org entity name using org display name."""\n    assert (\n        api_with_multiple_orgs._resolve_org_entity_name("entity", "org1-display")\n        == "org1-entity"\n    )\n\n\ndef test_resolve_org_entity_name_with_multiple_orgs_entity_name(api_with_multiple_orgs):\n    """Test resolving org entity name using org entity name."""\n    assert (\n        api_with_multiple_orgs._resolve_org_entity_name("entity", "org2-entity")\n        == "org2-entity"\n    )\n\n\ndef test_resolve_org_entity_name_with_multiple_orgs_invalid_org(api_with_multiple_orgs):\n    """Test that error is raised when specified org doesn\'t match any available orgs."""\n    with pytest.raises(\n        ValueError, match="Personal entity belongs to multiple organizations"\n    ):\n        api_with_multiple_orgs._resolve_org_entity_name("entity", "potato-org")\n\n\ndef test_resolve_org_entity_name_with_old_server():\n    api = internal.InternalApi()\n    api.server_organization_type_introspection = Mock(return_value=[])\n\n    # Should error without organization\n    with pytest.raises(ValueError, match="unavailable for your server version"):\n        api._resolve_org_entity_name("entity")\n\n    # Should return organization as-is when specified\n    assert api._resolve_org_entity_name("entity", "org-name-input") == "org-name-input"\n\n\nMockResponseOrException = Union[Exception, Tuple[int, Mapping[int, int], str]]\n\n\nclass TestUploadFile:\n    """Tests `upload_file`."""\n\n    class TestSimple:\n        def test_adds_headers_to_request(\n            self, mock_responses: RequestsMock, example_file: Path\n        ):\n            response_callback = Mock(return_value=(200, {}, "success!"))\n            mock_responses.add_callback(\n                "PUT", "http://example.com/upload-dst", response_callback\n            )\n            internal.InternalApi().upload_file(\n                "http://example.com/upload-dst",\n                example_file.open("rb"),\n                extra_headers={"X-Test": "test"},\n            )\n            assert response_callback.call_args[0][0].headers["X-Test"] == "test"\n\n        def test_returns_response_on_success(\n            self, mock_responses: RequestsMock, example_file: Path\n        ):\n            mock_responses.put(\n                "http://example.com/upload-dst", status=200, body="success!"\n            )\n            resp = internal.InternalApi().upload_file(\n                "http://example.com/upload-dst", example_file.open("rb")\n            )\n            assert resp.content == b"success!"\n\n        # test_async_returns_response_on_success: doesn\'t exist,\n        # because `upload_file_async` doesn\'t return the response.\n\n        @pytest.mark.parametrize(\n            "response,expected_errtype",\n            [\n                ((400, {}, ""), requests.exceptions.HTTPError),\n                ((500, {}, ""), retry.TransientError),\n                ((502, {}, ""), retry.TransientError),\n                (requests.exceptions.ConnectionError(), retry.TransientError),\n                (requests.exceptions.Timeout(), retry.TransientError),\n                (RuntimeError("oh no"), RuntimeError),\n            ],\n        )\n        def test_returns_transienterror_on_transient_issues(\n            self,\n            mock_responses: RequestsMock,\n            example_file: Path,\n            response: MockResponseOrException,\n            expected_errtype: Type[Exception],\n        ):\n            mock_responses.add_callback(\n                "PUT",\n                "http://example.com/upload-dst",\n                Mock(return_value=response),\n            )\n            with pytest.raises(expected_errtype):\n                internal.InternalApi().upload_file(\n                    "http://example.com/upload-dst", example_file.open("rb")\n                )\n\n    class TestProgressCallback:\n        def test_smoke(self, mock_responses: RequestsMock, example_file: Path):\n            file_contents = "some text"\n            example_file.write_text(file_contents)\n\n            def response_callback(request: requests.models.PreparedRequest):\n                assert request.body.read() == file_contents.encode()\n                return (200, {}, "success!")\n\n            mock_responses.add_callback(\n                "PUT", "http://example.com/upload-dst", response_callback\n            )\n\n            progress_callback = Mock()\n            internal.InternalApi().upload_file(\n                "http://example.com/upload-dst",\n                example_file.open("rb"),\n                callback=progress_callback,\n            )\n\n            assert progress_callback.call_args_list == [\n                call(len(file_contents), len(file_contents))\n            ]\n\n        def test_handles_multiple_calls(\n            self, mock_responses: RequestsMock, example_file: Path\n        ):\n            example_file.write_text("12345")\n\n            def response_callback(request: requests.models.PreparedRequest):\n                assert request.body.read(2) == b"12"\n                assert request.body.read(2) == b"34"\n                assert request.body.read() == b"5"\n                assert request.body.read() == b""\n                return (200, {}, "success!")\n\n            mock_responses.add_callback(\n                "PUT", "http://example.com/upload-dst", response_callback\n            )\n\n            progress_callback = Mock()\n            internal.InternalApi().upload_file(\n                "http://example.com/upload-dst",\n                example_file.open("rb"),\n                callback=progress_callback,\n            )\n\n            assert progress_callback.call_args_list == [\n                call(2, 2),\n                call(2, 4),\n                call(1, 5),\n                call(0, 5),\n            ]\n\n        @pytest.mark.parametrize(\n            "failure",\n            [\n                requests.exceptions.Timeout(),\n                requests.exceptions.ConnectionError(),\n                (400, {}, ""),\n                (500, {}, ""),\n            ],\n        )\n        def test_rewinds_on_failure(\n            self,\n            mock_responses: RequestsMock,\n            example_file: Path,\n            failure: MockResponseOrException,\n        ):\n            example_file.write_text("1234567")\n\n            def response_callback(request: requests.models.PreparedRequest):\n                assert request.body.read(2) == b"12"\n                assert request.body.read(2) == b"34"\n                return failure\n\n            mock_responses.add_callback(\n                "PUT", "http://example.com/upload-dst", response_callback\n            )\n\n            progress_callback = Mock()\n            with pytest.raises((retry.TransientError, requests.RequestException)):\n                internal.InternalApi().upload_file(\n                    "http://example.com/upload-dst",\n                    example_file.open("rb"),\n                    callback=progress_callback,\n                )\n\n            assert progress_callback.call_args_list == [\n                call(2, 2),\n                call(2, 4),\n                call(-4, 0),\n            ]\n\n    @pytest.mark.parametrize(\n        "request_headers,response,expected_errtype",\n        [\n            (\n                {"x-amz-meta-md5": "1234"},\n                (400, {}, "blah blah RequestTimeout blah blah"),\n                retry.TransientError,\n            ),\n            (\n                {"x-amz-meta-md5": "1234"},\n                (400, {}, "non-timeout-related error message"),\n                requests.RequestException,\n            ),\n            (\n                {"x-amz-meta-md5": "1234"},\n                requests.exceptions.ConnectionError(),\n                retry.TransientError,\n            ),\n            (\n                {},\n                (400, {}, "blah blah RequestTimeout blah blah"),\n                requests.RequestException,\n            ),\n        ],\n    )\n    def test_transient_failure_on_special_aws_request_timeout(\n        self,\n        mock_responses: RequestsMock,\n        example_file: Path,\n        request_headers: Mapping[str, str],\n        response,\n        expected_errtype: Type[Exception],\n    ):\n        mock_responses.add_callback(\n            "PUT", "http://example.com/upload-dst", Mock(return_value=response)\n        )\n        with pytest.raises(expected_errtype):\n            internal.InternalApi().upload_file(\n                "http://example.com/upload-dst",\n                example_file.open("rb"),\n                extra_headers=request_headers,\n            )\n\n    # test_async_transient_failure_on_special_aws_request_timeout: see\n    # `test_async_retries_on_special_aws_request_timeout` on TestUploadRetry.\n\n    class TestAzure:\n        MAGIC_HEADERS = {"x-ms-blob-type": "SomeBlobType"}\n\n        @pytest.mark.parametrize(\n            "request_headers,uses_azure_lib",\n            [\n                ({}, False),\n                (MAGIC_HEADERS, True),\n            ],\n        )\n        def test_uses_azure_lib_if_available(\n            self,\n            mock_responses: RequestsMock,\n            example_file: Path,\n            request_headers: Mapping[str, str],\n            uses_azure_lib: bool,\n        ):\n            api = internal.InternalApi()\n\n            if uses_azure_lib:\n                api._azure_blob_module = Mock()\n            else:\n                mock_responses.put("http://example.com/upload-dst")\n\n            api.upload_file(\n                "http://example.com/upload-dst",\n                example_file.open("rb"),\n                extra_headers=request_headers,\n            )\n\n            if uses_azure_lib:\n                api._azure_blob_module.BlobClient.from_blob_url().upload_blob.assert_called_once()\n            else:\n                assert len(mock_responses.calls) == 1\n\n        @pytest.mark.parametrize(\n            "response,expected_errtype,check_err",\n            [\n                (\n                    (400, {}, "my-reason"),\n                    requests.RequestException,\n                    lambda e: e.response.status_code == 400 and "my-reason" in str(e),\n                ),\n                (\n                    (500, {}, "my-reason"),\n                    retry.TransientError,\n                    lambda e: (\n                        e.exception.response.status_code == 500\n                        and "my-reason" in str(e.exception)\n                    ),\n                ),\n                (\n                    requests.exceptions.ConnectionError("my-reason"),\n                    retry.TransientError,\n                    lambda e: "my-reason" in str(e.exception),\n                ),\n            ],\n        )\n        def test_translates_azure_err_to_normal_err(\n            self,\n            mock_responses: RequestsMock,\n            example_file: Path,\n            response: MockResponseOrException,\n            expected_errtype: Type[Exception],\n            check_err: Callable[[Exception], bool],\n        ):\n            mock_responses.add_callback(\n                "PUT", "https://example.com/foo/bar/baz", Mock(return_value=response)\n            )\n            with pytest.raises(expected_errtype) as e:\n                internal.InternalApi().upload_file(\n                    "https://example.com/foo/bar/baz",\n                    example_file.open("rb"),\n                    extra_headers=self.MAGIC_HEADERS,\n                )\n\n            assert check_err(e.value), e.value\n\n\nclass TestUploadFileRetry:\n    """Test the retry logic of upload_file_retry.\n\n    Testing the file-upload logic itself is done in TestUploadFile, above;\n    this class just tests the retry logic (though it does make a couple\n    assumptions about status codes, like "400 isn\'t retriable, 500 is.")\n    """\n\n    @pytest.mark.parametrize(\n        ["schedule", "num_requests"],\n        [\n            ([200, 0], 1),\n            ([500, 500, 200, 0], 3),\n        ],\n    )\n    def test_stops_after_success(\n        self,\n        example_file: Path,\n        mock_responses: RequestsMock,\n        schedule: Sequence[int],\n        num_requests: int,\n    ):\n        handler = Mock(side_effect=[(status, {}, "") for status in schedule])\n        mock_responses.add_callback("PUT", "http://example.com/upload-dst", handler)\n\n        internal.InternalApi().upload_file_retry(\n            "http://example.com/upload-dst",\n            example_file.open("rb"),\n        )\n\n        assert handler.call_count == num_requests\n\n    def test_stops_after_bad_status(\n        self,\n        example_file: Path,\n        mock_responses: RequestsMock,\n    ):\n        handler = Mock(side_effect=[(400, {}, "")])\n        mock_responses.add_callback("PUT", "http://example.com/upload-dst", handler)\n\n        with pytest.raises(wandb.errors.CommError):\n            internal.InternalApi().upload_file_retry(\n                "http://example.com/upload-dst",\n                example_file.open("rb"),\n            )\n        assert handler.call_count == 1\n\n    def test_stops_after_retry_limit_exceeded(\n        self,\n        example_file: Path,\n        mock_responses: RequestsMock,\n    ):\n        num_retries = 8\n        handler = Mock(return_value=(500, {}, ""))\n        mock_responses.add_callback("PUT", "http://example.com/upload-dst", handler)\n\n        with pytest.raises(wandb.errors.CommError):\n            internal.InternalApi().upload_file_retry(\n                "http://example.com/upload-dst",\n                example_file.open("rb"),\n                num_retries=num_retries,\n            )\n\n        assert handler.call_count == num_retries + 1\n\n\nENABLED_FEATURE_RESPONSE = {\n    "serverInfo": {\n        "features": [\n            {"name": "LARGE_FILENAMES", "isEnabled": True},\n            {"name": "ARTIFACT_TAGS", "isEnabled": False},\n        ]\n    }\n}\n\n\n@pytest.fixture\ndef mock_client(mocker: MockerFixture):\n    mock = mocker.patch("wandb.sdk.internal.internal_api.Client")\n    mock.return_value = mocker.Mock()\n    yield mock.return_value\n\n\n@pytest.fixture\ndef mock_client_with_enabled_features(mock_client):\n    mock_client.execute.return_value = ENABLED_FEATURE_RESPONSE\n    yield mock_client\n\n\nNO_FEATURES_RESPONSE = {"serverInfo": {"features": []}}\n\n\n@pytest.fixture\ndef mock_client_with_no_features(mock_client):\n    mock_client.execute.return_value = NO_FEATURES_RESPONSE\n    yield mock_client\n\n\n@pytest.fixture\ndef mock_client_with_error_no_field(mock_client):\n    error_msg = \'Cannot query field "features" on type "ServerInfo".\'\n    mock_client.execute.side_effect = Exception(error_msg)\n    yield mock_client\n\n\n@pytest.fixture\ndef mock_client_with_random_error(mock_client):\n    error_msg = "Some random error"\n    mock_client.execute.side_effect = Exception(error_msg)\n    yield mock_client\n\n\n@pytest.mark.parametrize(\n    "fixture_name, feature, expected_result, expected_error",\n    [\n        (\n            # Test enabled features\n            mock_client_with_enabled_features.__name__,\n            ServerFeature.LARGE_FILENAMES,\n            True,\n            False,\n        ),\n        (\n            # Test disabled features\n            mock_client_with_enabled_features.__name__,\n            ServerFeature.ARTIFACT_TAGS,\n            False,\n            False,\n        ),\n        (\n            # Test features not in response\n            mock_client_with_enabled_features.__name__,\n            ServerFeature.ARTIFACT_REGISTRY_SEARCH,\n            False,\n            False,\n        ),\n        (\n            # Test empty features list\n            mock_client_with_no_features.__name__,\n            ServerFeature.LARGE_FILENAMES,\n            False,\n            False,\n        ),\n        (\n            # Test server not supporting features\n            mock_client_with_error_no_field.__name__,\n            ServerFeature.LARGE_FILENAMES,\n            False,\n            False,\n        ),\n        (\n            # Test other server errors\n            mock_client_with_random_error.__name__,\n            ServerFeature.LARGE_FILENAMES,\n            False,\n            True,\n        ),\n    ],\n)\n@pytest.mark.usefixtures("patch_apikey", "patch_prompt")\ndef test_server_feature_checks(\n    request,\n    fixture_name,\n    feature: ServerFeature,\n    expected_result,\n    expected_error,\n):\n    """Test check_server_feature with various scenarios."""\n    request.getfixturevalue(fixture_name)\n    api = internal.InternalApi()\n\n    if expected_error:\n        with pytest.raises(Exception, match="Some random error"):\n            api._server_supports(feature)\n    else:\n        result = api._server_supports(feature)\n        assert result == expected_result\n\n\ndef test_construct_use_artifact_query_with_every_field(mocker: MockerFixture):\n    # Create mock internal API instance\n    api = internal.InternalApi()\n\n    mocker.patch.object(api, "settings", side_effect=lambda x: "default-" + x)\n\n    # Mock the server introspection methods\n    mocker.patch.object(\n        api,\n        "server_use_artifact_input_introspection",\n        return_value={"usedAs": "String"},\n    )\n\n    # Simulate server support for ALL known features\n    mock_server_features = dict.fromkeys(\n        chain(ServerFeature.keys(), ServerFeature.values()),\n        True,\n    )\n    mocker.patch.object(api, "_server_features", return_value=mock_server_features)\n\n    test_cases = [\n        {\n            "entity_name": "test-entity",\n            "project_name": "test-project",\n            "run_name": "test-run",\n            "artifact_id": "test-artifact-id",\n            "use_as": "test-use-as",\n            "artifact_entity_name": "test-artifact-entity",\n            "artifact_project_name": "test-artifact-project",\n        },\n        {\n            "entity_name": None,\n            "project_name": None,\n            "run_name": None,\n            "artifact_id": "test-artifact-id",\n            "use_as": None,\n            "artifact_entity_name": "test-artifact-entity",\n            "artifact_project_name": "test-artifact-project",\n        },\n    ]\n\n    for case in test_cases:\n        query, variables = api._construct_use_artifact_query(\n            entity_name=case["entity_name"],\n            project_name=case["project_name"],\n            run_name=case["run_name"],\n            artifact_id=case["artifact_id"],\n            use_as=case["use_as"],\n            artifact_entity_name=case["artifact_entity_name"],\n            artifact_project_name=case["artifact_project_name"],\n        )\n\n        # Verify variables are correctly set\n        expected_variables = {\n            "entityName": case["entity_name"] or "default-entity",\n            "projectName": case["project_name"] or "default-project",\n            "runName": case["run_name"],\n            "artifactID": case["artifact_id"],\n            "usedAs": case["use_as"],\n            "artifactEntityName": case["artifact_entity_name"],\n            "artifactProjectName": case["artifact_project_name"],\n        }\n        assert variables == expected_variables\n\n        query_str = str(query)\n        assert "artifactEntityName" in query_str\n        assert "artifactProjectName" in query_str\n        if case["use_as"]:\n            assert "usedAs" in query_str\n        else:\n            assert "usedAs" not in query_str\n\n\ndef test_construct_use_artifact_query_without_entity_project():\n    # Test when server doesn\'t support entity/project information\n    api = internal.InternalApi()\n    api.settings = Mock(side_effect=lambda x: "default-" + x)\n\n    # Mock methods to return False for entity/project support\n    api.server_use_artifact_input_introspection = Mock(\n        return_value={"usedAs": "String"}\n    )\n    api._server_features = Mock(return_value={})\n\n    query, variables = api._construct_use_artifact_query(\n        entity_name="test-entity",\n        project_name="test-project",\n        run_name="test-run",\n        artifact_id="test-artifact-id",\n        use_as="test-use-as",\n        artifact_entity_name="test-artifact-entity",\n        artifact_project_name="test-artifact-project",\n    )\n    query_str = str(query)\n\n    # Verify entity/project information is not in variables\n    assert "artifactEntityName" not in variables\n    assert "artifactProjectName" not in variables\n    assert "artifactEntityName" not in query_str\n    assert "artifactProjectName" not in query_str\n\n\ndef test_construct_use_artifact_query_without_used_as():\n    # Test when server doesn\'t support usedAs field\n    api = internal.InternalApi()\n    api.settings = Mock(side_effect=lambda x: "default-" + x)\n\n    # Mock methods to return empty dict for introspection\n    api.server_use_artifact_input_introspection = Mock(return_value={})\n    # Simulate server support for ALL known features\n    mock_server_features = dict.fromkeys(\n        chain(ServerFeature.keys(), ServerFeature.values()),\n        True,\n    )\n    api._server_features = Mock(return_value=mock_server_features)\n\n    query, variables = api._construct_use_artifact_query(\n        entity_name="test-entity",\n        project_name="test-project",\n        run_name="test-run",\n        artifact_id="test-artifact-id",\n        use_as="test-use-as",\n        artifact_entity_name="test-artifact-entity",\n        artifact_project_name="test-artifact-project",\n    )\n    query_str = str(query)\n\n    # Verify usedAs is still in variables but not in query\n    assert "usedAs" in variables\n    assert "usedAs:" not in query_str\n\n\nclass TestJWTAuth:\n    def test_jwt_auth_sets_bearer_header(\n        self, tmp_path: pathlib.Path, mocker: MockerFixture\n    ):\n        token_file = tmp_path / "token.jwt"\n        token_file.write_text("test.jwt.token")\n\n        mocker.patch(\n            "wandb.sdk.lib.wbauth.AuthIdentityTokenFile.fetch_access_token",\n            return_value="test_access_token_12345",\n        )\n\n        environ = {"WANDB_IDENTITY_TOKEN_FILE": str(token_file)}\n        api = internal.InternalApi(environ=environ)\n\n        assert "Authorization" in api._extra_http_headers\n        assert (\n            api._extra_http_headers["Authorization"] == "Bearer test_access_token_12345"\n        )\n\n    def test_api_key_takes_precedence_over_jwt(\n        self, tmp_path: pathlib.Path, mocker: MockerFixture\n    ):\n        token_file = tmp_path / "token.jwt"\n        token_file.write_text("test.jwt.token")\n\n        fetch_mock = mocker.patch(\n            "wandb.sdk.lib.wbauth.AuthIdentityTokenFile.fetch_access_token",\n            return_value="test_access_token",\n        )\n\n        environ = {"WANDB_IDENTITY_TOKEN_FILE": str(token_file)}\n        api = internal.InternalApi(\n            default_settings={"api_key": "a" * 40},\n            environ=environ,\n        )\n\n        fetch_mock.assert_not_called()\n        assert api.client.transport.session.auth == ("api", "a" * 40)\n\n    def test_access_token_returns_none_without_token_file(self):\n        api = internal.InternalApi(environ={})\n        assert api.access_token is None\n\n    def test_access_token_raises_for_missing_file(self, tmp_path: pathlib.Path):\n        missing_file = tmp_path / "nonexistent.jwt"\n        environ = {"WANDB_IDENTITY_TOKEN_FILE": str(missing_file)}\n\n        with pytest.raises(wandb.errors.AuthenticationError, match="not found"):\n            internal.InternalApi(environ=environ)\n',
            'wandb/agents/pyagent.py': '"""Agent - Agent object.\n\nManage wandb agent.\n\n"""\n\nimport ctypes\nimport logging\nimport os\nimport queue\nimport socket\nimport sys\nimport threading\nimport time\nimport traceback\n\nimport wandb\nfrom wandb.apis import InternalApi\nfrom wandb.sdk.launch.sweeps import utils as sweep_utils\nfrom wandb.sdk.lib import config_util\n\nlogger = logging.getLogger(__name__)\n\n\ndef _terminate_thread(thread):\n    if not thread.is_alive():\n        return\n    if hasattr(thread, "_terminated"):\n        return\n    thread._terminated = True\n    tid = getattr(thread, "_thread_id", None)\n    if tid is None:\n        for k, v in threading._active.items():\n            if v is thread:\n                tid = k\n    if tid is None:\n        # This should never happen\n        return\n    logger.debug(f"Terminating thread: {tid}")\n    res = ctypes.pythonapi.PyThreadState_SetAsyncExc(\n        ctypes.c_long(tid), ctypes.py_object(Exception)\n    )\n    if res == 0:\n        # This should never happen\n        return\n    elif res != 1:\n        # Revert\n        logger.debug(f"Termination failed for thread {tid}")\n        ctypes.pythonapi.PyThreadState_SetAsyncExc(ctypes.c_long(tid), None)\n\n\nclass Job:\n    def __init__(self, command):\n        self.command = command\n        job_type = command.get("type")\n        self.type = job_type\n        self.run_id = command.get("run_id")\n        self.config = command.get("args")\n\n    def __repr__(self):\n        if self.type == "run":\n            return f"Job({self.run_id},{self.config})"\n        elif self.type == "stop":\n            return f"stop({self.run_id})"\n        else:\n            return "exit"\n\n\nclass RunStatus:\n    QUEUED = "QUEUED"\n    RUNNING = "RUNNING"\n    STOPPED = "STOPPED"\n    ERRORED = "ERRORED"\n    DONE = "DONE"\n\n\nclass Agent:\n    FLAPPING_MAX_SECONDS = 60\n    FLAPPING_MAX_FAILURES = 3\n    MAX_INITIAL_FAILURES = 5\n\n    def __init__(\n        self, sweep_id=None, project=None, entity=None, function=None, count=None\n    ):\n        self._sweep_path = sweep_id\n        self._sweep_id = None\n        self._project = project\n        self._entity = entity\n        self._function = function\n        self._count = count\n        # glob_config = os.path.expanduser(\'~/.config/wandb/settings\')\n        # loc_config = \'wandb/settings\'\n        # files = (glob_config, loc_config)\n        self._api = InternalApi()\n        self._agent_id = None\n        self._max_initial_failures = wandb.env.get_agent_max_initial_failures(\n            self.MAX_INITIAL_FAILURES\n        )\n        # if the directory to log to is not set, set it\n        if os.environ.get(wandb.env.DIR) is None:\n            os.environ[wandb.env.DIR] = os.path.abspath(os.getcwd())\n\n    def _init(self):\n        # These are not in constructor so that Agent instance can be rerun\n        self._run_threads = {}\n        self._run_status = {}\n        self._queue = queue.Queue()\n        self._exit_flag = False\n        self._exceptions = {}\n        self._start_time = time.time()\n\n    def _register(self):\n        logger.debug("Agent._register()")\n        agent = self._api.register_agent(socket.gethostname(), sweep_id=self._sweep_id)\n        self._agent_id = agent["id"]\n        logger.debug(f"agent_id = {self._agent_id}")\n\n    def _setup(self):\n        logger.debug("Agent._setup()")\n        self._init()\n        parts = dict(entity=self._entity, project=self._project, name=self._sweep_path)\n        err = sweep_utils.parse_sweep_id(parts)\n        if err:\n            wandb.termerror(err)\n            return\n        entity = parts.get("entity") or self._entity\n        project = parts.get("project") or self._project\n        sweep_id = parts.get("name") or self._sweep_id\n        if sweep_id:\n            os.environ[wandb.env.SWEEP_ID] = sweep_id\n        if entity:\n            wandb.env.set_entity(entity)\n        if project:\n            wandb.env.set_project(project)\n        if sweep_id:\n            self._sweep_id = sweep_id\n        self._register()\n\n    def _stop_run(self, run_id):\n        logger.debug(f"Stopping run {run_id}.")\n        self._run_status[run_id] = RunStatus.STOPPED\n        thread = self._run_threads.get(run_id)\n        if thread:\n            _terminate_thread(thread)\n\n    def _stop_all_runs(self):\n        logger.debug("Stopping all runs.")\n        for run in list(self._run_threads.keys()):\n            self._stop_run(run)\n\n    def _exit(self):\n        self._stop_all_runs()\n        self._exit_flag = True\n        # _terminate_thread(self._main_thread)\n\n    def _heartbeat(self):\n        while True:\n            if self._exit_flag:\n                return\n            # if not self._main_thread.is_alive():\n            #     return\n            run_status = {\n                run: True\n                for run, status in self._run_status.items()\n                if status in (RunStatus.QUEUED, RunStatus.RUNNING)\n            }\n            commands = self._api.agent_heartbeat(self._agent_id, {}, run_status)\n            if commands:\n                job = Job(commands[0])\n                logger.debug(f"Job received: {job}")\n                if job.type in ["run", "resume"]:\n                    self._queue.put(job)\n                    self._run_status[job.run_id] = RunStatus.QUEUED\n                elif job.type == "stop":\n                    self._stop_run(job.run_id)\n                elif job.type == "exit":\n                    self._exit()\n                    return\n            time.sleep(5)\n\n    def _run_jobs_from_queue(self):\n        global _INSTANCES\n        _INSTANCES += 1\n        try:\n            waiting = False\n            count = 0\n            while True:\n                if self._exit_flag:\n                    return\n                try:\n                    try:\n                        job = self._queue.get(timeout=5)\n                        if self._exit_flag:\n                            logger.debug("Exiting main loop due to exit flag.")\n                            wandb.termlog("Sweep Agent: Exiting.")\n                            return\n                    except queue.Empty:\n                        if not waiting:\n                            logger.debug("Paused.")\n                            wandb.termlog("Sweep Agent: Waiting for job.")\n                            waiting = True\n                        time.sleep(5)\n                        if self._exit_flag:\n                            logger.debug("Exiting main loop due to exit flag.")\n                            wandb.termlog("Sweep Agent: Exiting.")\n                            return\n                        continue\n                    if waiting:\n                        logger.debug("Resumed.")\n                        wandb.termlog("Job received.")\n                        waiting = False\n                    count += 1\n                    run_id = job.run_id\n                    if self._run_status[run_id] == RunStatus.STOPPED:\n                        continue\n                    logger.debug(f"Spawning new thread for run {run_id}.")\n                    thread = threading.Thread(target=self._run_job, args=(job,))\n                    self._run_threads[run_id] = thread\n                    thread.start()\n                    self._run_status[run_id] = RunStatus.RUNNING\n                    thread.join()\n                    logger.debug(f"Thread joined for run {run_id}.")\n                    if self._run_status[run_id] == RunStatus.RUNNING:\n                        self._run_status[run_id] = RunStatus.DONE\n                    elif self._run_status[run_id] == RunStatus.ERRORED:\n                        exc = self._exceptions[run_id]\n                        # Extract to reduce a decision point to avoid ruff c901\n                        log_str, term_str = _get_exception_logger_and_term_strs(exc)\n                        logger.error(f"Run {run_id} errored:\\n{log_str}")\n                        wandb.termerror(f"Run {run_id} errored:{term_str}")\n                        if os.getenv(wandb.env.AGENT_DISABLE_FLAPPING) == "true":\n                            self._exit_flag = True\n                            return\n                        elif (\n                            time.time() - self._start_time < self.FLAPPING_MAX_SECONDS\n                        ) and (len(self._exceptions) >= self.FLAPPING_MAX_FAILURES):\n                            msg = f"Detected {self.FLAPPING_MAX_FAILURES} failed runs in the first {self.FLAPPING_MAX_SECONDS} seconds, killing sweep."\n                            logger.error(msg)\n                            wandb.termerror(msg)\n                            wandb.termlog(\n                                "To disable this check set WANDB_AGENT_DISABLE_FLAPPING=true"\n                            )\n                            self._exit_flag = True\n                            return\n                        if (\n                            self._max_initial_failures < len(self._exceptions)\n                            and len(self._exceptions) >= count\n                        ):\n                            msg = f"Detected {self._max_initial_failures} failed runs in a row at start, killing sweep."\n                            logger.error(msg)\n                            wandb.termerror(msg)\n                            wandb.termlog(\n                                "To change this value set WANDB_AGENT_MAX_INITIAL_FAILURES=val"\n                            )\n                            self._exit_flag = True\n                            return\n                    if self._count and self._count == count:\n                        logger.debug("Exiting main loop because max count reached.")\n                        self._exit_flag = True\n                        return\n                except KeyboardInterrupt:\n                    logger.debug("Ctrl + C detected. Stopping sweep.")\n                    wandb.termlog("Ctrl + C detected. Stopping sweep.")\n                    self._exit()\n                    return\n                except Exception:\n                    if self._exit_flag:\n                        logger.debug("Exiting main loop due to exit flag.")\n                        wandb.termlog("Sweep Agent: Killed.")\n                        return\n                    else:\n                        raise\n        finally:\n            _INSTANCES -= 1\n\n    def _run_job(self, job):\n        try:\n            run_id = job.run_id\n\n            config_file = os.path.join(\n                "wandb", "sweep-" + self._sweep_id, "config-" + run_id + ".yaml"\n            )\n            os.environ[wandb.env.RUN_ID] = run_id\n            base_dir = os.environ.get(wandb.env.DIR, "")\n            sweep_param_path = os.path.join(base_dir, config_file)\n            os.environ[wandb.env.SWEEP_PARAM_PATH] = sweep_param_path\n            config_util.save_config_file_from_dict(sweep_param_path, job.config)\n            os.environ[wandb.env.SWEEP_ID] = self._sweep_id\n            wandb.teardown()\n\n            wandb.termlog(f"Agent Starting Run: {run_id} with config:")\n            for k, v in job.config.items():\n                wandb.termlog("\\t{}: {}".format(k, v["value"]))\n\n            try:\n                self._function()\n            except KeyboardInterrupt:\n                raise\n            except Exception as e:\n                # Log the run\'s exceptions directly to stderr to match CLI case, and wrap so we\n                # can identify it as coming from the job later later. This will get automatically\n                # logged by console_capture.py. Exception handler below will also handle exceptions\n                # in setup code.\n                exc_repr = _format_exception_traceback(e)\n                print(exc_repr, file=sys.stderr)  # noqa: T201\n                raise _JobError(f"Run threw exception: {str(e)}") from e\n            wandb.finish()\n        except KeyboardInterrupt:\n            raise\n        except Exception as e:\n            wandb.finish(exit_code=1)\n            if self._run_status[run_id] == RunStatus.RUNNING:\n                self._run_status[run_id] = RunStatus.ERRORED\n                self._exceptions[run_id] = e\n        finally:\n            # clean up the environment changes made\n            os.environ.pop(wandb.env.RUN_ID, None)\n            os.environ.pop(wandb.env.SWEEP_ID, None)\n            os.environ.pop(wandb.env.SWEEP_PARAM_PATH, None)\n\n    def run(self):\n        logger.info(\n            f"Starting sweep agent: entity={self._entity}, project={self._project}, count={self._count}"\n        )\n        self._setup()\n        # self._main_thread = threading.Thread(target=self._run_jobs_from_queue)\n        self._heartbeat_thread = threading.Thread(target=self._heartbeat)\n        self._heartbeat_thread.daemon = True\n        # self._main_thread.start()\n        self._heartbeat_thread.start()\n        # self._main_thread.join()\n        self._run_jobs_from_queue()\n\n\ndef pyagent(sweep_id, function, entity=None, project=None, count=None):\n    """Generic agent entrypoint, used for CLI or jupyter.\n\n    Args:\n        sweep_id (dict): Sweep ID generated by CLI or sweep API\n        function (func, optional): A function to call instead of the "program"\n        entity (str, optional): W&B Entity\n        project (str, optional): W&B Project\n        count (int, optional): the number of trials to run.\n    """\n    if not callable(function):\n        raise TypeError("function parameter must be callable!")\n    agent = Agent(\n        sweep_id,\n        function=function,\n        entity=entity,\n        project=project,\n        count=count,\n    )\n    agent.run()\n\n\ndef _format_exception_traceback(exc):\n    return "".join(traceback.format_exception(type(exc), exc, exc.__traceback__))\n\n\nclass _JobError(Exception):\n    """Exception raised when a job fails during execution."""\n\n    pass\n\n\ndef _get_exception_logger_and_term_strs(exc):\n    if isinstance(exc, _JobError) and exc.__cause__:\n        # If it\'s a JobException, get the original exception for display\n        job_exc = exc.__cause__\n        log_str = _format_exception_traceback(job_exc)\n        # Don\'t long full stacktrace to terminal again because we already\n        # printed it to stderr.\n        term_str = " " + str(job_exc)\n    else:\n        log_str = _format_exception_traceback(exc)\n        term_str = "\\n" + log_str\n    return log_str, term_str\n\n\n_INSTANCES = 0\n\n\ndef is_running():\n    return bool(_INSTANCES)\n',
            'wandb/cli/cli.py': 'import asyncio\nimport datetime\nimport getpass\nimport json\nimport logging\nimport os\nimport shlex\nimport shutil\nimport subprocess\nimport sys\nimport tempfile\nimport textwrap\nimport time\nimport traceback\nfrom functools import wraps\nfrom typing import Any, Dict, Optional, Tuple\n\nimport click\nimport yaml\nfrom click.exceptions import ClickException\n\nimport wandb\nimport wandb.errors\nimport wandb.sdk.verify.verify as wandb_verify\nfrom wandb import Config, Error, env, util, wandb_agent\nfrom wandb.analytics import get_sentry\nfrom wandb.apis import InternalApi, PublicApi\nfrom wandb.apis.public import RunQueue\nfrom wandb.errors.links import url_registry\nfrom wandb.old import core as old_core\nfrom wandb.sdk import wandb_setup, wandb_sweep\nfrom wandb.sdk.artifacts._validators import is_artifact_registry_project\nfrom wandb.sdk.artifacts.artifact_file_cache import get_artifact_file_cache\nfrom wandb.sdk.internal.internal_api import Api as SDKInternalApi\nfrom wandb.sdk.launch import utils as launch_utils\nfrom wandb.sdk.launch._launch_add import _launch_add\nfrom wandb.sdk.launch.errors import ExecutionError, LaunchError\nfrom wandb.sdk.launch.sweeps import utils as sweep_utils\nfrom wandb.sdk.launch.sweeps.scheduler import Scheduler\nfrom wandb.sdk.lib import filesystem, settings_file\nfrom wandb.sync import SyncManager, get_run_from_path, get_runs\n\nfrom .beta import beta\n\n# Send cli logs to wandb/debug-cli.<username>.log by default and fallback to a temp dir.\n_wandb_dir = old_core.wandb_dir(env.get_dir())\nif not os.path.exists(_wandb_dir) or not os.access(_wandb_dir, os.W_OK):\n    _wandb_dir = tempfile.gettempdir()\n\ntry:\n    _username = getpass.getuser()\nexcept KeyError:\n    # getuser() could raise KeyError in restricted environments like\n    # chroot jails or docker containers. Return user id in these cases.\n    _username = str(os.getuid())\n\n_wandb_log_path = os.path.join(_wandb_dir, f"debug-cli.{_username}.log")\nlogger = logging.getLogger("wandb")\n\n\ndef _setup_logger() -> None:\n    """Set up logging to the wandb/debug-cli.user.log file."""\n    logger_handler = logging.FileHandler(_wandb_log_path)\n    logger_handler.setLevel(logging.INFO)\n    logger_handler.setFormatter(\n        logging.Formatter(\n            fmt="%(asctime)s %(levelname)s %(message)s",\n            datefmt="%Y-%m-%d %H:%M:%S",\n        )\n    )\n\n    # The wandb logger does not forward messages to the root handler.\n    logger.addHandler(logger_handler)\n    logging.root.addHandler(logger_handler)\n\n\n_HAS_DOCKER = bool(shutil.which("docker"))\n_HAS_NVIDIA_DOCKER = bool(shutil.which("nvidia-docker"))\n\n# Click Contexts\nCONTEXT = {"default_map": {}}\nRUN_CONTEXT = {\n    "default_map": {},\n    "allow_extra_args": True,\n    "ignore_unknown_options": True,\n}\n\n\ndef cli_unsupported(argument):\n    wandb.termerror(f"Unsupported argument `{argument}`")\n    sys.exit(1)\n\n\nclass ClickWandbException(ClickException):\n    def format_message(self):\n        orig_type = f"{self.orig_type.__module__}.{self.orig_type.__name__}"\n        if issubclass(self.orig_type, Error):\n            return click.style(str(self.message), fg="red")\n        else:\n            return (\n                f"An Exception was raised, see {_wandb_log_path} for full"\n                " traceback.\\n"\n                f"{orig_type}: {self.message}"\n            )\n\n\ndef parse_service_config(\n    ctx: Optional[click.Context],\n    param: Optional[click.Parameter],\n    value: Optional[Tuple[str, ...]],\n) -> Dict[str, str]:\n    """Parse service configurations in format serviceName=policy."""\n    if not value:\n        return {}\n\n    result = {}\n    for config in value:\n        if "=" not in config:\n            raise click.BadParameter(\n                f"Service must be in format \'serviceName=policy\', got \'{config}\'"\n            )\n\n        service_name, policy = config.split("=", 1)\n        service_name = service_name.strip()\n        policy = policy.strip()\n        if not service_name:\n            raise click.BadParameter("Service name cannot be empty")\n\n        # Simple validation for two policies\n        if policy not in ["always", "never"]:\n            raise click.BadParameter(\n                f"Policy must be \'always\' or \'never\', got \'{policy}\'"\n            )\n\n        result[service_name] = policy\n\n    return result\n\n\ndef display_error(func):\n    """Function decorator for catching common errors and re-raising as wandb.Error."""\n\n    @wraps(func)\n    def wrapper(*args, **kwargs):\n        try:\n            return func(*args, **kwargs)\n        except wandb.Error as e:\n            exc_type, exc_value, exc_traceback = sys.exc_info()\n            lines = traceback.format_exception(exc_type, exc_value, exc_traceback)\n            logger.exception("".join(lines))\n            wandb.termerror(f"Find detailed error logs at: {_wandb_log_path}")\n            click_exc = ClickWandbException(e)\n            click_exc.orig_type = exc_type\n            raise click_exc.with_traceback(sys.exc_info()[2])\n\n    return wrapper\n\n\n_api = None  # caching api instance allows patching from unit tests\n\n\ndef _get_cling_api(reset=None):\n    """Get a reference to the internal api with cling settings."""\n    global _api\n    if reset:\n        _api = None\n        wandb.teardown()\n    if _api is None:\n        # TODO(jhr): make a settings object that is better for non runs.\n        # only override the necessary setting\n        wandb_setup.singleton().settings.x_cli_only_mode = True\n        _api = InternalApi()\n    return _api\n\n\ndef prompt_for_project(ctx, entity):\n    """Ask the user for a project, creating one if necessary."""\n    result = ctx.invoke(projects, entity=entity, display=False)\n    api = _get_cling_api()\n    try:\n        if len(result) == 0:\n            project = click.prompt("Enter a name for your first project")\n            # description = editor()\n            project = api.upsert_project(project, entity=entity)["name"]\n        else:\n            project_names = [project["name"] for project in result] + ["Create New"]\n            wandb.termlog("Which project should we use?")\n            result = util.prompt_choices(project_names)\n            if result:\n                project = result\n            else:\n                project = "Create New"\n            # TODO: check with the server if the project exists\n            if project == "Create New":\n                project = click.prompt(\n                    "Enter a name for your new project", value_proc=api.format_project\n                )\n                # description = editor()\n                project = api.upsert_project(project, entity=entity)["name"]\n\n    except wandb.errors.CommError as e:\n        raise ClickException(str(e))\n\n    return project\n\n\nclass RunGroup(click.Group):\n    @display_error\n    def get_command(self, ctx, cmd_name):\n        # TODO: check if cmd_name is a file in the current dir and not require `run`?\n        rv = click.Group.get_command(self, ctx, cmd_name)\n        if rv is not None:\n            return rv\n        return None\n\n\n@click.command(cls=RunGroup, invoke_without_command=True)\n@click.version_option(version=wandb.__version__)\n@click.pass_context\ndef cli(ctx):\n    _setup_logger()\n\n    if ctx.invoked_subcommand is None:\n        click.echo(ctx.get_help())\n\n\n@cli.command(context_settings=CONTEXT, help="List projects", hidden=True)\n@click.option(\n    "--entity",\n    "-e",\n    default=None,\n    envvar=env.ENTITY,\n    help="The entity to scope the listing to.",\n)\n@display_error\ndef projects(entity, display=True):\n    api = _get_cling_api()\n    projects = api.list_projects(entity=entity)\n    if len(projects) == 0:\n        message = f"No projects found for {entity}"\n    else:\n        message = f\'Latest projects for "{entity}"\'\n    if display:\n        click.echo(click.style(message, bold=True))\n        for project in projects:\n            click.echo(\n                "".join(\n                    (\n                        click.style(project["name"], fg="blue", bold=True),\n                        " - ",\n                        str(project["description"] or "").split("\\n")[0],\n                    )\n                )\n            )\n    return projects\n\n\n@cli.command(context_settings=CONTEXT)\n@click.argument("key", nargs=-1)\n@click.option("--cloud", is_flag=True, help="Login to the cloud instead of local")\n@click.option(\n    "--host", "--base-url", default=None, help="Login to a specific instance of W&B"\n)\n@click.option(\n    "--relogin", default=None, is_flag=True, help="Force relogin if already logged in."\n)\n@click.option(\n    "--anonymously",\n    default=False,\n    hidden=True,\n    is_flag=True,\n    help="Log in anonymously",\n)\n@click.option(\n    "--verify/--no-verify",\n    default=False,\n    is_flag=True,\n    help="Verify login credentials",\n)\n@display_error\ndef login(key, host, cloud, relogin, anonymously, verify, no_offline=False):\n    """Verify and store your API key for authentication with W&B services.\n\n    By default, only store credentials locally without verifying them with W&B.\n    To verify credentials, set `--verify=True`.\n\n    For server deployments (dedicated cloud or customer-managed instances),\n    specify the host URL using the `--host` flag. You can also set environment\n    variables `WANDB_BASE_URL` and `WANDB_API_KEY` instead of running\n    the `login` command with host parameters.\n    """\n    # TODO: handle no_offline\n    if anonymously:\n        wandb.termwarn(\n            "The --anonymously parameter has no effect and will be removed"\n            + " in a future version.",\n            repeat=False,\n        )\n\n    if host and cloud:\n        wandb.termerror("Cannot use --host and --cloud together.")\n        sys.exit(1)\n\n    if cloud:\n        host = "https://api.wandb.ai"\n\n    # A change in click or the test harness means key can be none...\n    key = key[0] if key is not None and len(key) > 0 else None\n    relogin = True if key or relogin else False\n\n    global_settings = wandb_setup.singleton().settings\n    global_settings.x_cli_only_mode = True\n    global_settings.x_disable_viewer = relogin and not verify\n\n    wandb.login(\n        force=True,\n        host=host,\n        key=key,\n        relogin=relogin,\n        verify=verify,\n        referrer="models",\n    )\n\n\n@cli.command(\n    context_settings=CONTEXT, help="Configure a directory with Weights & Biases"\n)\n@click.option("--project", "-p", help="The project to use.")\n@click.option("--entity", "-e", help="The entity to scope the project to.")\n# TODO(jhr): Enable these with settings rework\n# @click.option("--setting", "-s", help="enable an arbitrary setting.", multiple=True)\n# @click.option(\'--show\', is_flag=True, help="Show settings")\n@click.option("--reset", is_flag=True, help="Reset settings")\n@click.option(\n    "--mode",\n    "-m",\n    help=\' Can be "online", "offline" or "disabled". Defaults to online.\',\n)\n@click.pass_context\n@display_error\ndef init(ctx, project, entity, reset, mode):\n    # Load settings from environment variables and other normal sources.\n    global_settings = wandb_setup.singleton().settings\n\n    # non-interactive init\n    if reset or project or entity or mode:\n        system_settings = global_settings.read_system_settings()\n\n        if reset:\n            system_settings.clear("entity")\n            system_settings.clear("project")\n            system_settings.clear("mode")\n        if entity:\n            system_settings.set("entity", entity)\n        if project:\n            system_settings.set("project", project)\n        if mode:\n            system_settings.set("mode", mode)\n\n        system_settings.save()\n        return\n\n    if os.path.exists(global_settings.settings_workspace):\n        click.confirm(\n            click.style(\n                "This directory has been configured previously, should we re-configure it?",\n                bold=True,\n            ),\n            abort=True,\n        )\n    else:\n        click.echo(\n            click.style("Let\'s setup this directory for W&B!", fg="green", bold=True)\n        )\n    api = _get_cling_api()\n    if api.api_key is None:\n        ctx.invoke(login)\n        api = _get_cling_api(reset=True)\n\n    viewer = api.viewer()\n\n    # Viewer can be `None` in case your API information became invalid, or\n    # in testing if you switch hosts.\n    if not viewer:\n        click.echo(\n            click.style(\n                "Your login information seems to be invalid: can you log in again please?",\n                fg="red",\n                bold=True,\n            )\n        )\n        ctx.invoke(login)\n        api = _get_cling_api(reset=True)\n\n    # This shouldn\'t happen.\n    viewer = api.viewer()\n    if not viewer:\n        click.echo(\n            click.style(\n                "We\'re sorry, there was a problem logging you in. "\n                "Please send us a note at support@wandb.com and tell us how this happened.",\n                fg="red",\n                bold=True,\n            )\n        )\n        sys.exit(1)\n\n    # At this point we should be logged in successfully.\n    if len(viewer["teams"]["edges"]) > 1:\n        team_names = [e["node"]["name"] for e in viewer["teams"]["edges"]] + [\n            "Manual entry"\n        ]\n        wandb.termlog(\n            "Which team should we use?",\n        )\n        result = util.prompt_choices(team_names)\n        # result can be empty on click\n        if result:\n            entity = result\n        else:\n            entity = "Manual Entry"\n        if entity == "Manual Entry":\n            entity = click.prompt("Enter the name of the team you want to use")\n    else:\n        entity = viewer.get("entity") or click.prompt(\n            "What username or team should we use?"\n        )\n\n    # TODO: this error handling sucks and the output isn\'t pretty\n    try:\n        project = prompt_for_project(ctx, entity)\n    except ClickWandbException:\n        raise ClickException(f"Could not find team: {entity}")\n\n    system_settings = global_settings.read_system_settings()\n    system_settings.set("entity", entity)\n    system_settings.set("project", project)\n    system_settings.save()\n\n    filesystem.mkdir_exists_ok(global_settings.wandb_dir)\n    with open(os.path.join(global_settings.wandb_dir, ".gitignore"), "w") as file:\n        file.write("*\\n!settings")\n\n    click.echo(\n        click.style("This directory is configured!  Next, track a run:\\n", fg="green")\n        + textwrap.dedent(\n            """\\\n        * In your training script:\n            {code1}\n            {code2}\n        * then `{run}`.\n        """\n        ).format(\n            code1=click.style("import wandb", bold=True),\n            code2=click.style(f\'wandb.init(project="{project}")\', bold=True),\n            run=click.style("python <train.py>", bold=True),\n        )\n    )\n\n\n@cli.command(context_settings=CONTEXT)\n@click.pass_context\n@click.argument("path", nargs=-1, type=click.Path(exists=True))\n@click.option("--view", is_flag=True, default=False, help="View runs", hidden=True)\n@click.option("--verbose", is_flag=True, default=False, help="Verbose", hidden=True)\n@click.option("--id", "run_id", help="The run you want to upload to.")\n@click.option("--project", "-p", help="The project you want to upload to.")\n@click.option("--entity", "-e", help="The entity to scope to.")\n@click.option(\n    "--job_type",\n    "job_type",\n    help="Specifies the type of run for grouping related runs together.",\n)\n@click.option(\n    "--sync-tensorboard/--no-sync-tensorboard",\n    is_flag=True,\n    default=None,\n    help="Stream tfevent files to wandb.",\n)\n@click.option("--include-globs", help="Comma separated list of globs to include.")\n@click.option("--exclude-globs", help="Comma separated list of globs to exclude.")\n@click.option(\n    "--include-online/--no-include-online",\n    is_flag=True,\n    default=None,\n    help="Include online runs",\n)\n@click.option(\n    "--include-offline/--no-include-offline",\n    is_flag=True,\n    default=None,\n    help="Include offline runs",\n)\n@click.option(\n    "--include-synced/--no-include-synced",\n    is_flag=True,\n    default=None,\n    help="Include synced runs",\n)\n@click.option(\n    "--mark-synced/--no-mark-synced",\n    is_flag=True,\n    default=True,\n    help="Mark runs as synced",\n)\n@click.option("--sync-all", is_flag=True, default=False, help="Sync all runs")\n@click.option("--clean", is_flag=True, default=False, help="Delete synced runs")\n@click.option(\n    "--clean-old-hours",\n    default=24,\n    help="Delete runs created before this many hours. To be used alongside --clean flag.",\n    type=int,\n)\n@click.option(\n    "--clean-force",\n    is_flag=True,\n    default=False,\n    help="Clean without confirmation prompt.",\n)\n@click.option("--ignore", hidden=True)\n@click.option("--show", default=5, help="Number of runs to show")\n@click.option("--append", is_flag=True, default=False, help="Append run")\n@click.option("--skip-console", is_flag=True, default=False, help="Skip console logs")\n@click.option(\n    "--replace-tags",\n    help="Replace tags in the format \'old_tag1=new_tag1,old_tag2=new_tag2\'",\n)\n@display_error\ndef sync(\n    ctx,\n    path=None,\n    view=None,\n    verbose=None,\n    run_id=None,\n    project=None,\n    entity=None,\n    job_type=None,  # trace this back to SyncManager\n    sync_tensorboard=None,\n    include_globs=None,\n    exclude_globs=None,\n    include_online=None,\n    include_offline=None,\n    include_synced=None,\n    mark_synced=None,\n    sync_all=None,\n    ignore=None,\n    show=None,\n    clean=None,\n    clean_old_hours=24,\n    clean_force=None,\n    append=None,\n    skip_console=None,\n    replace_tags=None,\n):\n    """Synchronize W&B run data to the cloud.\n\n    If PATH is provided, sync runs found at the given path. If a path\n    is not specified, search for `./wandb` first, then search for a\n    `wandb/` subdirectory.\n\n    To sync a specific run:\n\n        wandb sync ./wandb/run-20250813_124246-n67z9ude\n\n    Or equivalently:\n\n        wandb sync ./wandb/run-20250813_124246-n67z9ude/run-n67z9ude.wandb\n    """\n    api = _get_cling_api()\n    if not api.is_authenticated:\n        wandb.termlog("Login to W&B to sync runs")\n        ctx.invoke(login, no_offline=True)\n        api = _get_cling_api(reset=True)\n\n    if ignore:\n        exclude_globs = ignore\n    if include_globs:\n        include_globs = include_globs.split(",")\n    if exclude_globs:\n        exclude_globs = exclude_globs.split(",")\n\n    replace_tags_dict = _parse_sync_replace_tags(replace_tags)\n    if replace_tags and replace_tags_dict is None:\n        return  # Error already printed by helper function\n\n    def _summary():\n        all_items = get_runs(\n            include_online=True,\n            include_offline=True,\n            include_synced=True,\n            include_unsynced=True,\n        )\n        sync_items = get_runs(\n            include_online=include_online if include_online is not None else True,\n            include_offline=include_offline if include_offline is not None else True,\n            include_synced=include_synced if include_synced is not None else False,\n            include_unsynced=True,\n            exclude_globs=exclude_globs,\n            include_globs=include_globs,\n        )\n        synced = []\n        unsynced = []\n        for item in all_items:\n            (synced if item.synced else unsynced).append(item)\n        if sync_items:\n            wandb.termlog(f"Number of runs to be synced: {len(sync_items)}")\n            if show and show < len(sync_items):\n                wandb.termlog(f"Showing {show} runs to be synced:")\n            for item in sync_items[: (show or len(sync_items))]:\n                wandb.termlog(f"  {item}")\n        else:\n            wandb.termlog("No runs to be synced.")\n        if synced:\n            clean_cmd = click.style("wandb sync --clean", fg="yellow")\n            wandb.termlog(\n                f"NOTE: use {clean_cmd} to delete {len(synced)} synced runs from local directory."\n            )\n        if unsynced:\n            sync_cmd = click.style("wandb sync --sync-all", fg="yellow")\n            wandb.termlog(\n                f"NOTE: use {sync_cmd} to sync {len(unsynced)} unsynced runs from local directory."\n            )\n\n    def _sync_path(_path, _sync_tensorboard):\n        if run_id and len(_path) > 1:\n            wandb.termerror("id can only be set for a single run.")\n            sys.exit(1)\n        sm = SyncManager(\n            project=project,\n            entity=entity,\n            run_id=run_id,\n            job_type=job_type,\n            mark_synced=mark_synced,\n            app_url=api.app_url,\n            view=view,\n            verbose=verbose,\n            sync_tensorboard=_sync_tensorboard,\n            log_path=_wandb_log_path,\n            append=append,\n            skip_console=skip_console,\n            replace_tags=replace_tags_dict,\n        )\n        for p in _path:\n            sm.add(p)\n        sm.start()\n        while not sm.is_done():\n            _ = sm.poll()\n\n    def _sync_all():\n        sync_items = get_runs(\n            include_online=include_online if include_online is not None else True,\n            include_offline=include_offline if include_offline is not None else True,\n            include_synced=include_synced if include_synced is not None else False,\n            include_unsynced=True,\n            exclude_globs=exclude_globs,\n            include_globs=include_globs,\n        )\n        if not sync_items:\n            wandb.termerror("Nothing to sync.")\n        else:\n            # When syncing run directories, default to not syncing tensorboard\n            sync_tb = sync_tensorboard if sync_tensorboard is not None else False\n            _sync_path(sync_items, sync_tb)\n\n    def _clean():\n        if path:\n            runs = list(map(get_run_from_path, path))\n            if not clean_force:\n                click.confirm(\n                    click.style(\n                        f"Are you sure you want to remove {len(runs)} runs?",\n                        bold=True,\n                    ),\n                    abort=True,\n                )\n            for run in runs:\n                shutil.rmtree(run.path)\n            click.echo(click.style("Success!", fg="green"))\n            return\n        runs = get_runs(\n            include_online=include_online if include_online is not None else True,\n            include_offline=include_offline if include_offline is not None else True,\n            include_synced=include_synced if include_synced is not None else True,\n            include_unsynced=False,\n            exclude_globs=exclude_globs,\n            include_globs=include_globs,\n        )\n        since = datetime.datetime.now() - datetime.timedelta(hours=clean_old_hours)\n        old_runs = [run for run in runs if run.datetime < since]\n        old_runs.sort(key=lambda _run: _run.datetime)\n        if old_runs:\n            click.echo(\n                f"Found {len(runs)} runs, {len(old_runs)} are older than {clean_old_hours} hours"\n            )\n            for run in old_runs:\n                click.echo(run.path)\n            if not clean_force:\n                click.confirm(\n                    click.style(\n                        f"Are you sure you want to remove {len(old_runs)} runs?",\n                        bold=True,\n                    ),\n                    abort=True,\n                )\n            for run in old_runs:\n                shutil.rmtree(run.path)\n            click.echo(click.style("Success!", fg="green"))\n        else:\n            click.echo(\n                click.style(\n                    f"No runs older than {clean_old_hours} hours found", fg="red"\n                )\n            )\n\n    if sync_all:\n        _sync_all()\n    elif clean:\n        _clean()\n    elif path:\n        # When syncing a specific path, default to syncing tensorboard\n        sync_tb = sync_tensorboard if sync_tensorboard is not None else True\n        _sync_path(path, sync_tb)\n    else:\n        _summary()\n\n\ndef _parse_sync_replace_tags(replace_tags: str) -> Optional[Dict[str, str]]:\n    """Parse replace_tags string into a dictionary.\n\n    Args:\n        replace_tags: String in format \'old_tag1=new_tag1,old_tag2=new_tag2\'\n\n    Returns:\n        Mapping of old tags to new tags, or None if format is invalid\n    """\n    if not replace_tags:\n        return {}\n\n    replace_tags_dict = {}\n    for pair in replace_tags.split(","):\n        if "=" not in pair:\n            wandb.termerror(\n                f"Invalid replace-tags format: {pair}. Use \'old_tag=new_tag\' format."\n            )\n            return None\n        old_tag, new_tag = pair.split("=", 1)\n        replace_tags_dict[old_tag.strip()] = new_tag.strip()\n\n    return replace_tags_dict\n\n\n@cli.command(\n    context_settings=CONTEXT,\n    help="Initialize a hyperparameter sweep. Search for hyperparameters that optimizes a cost function of a machine learning model by testing various combinations.",\n)\n@click.option(\n    "--project",\n    "-p",\n    default=None,\n    help="""The name of the project where W&B runs created from the sweep are sent to. If the project is not specified, the run is sent to a project labeled Uncategorized.""",\n)\n@click.option(\n    "--entity",\n    "-e",\n    default=None,\n    help="""The username or team name where you want to send W&B runs created by the sweep to. Ensure that the entity you specify already exists. If you don\'t specify an entity, the run will be sent to your default entity, which is usually your username.""",\n)\n@click.option("--controller", is_flag=True, default=False, help="Run local controller")\n@click.option("--verbose", is_flag=True, default=False, help="Display verbose output")\n@click.option(\n    "--name",\n    default=None,\n    help="The name of the sweep. The sweep ID is used if no name is specified.",\n)\n@click.option("--program", default=None, help="Set sweep program")\n@click.option("--settings", default=None, help="Set sweep settings", hidden=True)\n@click.option("--update", default=None, help="Update pending sweep")\n@click.option(\n    "--stop",\n    is_flag=True,\n    default=False,\n    help="Finish a sweep to stop running new runs and let currently running runs finish.",\n)\n@click.option(\n    "--cancel",\n    is_flag=True,\n    default=False,\n    help="Cancel a sweep to kill all running runs and stop running new runs.",\n)\n@click.option(\n    "--pause",\n    is_flag=True,\n    default=False,\n    help="Pause a sweep to temporarily stop running new runs.",\n)\n@click.option(\n    "--resume",\n    is_flag=True,\n    default=False,\n    help="Resume a sweep to continue running new runs.",\n)\n@click.option(\n    "--prior_run",\n    "-R",\n    "prior_runs",\n    multiple=True,\n    default=None,\n    help="ID of an existing run to add to this sweep",\n)\n@click.argument("config_yaml_or_sweep_id")\n@click.pass_context\n@display_error\ndef sweep(\n    ctx,\n    project,\n    entity,\n    controller,\n    verbose,\n    name,\n    program,\n    settings,\n    update,\n    stop,\n    cancel,\n    pause,\n    resume,\n    prior_runs,\n    config_yaml_or_sweep_id,\n):\n    state_args = "stop", "cancel", "pause", "resume"\n    lcls = locals()\n    is_state_change_command = sum(lcls[k] for k in state_args)\n    if is_state_change_command > 1:\n        raise Exception("Only one state flag (stop/cancel/pause/resume) is allowed.")\n    elif is_state_change_command == 1:\n        sweep_id = config_yaml_or_sweep_id\n        api = _get_cling_api()\n        if not api.is_authenticated:\n            wandb.termlog("Login to W&B to use the sweep feature")\n            ctx.invoke(login, no_offline=True)\n            api = _get_cling_api(reset=True)\n        parts = dict(entity=entity, project=project, name=sweep_id)\n        err = sweep_utils.parse_sweep_id(parts)\n        if err:\n            wandb.termerror(err)\n            return\n        entity = parts.get("entity") or entity\n        project = parts.get("project") or project\n        sweep_id = parts.get("name") or sweep_id\n        state = [s for s in state_args if lcls[s]][0]\n        ings = {\n            "stop": "Stopping",\n            "cancel": "Cancelling",\n            "pause": "Pausing",\n            "resume": "Resuming",\n        }\n        wandb.termlog(f"{ings[state]} sweep {entity}/{project}/{sweep_id}")\n        getattr(api, f"{state}_sweep")(sweep_id, entity=entity, project=project)\n        wandb.termlog("Done.")\n        return\n    else:\n        config_yaml = config_yaml_or_sweep_id\n\n    def _parse_settings(settings):\n        """Parse settings from json or comma separated assignments."""\n        ret = {}\n        # TODO(jhr): merge with magic:_parse_magic\n        if settings.find("=") > 0:\n            for item in settings.split(","):\n                kv = item.split("=")\n                if len(kv) != 2:\n                    wandb.termwarn(\n                        "Unable to parse sweep settings key value pair", repeat=False\n                    )\n                ret.update(dict([kv]))\n            return ret\n        wandb.termwarn("Unable to parse settings parameter", repeat=False)\n        return ret\n\n    api = _get_cling_api()\n    if not api.is_authenticated:\n        wandb.termlog("Login to W&B to use the sweep feature")\n        ctx.invoke(login, no_offline=True)\n        api = _get_cling_api(reset=True)\n\n    sweep_obj_id = None\n    if update:\n        parts = dict(entity=entity, project=project, name=update)\n        err = sweep_utils.parse_sweep_id(parts)\n        if err:\n            wandb.termerror(err)\n            return\n        entity = parts.get("entity") or entity\n        project = parts.get("project") or project\n        sweep_id = parts.get("name") or update\n\n        has_project = (project or api.settings("project")) is not None\n        has_entity = (entity or api.settings("entity")) is not None\n\n        termerror_msg = (\n            "Sweep lookup requires a valid %s, and none was specified. \\n"\n            "Either set a default %s in wandb/settings, or, if invoking \\n`wandb sweep` "\n            "from the command line, specify the full sweep path via: \\n\\n"\n            "    wandb sweep {username}/{projectname}/{sweepid}\\n\\n"\n        )\n\n        if not has_entity:\n            wandb.termerror(termerror_msg % (("entity",) * 2))\n            return\n\n        if not has_project:\n            wandb.termerror(termerror_msg % (("project",) * 2))\n            return\n\n        found = api.sweep(sweep_id, "{}", entity=entity, project=project)\n        if not found:\n            wandb.termerror(f"Could not find sweep {entity}/{project}/{sweep_id}")\n            return\n        sweep_obj_id = found["id"]\n\n    action = "Updating" if sweep_obj_id else "Creating"\n    wandb.termlog(f"{action} sweep from: {config_yaml}")\n    config = sweep_utils.load_sweep_config(config_yaml)\n\n    # Set or override parameters\n    if name:\n        config["name"] = name\n    if program:\n        config["program"] = program\n    if settings:\n        settings = _parse_settings(settings)\n        if settings:\n            config.setdefault("settings", {})\n            config["settings"].update(settings)\n    if controller:\n        config.setdefault("controller", {})\n        config["controller"]["type"] = "local"\n\n    is_local = config.get("controller", {}).get("type") == "local"\n    if is_local:\n        from wandb import controller as wandb_controller\n\n        tuner = wandb_controller()\n        err = tuner._validate(config)\n        if err:\n            wandb.termerror(f"Error in sweep file: {err}")\n            return\n\n    env = os.environ\n    entity = (\n        entity\n        or env.get("WANDB_ENTITY")\n        or config.get("entity")\n        or api.settings("entity")\n    )\n    project = (\n        project\n        or env.get("WANDB_PROJECT")\n        or config.get("project")\n        or api.settings("project")\n        or util.auto_project_name(config.get("program"))\n    )\n\n    sweep_id, warnings = api.upsert_sweep(\n        config,\n        project=project,\n        entity=entity,\n        obj_id=sweep_obj_id,\n        prior_runs=prior_runs,\n    )\n    sweep_utils.handle_sweep_config_violations(warnings)\n\n    # Log nicely formatted sweep information\n    styled_id = click.style(sweep_id, fg="yellow")\n    wandb.termlog(f"{action} sweep with ID: {styled_id}")\n\n    sweep_url = wandb_sweep._get_sweep_url(api, sweep_id)\n    if sweep_url:\n        styled_url = click.style(sweep_url, underline=True, fg="blue")\n        wandb.termlog(f"View sweep at: {styled_url}")\n\n    # re-probe entity and project if it was auto-detected by upsert_sweep\n    entity = entity or env.get("WANDB_ENTITY")\n    project = project or env.get("WANDB_PROJECT")\n\n    if entity and project:\n        sweep_path = f"{entity}/{project}/{sweep_id}"\n    elif project:\n        sweep_path = f"{project}/{sweep_id}"\n    else:\n        sweep_path = sweep_id\n\n    if sweep_path.find(" ") >= 0:\n        sweep_path = f"{sweep_path!r}"\n\n    styled_path = click.style(f"wandb agent {sweep_path}", fg="yellow")\n    wandb.termlog(f"Run sweep agent with: {styled_path}")\n    if controller:\n        wandb.termlog("Starting wandb controller...")\n        from wandb import controller as wandb_controller\n\n        tuner = wandb_controller(sweep_id)\n        tuner.run(verbose=verbose)\n\n\n@cli.command(\n    context_settings=CONTEXT,\n    no_args_is_help=True,\n    help="Run a W&B launch sweep (Experimental).",\n)\n@click.option(\n    "--queue",\n    "-q",\n    default=None,\n    help="The name of a queue to push the sweep to",\n)\n@click.option(\n    "--project",\n    "-p",\n    default=None,\n    help="Name of the project which the agent will watch. "\n    "If passed in, will override the project value passed in using a config file",\n)\n@click.option(\n    "--entity",\n    "-e",\n    default=None,\n    help="The entity to use. Defaults to current logged-in user",\n)\n@click.option(\n    "--resume_id",\n    "-r",\n    default=None,\n    help="Resume a launch sweep by passing an 8-char sweep id. Queue required",\n)\n@click.option(\n    "--prior_run",\n    "-R",\n    "prior_runs",\n    multiple=True,\n    default=None,\n    help="ID of an existing run to add to this sweep",\n)\n@click.argument("config", required=False, type=click.Path(exists=True))\n@click.pass_context\n@display_error\ndef launch_sweep(\n    ctx,\n    project,\n    entity,\n    queue,\n    config,\n    resume_id,\n    prior_runs,\n):\n    api = _get_cling_api()\n    env = os.environ\n    if not api.is_authenticated:\n        wandb.termlog("Login to W&B to use the sweep feature")\n        ctx.invoke(login, no_offline=True)\n        api = _get_cling_api(reset=True)\n\n    entity = entity or env.get("WANDB_ENTITY") or api.settings("entity")\n    if entity is None:\n        wandb.termerror("Must specify entity when using launch")\n        return\n\n    project = project or env.get("WANDB_PROJECT") or api.settings("project")\n    if project is None:\n        wandb.termerror("A project must be configured when using launch")\n        return\n\n    # get personal username, not team name or service account, default to entity\n    author = api.viewer().get("username") or entity\n\n    # if not sweep_config XOR resume_id\n    if not (config or resume_id):\n        wandb.termerror("\'config\' and/or \'resume_id\' required")\n        return\n\n    parsed_user_config = sweep_utils.load_launch_sweep_config(config)\n    # Rip special keys out of config, store in scheduler run_config\n    launch_args: Dict[str, Any] = parsed_user_config.pop("launch", {})\n    scheduler_args: Dict[str, Any] = parsed_user_config.pop("scheduler", {})\n    settings: Dict[str, Any] = scheduler_args.pop("settings", {})\n\n    scheduler_job: Optional[str] = scheduler_args.get("job")\n    if scheduler_job:\n        wandb.termwarn(\n            "Using a scheduler job for launch sweeps is *experimental* and may change without warning"\n        )\n    queue: Optional[str] = queue or launch_args.get("queue")\n\n    sweep_config, sweep_obj_id = None, None\n    if not resume_id:\n        sweep_config = parsed_user_config\n\n        # check method\n        method = sweep_config.get("method")\n        if scheduler_job and not method:\n            sweep_config["method"] = "custom"\n        elif scheduler_job and method != "custom":\n            # TODO(gst): Check if using Anaconda2\n            wandb.termwarn(\n                "Use \'method\': \'custom\' in the sweep config when using scheduler jobs, "\n                "or omit it entirely. For jobs using the wandb optimization engine (WandbScheduler), "\n                "set the method in the sweep config under scheduler.settings.method "\n            )\n            settings["method"] = method\n\n        if settings.get("method"):\n            # assume WandbScheduler, and user is using this right\n            sweep_config["method"] = settings["method"]\n\n    else:  # Resuming an existing sweep\n        found = api.sweep(resume_id, "{}", entity=entity, project=project)\n        if not found:\n            wandb.termerror(f"Could not find sweep {entity}/{project}/{resume_id}")\n            return\n\n        if found.get("state") == "RUNNING":\n            wandb.termerror(\n                f"Cannot resume sweep {entity}/{project}/{resume_id}, it is already running"\n            )\n            return\n\n        sweep_obj_id = found["id"]\n        sweep_config = yaml.safe_load(found["config"])\n        wandb.termlog(f"Resuming from existing sweep {entity}/{project}/{resume_id}")\n        if len(parsed_user_config.keys()) > 0:\n            wandb.termwarn(\n                "Sweep parameters loaded from resumed sweep, ignoring provided config"\n            )\n\n        prev_scheduler = json.loads(found.get("scheduler") or "{}")\n        run_spec = json.loads(prev_scheduler.get("run_spec", "{}"))\n        if (\n            scheduler_job\n            and run_spec.get("job")\n            and run_spec.get("job") != scheduler_job\n        ):\n            wandb.termerror(\n                f"Resuming a launch sweep with a different scheduler job is not supported. Job loaded from sweep: {run_spec.get(\'job\')}, job in config: {scheduler_job}"\n            )\n            return\n\n        prev_scheduler_args, prev_settings = sweep_utils.get_previous_args(run_spec)\n        # Passed in scheduler_args and settings override previous\n        scheduler_args.update(prev_scheduler_args)\n        settings.update(prev_settings)\n    if not queue:\n        wandb.termerror(\n            "Launch-sweeps require setting a \'queue\', use --queue option or a \'queue\' key in the \'launch\' section in the config"\n        )\n        return\n\n    entrypoint = Scheduler.ENTRYPOINT if not scheduler_job else None\n    args = sweep_utils.construct_scheduler_args(\n        return_job=scheduler_job is not None,\n        sweep_config=sweep_config,\n        queue=queue,\n        project=project,\n        author=author,\n    )\n    if not args:\n        return\n\n    # validate training job existence\n    if not sweep_utils.check_job_exists(PublicApi(), sweep_config.get("job")):\n        return False\n\n    # validate scheduler job existence, if present\n    if not sweep_utils.check_job_exists(PublicApi(), scheduler_job):\n        return False\n\n    # Set run overrides for the Scheduler\n    overrides = {"run_config": {}}\n    if launch_args:\n        overrides["run_config"]["launch"] = launch_args\n    if scheduler_args:\n        overrides["run_config"]["scheduler"] = scheduler_args\n    if settings:\n        overrides["run_config"]["settings"] = settings\n\n    if scheduler_job:\n        overrides["run_config"]["sweep_args"] = args\n    else:\n        overrides["args"] = args\n\n    # configure scheduler job resource\n    resource = scheduler_args.get("resource")\n    if resource:\n        if resource == "local-process" and scheduler_job:\n            wandb.termerror(\n                "Scheduler jobs cannot be run with the \'local-process\' resource"\n            )\n            return\n        if resource == "local-process" and scheduler_args.get("docker_image"):\n            wandb.termerror(\n                "Scheduler jobs cannot be run with the \'local-process\' resource and a docker image"\n            )\n            return\n    else:  # no resource set, default local-process if not scheduler job, else container\n        resource = "local-process" if not scheduler_job else "local-container"\n\n    # Launch job spec for the Scheduler\n    launch_scheduler_spec = launch_utils.construct_launch_spec(\n        uri=Scheduler.PLACEHOLDER_URI,\n        api=api,\n        name="Scheduler.WANDB_SWEEP_ID",\n        project=project,\n        entity=entity,\n        docker_image=scheduler_args.get("docker_image"),\n        resource=resource,\n        entry_point=entrypoint,\n        resource_args=scheduler_args.get("resource_args", {}),\n        repository=launch_args.get("registry", {}).get("url", None),\n        job=scheduler_job,\n        version=None,\n        launch_config={"overrides": overrides},\n        run_id="WANDB_SWEEP_ID",  # scheduler inits run with sweep_id=run_id\n        author=None,  # author gets passed into scheduler override args\n    )\n    launch_scheduler_with_queue = json.dumps(\n        {\n            "queue": queue,\n            "run_queue_project": launch_utils.LAUNCH_DEFAULT_PROJECT,\n            "run_spec": json.dumps(launch_scheduler_spec),\n        }\n    )\n\n    sweep_id, warnings = api.upsert_sweep(\n        sweep_config,\n        project=project,\n        entity=entity,\n        obj_id=sweep_obj_id,  # if resuming\n        launch_scheduler=launch_scheduler_with_queue,\n        state="PENDING",\n        prior_runs=prior_runs,\n        template_variable_values=scheduler_args.get("template_variables", None),\n    )\n    sweep_utils.handle_sweep_config_violations(warnings)\n    # Log nicely formatted sweep information\n    styled_id = click.style(sweep_id, fg="yellow")\n    wandb.termlog(f"{\'Resumed\' if resume_id else \'Created\'} sweep with ID: {styled_id}")\n    sweep_url = wandb_sweep._get_sweep_url(api, sweep_id)\n    if sweep_url:\n        styled_url = click.style(sweep_url, underline=True, fg="blue")\n        wandb.termlog(f"View sweep at: {styled_url}")\n    wandb.termlog(f"Scheduler added to launch queue ({queue})")\n\n\n@cli.command(help=f"Launch or queue a W&B Job. See {url_registry.url(\'wandb-launch\')}")\n@click.option(\n    "--uri",\n    "-u",\n    metavar="(str)",\n    default=None,\n    help="Local path or git repo uri to launch. If provided this command will "\n    "create a job from the specified uri.",\n)\n@click.option(\n    "--job",\n    "-j",\n    metavar="(str)",\n    default=None,\n    help="Name of the job to launch. If passed in, launch does not require a uri.",\n)\n@click.option(\n    "--entry-point",\n    "-E",\n    metavar="NAME",\n    default=None,\n    help="""Entry point within project. [default: main]. If the entry point is not found,\n    attempts to run the project file with the specified name as a script,\n    using \'python\' to run .py files and the default shell (specified by\n    environment variable $SHELL) to run .sh files. If passed in, will override the entrypoint value passed in using a config file.""",\n)\n@click.option(\n    "--git-version",\n    "-g",\n    metavar="GIT-VERSION",\n    hidden=True,\n    help="Version of the project to run, as a Git commit reference for Git projects.",\n)\n@click.option(\n    "--build-context",\n    metavar="(str)",\n    help="Path to the build context within the source code. Defaults to the "\n    "root of the source code. Compatible only with -u.",\n)\n@click.option(\n    "--job-name",\n    "-J",\n    metavar="(str)",\n    default=None,\n    hidden=True,\n    help="Name for the job created if the -u,--uri flag is passed in.",\n)\n@click.option(\n    "--name",\n    envvar="WANDB_NAME",\n    help="""Name of the run under which to launch the run. If not\n    specified, a random run name will be used to launch run. If passed in, will override the name passed in using a config file.""",\n)\n@click.option(\n    "--entity",\n    "-e",\n    metavar="(str)",\n    default=None,\n    help="""Name of the target entity which the new run will be sent to. Defaults to using the entity set by local wandb/settings folder.\n    If passed in, will override the entity value passed in using a config file.""",\n)\n@click.option(\n    "--project",\n    "-p",\n    metavar="(str)",\n    default=None,\n    help="""Name of the target project which the new run will be sent to. Defaults to using the project name given by the source uri\n    or for github runs, the git repo name. If passed in, will override the project value passed in using a config file.""",\n)\n@click.option(\n    "--resource",\n    "-r",\n    metavar="BACKEND",\n    default=None,\n    help="""Execution resource to use for run. Supported values: \'local-process\', \'local-container\', \'kubernetes\', \'sagemaker\', \'gcp-vertex\'.\n    This is now a required parameter if pushing to a queue with no resource configuration.\n    If passed in, will override the resource value passed in using a config file.""",\n)\n@click.option(\n    "--docker-image",\n    "-d",\n    default=None,\n    metavar="DOCKER IMAGE",\n    help="""Specific docker image you\'d like to use. In the form name:tag.\n    If passed in, will override the docker image value passed in using a config file.""",\n)\n@click.option(\n    "--base-image",\n    "-B",\n    default=None,\n    metavar="BASE IMAGE",\n    help="""Docker image to run job code in. Incompatible with --docker-image.""",\n)\n@click.option(\n    "--config",\n    "-c",\n    metavar="FILE",\n    help="""Path to JSON file (must end in \'.json\') or JSON string which will be passed\n    as a launch config. Dictation how the launched run will be configured.""",\n)\n@click.option(\n    "--set-var",\n    "-v",\n    "cli_template_vars",\n    default=None,\n    multiple=True,\n    help="""Set template variable values for queues with allow listing enabled,\n    as key-value pairs e.g. `--set-var key1=value1 --set-var key2=value2`""",\n)\n@click.option(\n    "--queue",\n    "-q",\n    is_flag=False,\n    flag_value="default",\n    default=None,\n    help="""Name of run queue to push to. If none, launches single run directly. If supplied without\n    an argument (`--queue`), defaults to queue \'default\'. Else, if name supplied, specified run queue must exist under the\n    project and entity supplied.""",\n)\n@click.option(\n    "--async",\n    "run_async",\n    is_flag=True,\n    help="""Flag to run the job asynchronously. Defaults to false, i.e. unless --async is set, wandb launch will wait for\n    the job to finish. This option is incompatible with --queue; asynchronous options when running with an agent should be\n    set on wandb launch-agent.""",\n)\n@click.option(\n    "--resource-args",\n    "-R",\n    metavar="FILE",\n    help="""Path to JSON file (must end in \'.json\') or JSON string which will be passed\n    as resource args to the compute resource. The exact content which should be\n    provided is different for each execution backend. See documentation for layout of this file.""",\n)\n@click.option(\n    "--build",\n    "-b",\n    is_flag=True,\n    hidden=True,\n    help="Flag to build an associated job and push to queue as an image job.",\n)\n@click.option(\n    "--repository",\n    "-rg",\n    is_flag=False,\n    default=None,\n    hidden=True,\n    help="Name of a remote repository. Will be used to push a built image to.",\n)\n# TODO: this is only included for back compat. But we should remove this in the future\n@click.option(\n    "--project-queue",\n    "-pq",\n    default=None,\n    hidden=True,\n    help="Name of the project containing the queue to push to. If none, defaults to entity level queues.",\n)\n@click.option(\n    "--dockerfile",\n    "-D",\n    default=None,\n    help="Path to the Dockerfile used to build the job, relative to the job\'s root",\n)\n@click.option(\n    "--priority",\n    "-P",\n    default=None,\n    type=click.Choice(["critical", "high", "medium", "low"]),\n    help="""When --queue is passed, set the priority of the job. Launch jobs with higher priority\n    are served first.  The order, from highest to lowest priority, is: critical, high, medium, low""",\n)\n@display_error\ndef launch(\n    uri,\n    job,\n    entry_point,\n    git_version,\n    build_context,\n    name,\n    resource,\n    entity,\n    project,\n    docker_image,\n    base_image,\n    config,\n    cli_template_vars,\n    queue,\n    run_async,\n    resource_args,\n    build,\n    repository,\n    project_queue,\n    dockerfile,\n    priority,\n    job_name,\n):\n    """Start a W&B run from the given URI.\n\n    The URI can bea wandb URI, a GitHub repo uri, or a local path). In the case of a\n    wandb URI the arguments used in the original run will be used by default. These\n    arguments can be overridden using the args option, or specifying those arguments in\n    the config\'s \'overrides\' key, \'args\' field as a list of strings.\n\n    Running `wandb launch [URI]` will launch the run directly. To add the run to a\n    queue, run `wandb launch [URI] --queue [optional queuename]`.\n    """\n    logger.info(\n        f"=== Launch called with kwargs {locals()} CLI Version: {wandb.__version__}==="\n    )\n    from wandb.sdk.launch._launch import _launch\n    from wandb.sdk.launch.create_job import _create_job\n    from wandb.sdk.launch.utils import _is_git_uri\n\n    api = _get_cling_api()\n    get_sentry().configure_scope(process_context="launch_cli")\n\n    if run_async and queue is not None:\n        raise LaunchError(\n            "Cannot use both --async and --queue with wandb launch, see help for details."\n        )\n\n    if queue and docker_image and not project:\n        raise LaunchError(\n            "Cannot use --queue and --docker together without a project. Please specify a project with --project or -p."\n        )\n\n    if priority is not None and queue is None:\n        raise LaunchError("--priority flag requires --queue to be set")\n\n    if resource_args is not None:\n        resource_args = util.load_json_yaml_dict(resource_args)\n        if resource_args is None:\n            raise LaunchError("Invalid format for resource-args")\n    else:\n        resource_args = {}\n\n    if entry_point is not None:\n        entry_point = shlex.split(entry_point)\n\n    if config is not None:\n        config = util.load_json_yaml_dict(config)\n        if config is None:\n            raise LaunchError("Invalid format for config")\n    else:\n        config = {}\n\n    resource = resource or config.get("resource")\n\n    if build and queue is None:\n        raise LaunchError("Build flag requires a queue to be set")\n\n    try:\n        launch_utils.check_logged_in(api)\n    except Exception:\n        wandb.termerror(f"Error running job: {traceback.format_exc()}")\n\n    run_id = config.get("run_id")\n\n    # If URI was provided, we need to create a job from it.\n    if uri:\n        if entry_point is None:\n            raise LaunchError(\n                "Cannot provide a uri without an entry point. Please provide an "\n                "entry point with --entry-point or -E."\n            )\n        if job is not None:\n            raise LaunchError("Cannot provide both a uri and a job name.")\n        job_type = (\n            "git" if _is_git_uri(uri) else "code"\n        )  # TODO: Add support for local URIs with git.\n        if entity is None:\n            entity = launch_utils.get_default_entity(api, config)\n        artifact, _, _ = _create_job(\n            api,\n            job_type,\n            uri,\n            entrypoint=" ".join(entry_point),\n            git_hash=git_version,\n            name=job_name,\n            project=project,\n            base_image=base_image,\n            build_context=build_context,\n            dockerfile=dockerfile,\n            entity=entity,\n        )\n        if artifact is None:\n            raise LaunchError(f"Failed to create job from uri: {uri}")\n        job = f"{entity}/{project}/{artifact.name}"\n\n    if dockerfile:\n        if "overrides" in config:\n            config["overrides"]["dockerfile"] = dockerfile\n        else:\n            config["overrides"] = {"dockerfile": dockerfile}\n\n    if priority is not None:\n        priority_map = {\n            "critical": 0,\n            "high": 1,\n            "medium": 2,\n            "low": 3,\n        }\n        priority = priority_map[priority.lower()]\n\n    template_variables = None\n    if cli_template_vars:\n        if queue is None:\n            raise LaunchError("\'--set-var\' flag requires queue to be set")\n        if entity is None:\n            entity = launch_utils.get_default_entity(api, config)\n        public_api = PublicApi()\n        runqueue = RunQueue(client=public_api.client, name=queue, entity=entity)\n        template_variables = launch_utils.fetch_and_validate_template_variables(\n            runqueue, cli_template_vars\n        )\n\n    if queue is None:\n        # direct launch\n        try:\n            run = asyncio.run(\n                _launch(\n                    api,\n                    job,\n                    project=project,\n                    entity=entity,\n                    docker_image=docker_image,\n                    name=name,\n                    entry_point=entry_point,\n                    version=git_version,\n                    resource=resource,\n                    resource_args=resource_args,\n                    launch_config=config,\n                    synchronous=(not run_async),\n                    run_id=run_id,\n                    repository=repository,\n                )\n            )\n            if asyncio.run(run.get_status()).state in [\n                "failed",\n                "stopped",\n                "preempted",\n            ]:\n                wandb.termerror("Launched run exited with non-zero status")\n                sys.exit(1)\n        except LaunchError as e:\n            logger.exception("An error occurred.")\n            get_sentry().exception(e)\n            sys.exit(e)\n        except ExecutionError as e:\n            logger.exception("An error occurred.")\n            get_sentry().exception(e)\n            sys.exit(e)\n        except asyncio.CancelledError:\n            sys.exit(0)\n    else:\n        try:\n            _launch_add(\n                api,\n                job,\n                config,\n                template_variables,\n                project,\n                entity,\n                queue,\n                resource,\n                entry_point,\n                name,\n                git_version,\n                docker_image,\n                project_queue,\n                resource_args,\n                build=build,\n                run_id=run_id,\n                repository=repository,\n                priority=priority,\n            )\n\n        except Exception as e:\n            get_sentry().exception(e)\n            raise\n\n\n@cli.command(\n    context_settings=CONTEXT,\n    help="Run a W&B launch agent.",\n)\n@click.pass_context\n@click.option(\n    "--queue",\n    "-q",\n    "queues",\n    default=None,\n    multiple=True,\n    help="The name of a queue for the agent to watch. Multiple -q flags supported.",\n)\n@click.option(\n    "--entity",\n    "-e",\n    default=None,\n    help="The entity to use. Defaults to current logged-in user",\n)\n@click.option(\n    "--log-file",\n    "-l",\n    default=None,\n    help=(\n        "Destination for internal agent logs. Use - for stdout. "\n        "By default all agents logs will go to debug.log in your wandb/ "\n        "subdirectory or WANDB_DIR if set."\n    ),\n)\n@click.option(\n    "--max-jobs",\n    "-j",\n    default=None,\n    help="The maximum number of launch jobs this agent can run in parallel. Defaults to 1. Set to -1 for no upper limit",\n)\n@click.option(\n    "--config", "-c", default=None, help="path to the agent config yaml to use"\n)\n@click.option(\n    "--url",\n    "-u",\n    default=None,\n    hidden=True,\n    help="a wandb client registration URL, this is generated in the UI",\n)\n@click.option("--verbose", "-v", count=True, help="Display verbose output")\n@display_error\ndef launch_agent(\n    ctx,\n    entity=None,\n    queues=None,\n    max_jobs=None,\n    config=None,\n    url=None,\n    log_file=None,\n    verbose=0,\n):\n    logger.info(\n        f"=== Launch-agent called with kwargs {locals()}  CLI Version: {wandb.__version__} ==="\n    )\n    if url is not None:\n        raise LaunchError(\n            "--url is not supported in this version, upgrade with: pip install -u wandb"\n        )\n\n    import wandb.sdk.launch._launch as _launch\n\n    if log_file is not None:\n        _launch.set_launch_logfile(log_file)\n\n    api = _get_cling_api()\n    get_sentry().configure_scope(process_context="launch_agent")\n    agent_config, api = _launch.resolve_agent_config(\n        entity, max_jobs, queues, config, verbose\n    )\n\n    if len(agent_config.get("queues")) == 0:\n        raise LaunchError(\n            "To launch an agent please specify a queue or a list of queues in the configuration file or cli."\n        )\n\n    launch_utils.check_logged_in(api)\n\n    wandb.termlog("Starting launch agent ✨")\n    try:\n        _launch.create_and_run_agent(api, agent_config)\n    except Exception as e:\n        get_sentry().exception(e)\n        raise\n\n\n@cli.command(context_settings=CONTEXT, help="Run the W&B agent")\n@click.pass_context\n@click.option(\n    "--project",\n    "-p",\n    default=None,\n    help="""The name of the project where W&B runs created from the sweep are sent to. If the project is not specified, the run is sent to a project labeled \'Uncategorized\'.""",\n)\n@click.option(\n    "--entity",\n    "-e",\n    default=None,\n    help="""The username or team name where you want to send W&B runs created by the sweep to. Ensure that the entity you specify already exists. If you don\'t specify an entity, the run will be sent to your default entity, which is usually your username.""",\n)\n@click.option(\n    "--count", default=None, type=int, help="The max number of runs for this agent."\n)\n@click.option(\n    "--forward-signals",\n    "-f",\n    is_flag=True,\n    default=False,\n    help="""Forward signals delivered to the agent (e.g. SIGINT/SIGTERM) to its child runs so they can shut down cleanly.""",\n)\n@click.argument("sweep_id")\n@display_error\ndef agent(ctx, project, entity, count, forward_signals, sweep_id):\n    api = _get_cling_api()\n    if not api.is_authenticated:\n        wandb.termlog("Login to W&B to use the sweep agent feature")\n        ctx.invoke(login, no_offline=True)\n        api = _get_cling_api(reset=True)\n\n    wandb.termlog("Starting wandb agent 🕵️")\n    wandb_agent.agent(\n        sweep_id,\n        entity=entity,\n        project=project,\n        count=count,\n        forward_signals=forward_signals,\n    )\n\n    # you can send local commands like so:\n    # agent_api.command({\'type\': \'run\', \'program\': \'train.py\',\n    #                \'args\': [\'--max_epochs=10\']})\n\n\n@cli.command(\n    context_settings=RUN_CONTEXT, help="Run a W&B launch sweep scheduler (Experimental)"\n)\n@click.pass_context\n@click.argument("sweep_id")\n@display_error\ndef scheduler(\n    ctx,\n    sweep_id,\n):\n    api = InternalApi()\n    if not api.is_authenticated:\n        wandb.termlog("Login to W&B to use the sweep scheduler feature")\n        ctx.invoke(login, no_offline=True)\n        api = InternalApi(reset=True)\n\n    get_sentry().configure_scope(process_context="sweep_scheduler")\n    wandb.termlog("Starting a Launch Scheduler 🚀")\n    from wandb.sdk.launch.sweeps import load_scheduler\n\n    # TODO(gst): remove this monstrosity\n    # Future-proofing hack to pull any kwargs that get passed in through the CLI\n    kwargs = {}\n    for i, _arg in enumerate(ctx.args):\n        if isinstance(_arg, str) and _arg.startswith("--"):\n            # convert input kwargs from hyphens to underscores\n            _key = _arg[2:].replace("-", "_")\n            _args = ctx.args[i + 1]\n            if str.isdigit(_args):\n                _args = int(_args)\n            kwargs[_key] = _args\n    try:\n        sweep_type = kwargs.get("sweep_type", "wandb")\n        _scheduler = load_scheduler(scheduler_type=sweep_type)(\n            api,\n            sweep_id=sweep_id,\n            **kwargs,\n        )\n        _scheduler.start()\n    except Exception as e:\n        get_sentry().exception(e)\n        raise\n\n\n@cli.group(help="Commands for managing and viewing W&B jobs")\ndef job() -> None:\n    pass\n\n\n@job.command("list", help="List jobs in a project")\n@click.option(\n    "--project",\n    "-p",\n    envvar=env.PROJECT,\n    help="The project you want to list jobs from.",\n)\n@click.option(\n    "--entity",\n    "-e",\n    default="models",\n    envvar=env.ENTITY,\n    help="The entity the jobs belong to",\n)\ndef _list(project, entity):\n    wandb.termlog(f"Listing jobs in {entity}/{project}")\n    public_api = PublicApi()\n    try:\n        jobs = public_api.list_jobs(entity=entity, project=project)\n    except wandb.errors.CommError as e:\n        wandb.termerror(f"{e}")\n        return\n\n    if len(jobs) == 0:\n        wandb.termlog("No jobs found")\n        return\n\n    for job in jobs:\n        aliases = []\n        if len(job["edges"]) == 0:\n            # deleted?\n            continue\n\n        name = job["edges"][0]["node"]["artifactSequence"]["name"]\n        for version in job["edges"]:\n            aliases += [x["alias"] for x in version["node"]["aliases"]]\n\n        # only list the most recent 10 job versions\n        aliases_str = ",".join(aliases[::-1])\n        wandb.termlog(f"{name} -- versions ({len(aliases)}): {aliases_str}")\n\n\n@job.command(\n    help="Describe a launch job. Provide the launch job in the form of: entity/project/job-name:alias-or-version"\n)\n@click.argument("job")\ndef describe(job):\n    public_api = PublicApi()\n    try:\n        job = public_api.job(name=job)\n    except wandb.errors.CommError as e:\n        wandb.termerror(f"{e}")\n        return\n\n    for key in job._job_info:\n        if key.startswith("_"):\n            continue\n        wandb.termlog(f"{key}: {job._job_info[key]}")\n\n\n@job.command(\n    no_args_is_help=True,\n)\n@click.option(\n    "--project",\n    "-p",\n    envvar=env.PROJECT,\n    help="The project you want to list jobs from.",\n)\n@click.option(\n    "--entity",\n    "-e",\n    envvar=env.ENTITY,\n    help="The entity the jobs belong to",\n)\n@click.option(\n    "--name",\n    "-n",\n    help="Name for the job",\n)\n@click.option(\n    "--description",\n    "-d",\n    help="Description for the job",\n)\n@click.option(\n    "--alias",\n    "-a",\n    "aliases",\n    help="Alias for the job",\n    multiple=True,\n    default=tuple(),\n)\n@click.option(\n    "--entry-point",\n    "-E",\n    "entrypoint",\n    help="Entrypoint to the script, including an executable and an entrypoint "\n    "file. Required for code or repo jobs. If --build-context is provided, "\n    "paths in the entrypoint command will be relative to the build context.",\n)\n@click.option(\n    "--git-hash",\n    "-g",\n    "git_hash",\n    type=str,\n    help="Commit reference to use as the source for git jobs",\n)\n@click.option(\n    "--runtime",\n    "-r",\n    type=str,\n    help="Python runtime to execute the job",\n)\n@click.option(\n    "--build-context",\n    "-b",\n    type=str,\n    help="Path to the build context from the root of the job source code. If "\n    "provided, this is used as the base path for the Dockerfile and entrypoint.",\n)\n@click.option(\n    "--base-image",\n    "-B",\n    type=str,\n    help="Base image to use for the job. Incompatible with image jobs.",\n)\n@click.option(\n    "--dockerfile",\n    "-D",\n    type=str,\n    help="Path to the Dockerfile for the job. If --build-context is provided, "\n    "the Dockerfile path will be relative to the build context.",\n)\n@click.argument(\n    "job_type",\n    type=click.Choice(("git", "code", "image")),\n)\n@click.option(\n    "--service",\n    "-s",\n    "services",\n    multiple=True,\n    callback=parse_service_config,\n    help="Service configurations in format serviceName=policy. Valid policies: always, never",\n    hidden=True,\n)\n@click.option(\n    "--schema",\n    type=str,\n    help="Path to the schema file for the job.",\n    hidden=True,\n)\n@click.argument("path")\ndef create(\n    path,\n    project,\n    entity,\n    name,\n    job_type,\n    description,\n    aliases,\n    entrypoint,\n    git_hash,\n    runtime,\n    build_context,\n    base_image,\n    dockerfile,\n    services,\n    schema,\n):\n    """Create a job from a source, without a wandb run.\n\n    Jobs can be of three types, git, code, or image.\n\n    git: A git source, with an entrypoint either in the path or provided explicitly pointing to the main python executable.\n    code: A code path, containing a requirements.txt file.\n    image: A docker image.\n    """\n    from wandb.sdk.launch.create_job import _create_job\n\n    api = _get_cling_api()\n    get_sentry().configure_scope(process_context="job_create")\n\n    entity = entity or os.getenv("WANDB_ENTITY") or api.default_entity\n    if not entity:\n        wandb.termerror("No entity provided, use --entity or set WANDB_ENTITY")\n        return\n\n    project = project or os.getenv("WANDB_PROJECT")\n    if not project:\n        wandb.termerror("No project provided, use --project or set WANDB_PROJECT")\n        return\n\n    if entrypoint is None and job_type in ["git", "code"]:\n        wandb.termwarn(\n            f"No entrypoint provided for {job_type} job, defaulting to main.py"\n        )\n        entrypoint = "main.py"\n\n    if job_type == "image" and base_image:\n        wandb.termerror("Cannot provide --base-image/-B for an `image` job")\n        return\n\n    if schema:\n        schema_dict = util.load_json_yaml_dict(schema)\n        if schema_dict is None:\n            wandb.termerror(f"Invalid format for schema file: {schema}")\n            return\n\n    artifact, action, aliases = _create_job(\n        api=api,\n        path=path,\n        entity=entity,\n        project=project,\n        name=name,\n        job_type=job_type,\n        description=description,\n        aliases=list(aliases),\n        entrypoint=entrypoint,\n        git_hash=git_hash,\n        runtime=runtime,\n        build_context=build_context,\n        base_image=base_image,\n        dockerfile=dockerfile,\n        services=services,\n        schema=schema_dict if schema else None,\n    )\n    if not artifact:\n        wandb.termerror("Job creation failed")\n        return\n\n    artifact_path = f"{entity}/{project}/{artifact.name}"\n    msg = f"{action} job: {click.style(artifact_path, fg=\'yellow\')}"\n    if len(aliases) == 1:\n        alias_str = click.style(aliases[0], fg="yellow")\n        msg += f", with alias: {alias_str}"\n    elif len(aliases) > 1:\n        alias_str = click.style(", ".join(aliases), fg="yellow")\n        msg += f", with aliases: {alias_str}"\n\n    wandb.termlog(msg)\n    web_url = util.app_url(api.settings().get("base_url"))\n    url = click.style(f"{web_url}/{entity}/{project}/jobs", underline=True)\n    wandb.termlog(f"View all jobs in project \'{project}\' here: {url}\\n")\n\n\n@cli.command(context_settings=CONTEXT, help="Run the W&B local sweep controller")\n@click.option("--verbose", is_flag=True, default=False, help="Display verbose output")\n@click.argument("sweep_id")\n@display_error\ndef controller(verbose, sweep_id):\n    click.echo("Starting wandb controller...")\n    from wandb import controller as wandb_controller\n\n    tuner = wandb_controller(sweep_id)\n    tuner.run(verbose=verbose)\n\n\n@cli.command(context_settings=RUN_CONTEXT, name="docker-run")\n@click.pass_context\n@click.argument("docker_run_args", nargs=-1)\ndef docker_run(ctx, docker_run_args):\n    """Wrap `docker run` and adds WANDB_API_KEY and WANDB_DOCKER environment variables.\n\n    This will also set the runtime to nvidia if the nvidia-docker executable is present\n    on the system and --runtime wasn\'t set.\n\n    See `docker run --help` for more details.\n    """\n    import wandb.docker\n\n    api = InternalApi()\n    args = list(docker_run_args)\n    if len(args) > 0 and args[0] == "run":\n        args.pop(0)\n    if len([a for a in args if a.startswith("--runtime")]) == 0 and _HAS_NVIDIA_DOCKER:\n        args = ["--runtime", "nvidia"] + args\n    #  TODO: image_from_docker_args uses heuristics to find the docker image arg, there are likely cases\n    #  where this won\'t work\n    image = util.image_from_docker_args(args)\n    resolved_image = None\n    if image:\n        resolved_image = wandb.docker.image_id(image)\n    if resolved_image:\n        args = ["-e", f"WANDB_DOCKER={resolved_image}"] + args\n    else:\n        wandb.termlog(\n            "Couldn\'t detect image argument, running command without the WANDB_DOCKER env variable"\n        )\n    if api.api_key:\n        args = ["-e", f"WANDB_API_KEY={api.api_key}"] + args\n    else:\n        wandb.termlog(\n            "Not logged in, run `wandb login` from the host machine to enable result logging"\n        )\n    subprocess.call(["docker", "run"] + args)\n\n\n@cli.command(context_settings=RUN_CONTEXT)\n@click.pass_context\n@click.argument("docker_run_args", nargs=-1)\n@click.argument("docker_image", required=False)\n@click.option(\n    "--nvidia/--no-nvidia",\n    default=_HAS_NVIDIA_DOCKER,\n    help="Use the nvidia runtime, defaults to nvidia if nvidia-docker is present",\n)\n@click.option(\n    "--digest", is_flag=True, default=False, help="Output the image digest and exit"\n)\n@click.option(\n    "--jupyter/--no-jupyter", default=False, help="Run jupyter lab in the container"\n)\n@click.option(\n    "--dir", default="/app", help="Which directory to mount the code in the container"\n)\n@click.option("--no-dir", is_flag=True, help="Don\'t mount the current directory")\n@click.option(\n    "--shell", default="/bin/bash", help="The shell to start the container with"\n)\n@click.option("--port", default="8888", help="The host port to bind jupyter on")\n@click.option("--cmd", help="The command to run in the container")\n@click.option(\n    "--no-tty", is_flag=True, default=False, help="Run the command without a tty"\n)\n@display_error\ndef docker(\n    ctx,\n    docker_run_args,\n    docker_image,\n    nvidia,\n    digest,\n    jupyter,\n    dir,\n    no_dir,\n    shell,\n    port,\n    cmd,\n    no_tty,\n):\n    """Run your code in a docker container.\n\n    W&B docker lets you run your code in a docker image ensuring wandb is configured. It\n    adds the WANDB_DOCKER and WANDB_API_KEY environment variables to your container and\n    mounts the current directory in /app by default.  You can pass additional args which\n    will be added to `docker run` before the image name is declared, we\'ll choose a\n    default image for you if one isn\'t passed:\n\n    ```sh\n    wandb docker -v /mnt/dataset:/app/data\n    wandb docker gcr.io/kubeflow-images-public/tensorflow-1.12.0-notebook-cpu:v0.4.0 --jupyter\n    wandb docker wandb/deepo:keras-gpu --no-tty --cmd "python train.py --epochs=5"\n    ```\n\n    By default, we override the entrypoint to check for the existence of wandb and\n    install it if not present.  If you pass the --jupyter flag we will ensure jupyter is\n    installed and start jupyter lab on port 8888.  If we detect nvidia-docker on your\n    system we will use the nvidia runtime.  If you just want wandb to set environment\n    variable to an existing docker run command, see the wandb docker-run command.\n    """\n    api = InternalApi()\n    if not _HAS_DOCKER:\n        raise ClickException("Docker not installed, install it from https://docker.com")\n\n    import wandb.docker\n\n    args = list(docker_run_args)\n    image = docker_image or ""\n    # remove run for users used to nvidia-docker\n    if len(args) > 0 and args[0] == "run":\n        args.pop(0)\n    if image == "" and len(args) > 0:\n        image = args.pop(0)\n    # If the user adds docker args without specifying an image (should be rare)\n    if not util.docker_image_regex(image.split("@")[0]):\n        if image:\n            args = args + [image]\n        image = wandb.docker.default_image(gpu=nvidia)\n        subprocess.call(["docker", "pull", image])\n    _, repo_name, tag = wandb.docker.parse(image)\n\n    resolved_image = wandb.docker.image_id(image)\n    if resolved_image is None:\n        raise ClickException(\n            f"Couldn\'t find image locally or in a registry, try running `docker pull {image}`"\n        )\n    if digest:\n        sys.stdout.write(resolved_image)\n        exit(0)\n\n    existing = wandb.docker.shell(["ps", "-f", f"ancestor={resolved_image}", "-q"])\n    if existing:\n        if click.confirm(\n            "Found running container with the same image, do you want to attach?"\n        ):\n            subprocess.call(["docker", "attach", existing.split("\\n")[0]])\n            exit(0)\n    cwd = os.getcwd()\n    command = [\n        "docker",\n        "run",\n        "-e",\n        "LANG=C.UTF-8",\n        "-e",\n        f"WANDB_DOCKER={resolved_image}",\n        "--ipc=host",\n        "-v",\n        wandb.docker.entrypoint + ":/wandb-entrypoint.sh",\n        "--entrypoint",\n        "/wandb-entrypoint.sh",\n    ]\n    if nvidia:\n        command.extend(["--runtime", "nvidia"])\n    if not no_dir:\n        #  TODO: We should default to the working directory if defined\n        command.extend(["-v", cwd + ":" + dir, "-w", dir])\n    if api.api_key:\n        command.extend(["-e", f"WANDB_API_KEY={api.api_key}"])\n    else:\n        wandb.termlog(\n            "Couldn\'t find WANDB_API_KEY, run `wandb login` to enable streaming metrics"\n        )\n    if jupyter:\n        command.extend(["-e", "WANDB_ENSURE_JUPYTER=1", "-p", port + ":8888"])\n        no_tty = True\n        cmd = f"jupyter lab --no-browser --ip=0.0.0.0 --allow-root --NotebookApp.token= --notebook-dir {dir}"\n    command.extend(args)\n    if no_tty:\n        command.extend([image, shell, "-c", cmd])\n    else:\n        if cmd:\n            command.extend(["-e", f"WANDB_COMMAND={cmd}"])\n        command.extend(["-it", image, shell])\n        wandb.termlog("Launching docker container \\U0001f6a2")\n    subprocess.call(command)\n\n\n@cli.command(\n    context_settings=RUN_CONTEXT,\n    help="Start a local W&B container (deprecated, see wandb server --help)",\n    hidden=True,\n)\n@click.pass_context\n@click.option("--port", "-p", default="8080", help="The host port to bind W&B local on")\n@click.option(\n    "--env", "-e", default=[], multiple=True, help="Env vars to pass to wandb/local"\n)\n@click.option(\n    "--daemon/--no-daemon", default=True, help="Run or don\'t run in daemon mode"\n)\n@click.option(\n    "--upgrade", is_flag=True, default=False, help="Upgrade to the most recent version"\n)\n@click.option(\n    "--edge", is_flag=True, default=False, help="Run the bleeding edge", hidden=True\n)\n@display_error\ndef local(ctx, *args, **kwargs):\n    wandb.termwarn("`wandb local` has been replaced with `wandb server start`.")\n    ctx.invoke(start, *args, **kwargs)\n\n\n@cli.group(help="Commands for operating a local W&B server")\ndef server():\n    pass\n\n\n@server.command(context_settings=RUN_CONTEXT, help="Start a local W&B server")\n@click.pass_context\n@click.option(\n    "--port", "-p", default="8080", help="The host port to bind W&B server on"\n)\n@click.option(\n    "--env", "-e", default=[], multiple=True, help="Env vars to pass to wandb/local"\n)\n@click.option(\n    "--daemon/--no-daemon", default=True, help="Run or don\'t run in daemon mode"\n)\n@click.option(\n    "--upgrade",\n    is_flag=True,\n    default=False,\n    help="Upgrade to the most recent version",\n    hidden=True,\n)\n@click.option(\n    "--edge", is_flag=True, default=False, help="Run the bleeding edge", hidden=True\n)\n@display_error\ndef start(ctx, port, env, daemon, upgrade, edge):\n    api = InternalApi()\n    if not _HAS_DOCKER:\n        raise ClickException("Docker not installed, install it from https://docker.com")\n\n    import wandb.docker\n\n    local_image_sha = wandb.docker.image_id("wandb/local").split("wandb/local")[-1]\n    registry_image_sha = wandb.docker.image_id_from_registry("wandb/local").split(\n        "wandb/local"\n    )[-1]\n    if local_image_sha != registry_image_sha:\n        if upgrade:\n            subprocess.call(["docker", "pull", "wandb/local"])\n        else:\n            wandb.termlog(\n                "A new version of the W&B server is available, upgrade by calling `wandb server start --upgrade`"\n            )\n    running = subprocess.check_output(\n        ["docker", "ps", "--filter", "name=^wandb-local$", "--format", "{{.ID}}"]\n    )\n    if running != b"":\n        if upgrade:\n            subprocess.call(["docker", "stop", "wandb-local"])\n        else:\n            wandb.termerror(\n                "A container named wandb-local is already running, run `docker stop wandb-local` if you want to start a new instance"\n            )\n            exit(1)\n    image = "docker.pkg.github.com/wandb/core/local" if edge else "wandb/local"\n    username = getpass.getuser()\n    env_vars = ["-e", f"LOCAL_USERNAME={username}"]\n    for e in env:\n        env_vars.append("-e")\n        env_vars.append(e)\n    command = [\n        "docker",\n        "run",\n        "--rm",\n        "-v",\n        "wandb:/vol",\n        "-p",\n        port + ":8080",\n        "--name",\n        "wandb-local",\n    ] + env_vars\n    host = f"http://localhost:{port}"\n\n    system_settings = wandb_setup.singleton().settings.read_system_settings()\n    system_settings.set("base_url", host, globally=True)\n\n    try:\n        system_settings.save()\n    except settings_file.SaveSettingsError as e:\n        msg = "Failed to update base_url setting"\n        logger.exception(msg)\n        wandb.termerror(f"{msg}: {e}")\n\n    if daemon:\n        command += ["-d"]\n    command += [image]\n\n    # DEVNULL is only in py3\n    try:\n        from subprocess import DEVNULL\n    except ImportError:\n        DEVNULL = open(os.devnull, "wb")  # noqa: N806\n    code = subprocess.call(command, stdout=DEVNULL)\n    if daemon:\n        if code != 0:\n            wandb.termerror(\n                "Failed to launch the W&B server container, see the above error."\n            )\n            exit(1)\n        else:\n            wandb.termlog(f"W&B server started at http://localhost:{port} \\U0001f680")\n            wandb.termlog("You can stop the server by running `wandb server stop`")\n            if not api.api_key:\n                # Let the server start before potentially launching a browser\n                time.sleep(2)\n                ctx.invoke(login, host=host)\n\n\n@server.command(context_settings=RUN_CONTEXT, help="Stop a local W&B server")\ndef stop():\n    if not _HAS_DOCKER:\n        raise ClickException("Docker not installed, install it from https://docker.com")\n    subprocess.call(["docker", "stop", "wandb-local"])\n\n\n@cli.group(help="Commands for interacting with artifacts")\ndef artifact():\n    pass\n\n\n@artifact.command(context_settings=CONTEXT, help="Upload an artifact to wandb")\n@click.argument("path")\n@click.option(\n    "--name", "-n", help="The name of the artifact to push: project/artifact_name"\n)\n@click.option("--description", "-d", help="A description of this artifact")\n@click.option("--type", "-t", default="dataset", help="The type of the artifact")\n@click.option(\n    "--alias",\n    "-a",\n    default=["latest"],\n    multiple=True,\n    help="An alias to apply to this artifact",\n)\n@click.option("--id", "run_id", help="The run you want to upload to.")\n@click.option(\n    "--resume",\n    is_flag=True,\n    default=None,\n    help="Resume the last run from your current directory.",\n)\n@click.option(\n    "--skip_cache",\n    is_flag=True,\n    default=False,\n    help="Skip caching while uploading artifact files.",\n)\n@click.option(\n    "--policy",\n    default="mutable",\n    type=click.Choice(["mutable", "immutable"]),\n    help="Set the storage policy while uploading artifact files.",\n)\n@display_error\ndef put(\n    path,\n    name,\n    description,\n    type,\n    alias,\n    run_id,\n    resume,\n    skip_cache,\n    policy,\n):\n    if name is None:\n        name = os.path.basename(path)\n    public_api = PublicApi()\n    entity, project, artifact_name = public_api._parse_artifact_path(name)\n    if project is None:\n        project = click.prompt("Enter the name of the project you want to use")\n\n    artifact = wandb.Artifact(name=artifact_name, type=type, description=description)\n    artifact_path = f"{entity}/{project}/{artifact_name}:{alias[0]}"\n    if os.path.isdir(path):\n        wandb.termlog(f\'Uploading directory {path} to: "{artifact_path}" ({type})\')\n        artifact.add_dir(path, skip_cache=skip_cache, policy=policy)\n    elif os.path.isfile(path):\n        wandb.termlog(f\'Uploading file {path} to: "{artifact_path}" ({type})\')\n        artifact.add_file(path, skip_cache=skip_cache, policy=policy)\n    elif "://" in path:\n        wandb.termlog(\n            f\'Logging reference artifact from {path} to: "{artifact_path}" ({type})\'\n        )\n        artifact.add_reference(path)\n    else:\n        raise ClickException("Path argument must be a file or directory")\n\n    with wandb.init(\n        entity=entity,\n        project=project,\n        config={"path": path},\n        job_type="cli_put",\n        id=run_id,\n        resume=resume,\n    ) as run:\n        run.log_artifact(artifact, aliases=alias)\n    artifact.wait()\n\n    wandb.termlog(\n        "Artifact uploaded, use this artifact in a run by adding:\\n", prefix=False\n    )\n    wandb.termlog(\n        f\'    artifact = run.use_artifact("{artifact.source_qualified_name}")\\n\',\n        prefix=False,\n    )\n\n\n@artifact.command(context_settings=CONTEXT, help="Download an artifact from wandb")\n@click.argument("path")\n@click.option("--root", help="The directory you want to download the artifact to")\n@click.option("--type", help="The type of artifact you are downloading")\n@display_error\ndef get(path, root, type):\n    public_api = PublicApi()\n    entity, project, artifact_name = public_api._parse_artifact_path(path)\n    if project is None:\n        project = click.prompt("Enter the name of the project you want to use")\n\n    try:\n        artifact_parts = artifact_name.split(":")\n        if len(artifact_parts) > 1:\n            version = artifact_parts[1]\n            artifact_name = artifact_parts[0]\n        else:\n            version = "latest"\n        if is_artifact_registry_project(project):\n            organization = path.split("/")[0] if path.count("/") == 2 else ""\n            # set entity to match the settings since in above code it was potentially set to an org\n            settings_entity = public_api.settings["entity"] or public_api.default_entity\n            # Registry artifacts are under the org entity. Because we offer a shorthand and alias for this path,\n            # we need to fetch the org entity to for the user behind the scenes.\n            entity = SDKInternalApi()._resolve_org_entity_name(\n                entity=settings_entity, organization=organization\n            )\n        full_path = f"{entity}/{project}/{artifact_name}:{version}"\n        wandb.termlog(\n            "Downloading {type} artifact {full_path}".format(\n                type=type or "dataset", full_path=full_path\n            )\n        )\n        artifact = public_api.artifact(full_path, type=type)\n        path = artifact.download(root=root)\n        wandb.termlog(f"Artifact downloaded to {path}")\n    except ValueError:\n        raise ClickException("Unable to download artifact")\n\n\n@artifact.command(\n    context_settings=CONTEXT, help="List all artifacts in a wandb project"\n)\n@click.argument("path")\n@click.option("--type", "-t", help="The type of artifacts to list")\n@display_error\ndef ls(path, type):\n    public_api = PublicApi()\n    if type is not None:\n        types = [public_api.artifact_type(type, path)]\n    else:\n        types = public_api.artifact_types(path)\n\n    for kind in types:\n        for collection in kind.collections():\n            versions = public_api.artifact_versions(\n                kind.type,\n                "/".join([kind.entity, kind.project, collection.name]),\n                per_page=1,\n            )\n            if (latest := next(versions, None)) is not None:\n                wandb.termlog(\n                    f"{kind.type:<15s}{latest.updated_at:<15s}{util.to_human_size(latest.size):>15s} {latest.name:<20s}"\n                )\n            else:\n                # Artifact collection exists but has no versions. This can happen when:\n                # 1. A collection was just created but no artifacts have been logged yet.\n                # 2. All versions within an artifact collection were deleted.\n                wandb.termlog(\n                    f"{kind.type:<15s}{\'N/A\':<15s}{\'0 B\':>15s} {collection.name:<20s} (no versions)"\n                )\n\n\n@artifact.group(help="Commands for interacting with the artifact cache")\ndef cache():\n    pass\n\n\n@cache.command(\n    context_settings=CONTEXT,\n    help="Clean up less frequently used files from the artifacts cache",\n)\n@click.argument("target_size")\n@click.option("--remove-temp/--no-remove-temp", default=False, help="Remove temp files")\n@display_error\ndef cleanup(target_size, remove_temp):\n    target_size = util.from_human_size(target_size)\n    cache = get_artifact_file_cache()\n    reclaimed_bytes = cache.cleanup(target_size, remove_temp)\n    wandb.termlog(f"Reclaimed {util.to_human_size(reclaimed_bytes)} of space")\n\n\n@cli.command(context_settings=CONTEXT, help="Pull files from Weights & Biases")\n@click.argument("run", envvar=env.RUN_ID)\n@click.option(\n    "--project", "-p", envvar=env.PROJECT, help="The project you want to download."\n)\n@click.option(\n    "--entity",\n    "-e",\n    default="models",\n    envvar=env.ENTITY,\n    help="The entity to scope the listing to.",\n)\n@display_error\ndef pull(run, project, entity):\n    api = InternalApi()\n    project, run = api.parse_slug(run, project=project)\n    urls = api.download_urls(project, run=run, entity=entity)\n    if len(urls) == 0:\n        raise ClickException("Run has no files")\n    click.echo(f"Downloading: {click.style(project, bold=True)}/{run}")\n\n    for name in urls:\n        if api.file_current(name, urls[name]["md5"]):\n            click.echo(f"File {name} is up to date")\n        else:\n            length, response = api.download_file(urls[name]["url"])\n            # TODO: I had to add this because some versions in CI broke click.progressbar\n            sys.stdout.write(f"File {name}\\r")\n            dirname = os.path.dirname(name)\n            if dirname != "":\n                filesystem.mkdir_exists_ok(dirname)\n            with click.progressbar(\n                length=length,\n                label=f"File {name}",\n                fill_char=click.style("&", fg="green"),\n            ) as bar:\n                with open(name, "wb") as f:\n                    for data in response.iter_content(chunk_size=4096):\n                        f.write(data)\n                        bar.update(len(data))\n\n\n@cli.command(\n    context_settings=CONTEXT,\n    help="Restore code, config and docker state for a run. Retrieves code from latest commit if code was not saved with `wandb.save()` or `wandb.init(save_code=True)`.",\n)\n@click.pass_context\n@click.argument("run", envvar=env.RUN_ID)\n@click.option("--no-git", is_flag=True, default=False, help="Don\'t restore git state")\n@click.option(\n    "--branch/--no-branch",\n    default=True,\n    help="Whether to create a branch or checkout detached",\n)\n@click.option(\n    "--project", "-p", envvar=env.PROJECT, help="The project you wish to upload to."\n)\n@click.option(\n    "--entity", "-e", envvar=env.ENTITY, help="The entity to scope the listing to."\n)\n@display_error\ndef restore(ctx, run, no_git, branch, project, entity):\n    from wandb.old.core import wandb_dir\n    from wandb.sdk.lib.gitlib import GitRepo\n\n    api = _get_cling_api()\n    if ":" in run:\n        if "/" in run:\n            entity, rest = run.split("/", 1)\n        else:\n            rest = run\n        project, run = rest.split(":", 1)\n    elif run.count("/") > 1:\n        entity, run = run.split("/", 1)\n\n    project, run = api.parse_slug(run, project=project)\n    commit, json_config, patch_content, metadata = api.run_config(\n        project, run=run, entity=entity\n    )\n    repo = metadata.get("git", {}).get("repo")\n    image = metadata.get("docker")\n    restore_message = f"""`wandb restore` needs to be run from the same git repository as the original run.\nRun `git clone {repo}` and restore from there or pass the --no-git flag."""\n\n    git = GitRepo(remote=api.settings("git_remote"))\n\n    if no_git:\n        commit = None\n    elif not git.enabled:\n        if repo:\n            raise ClickException(restore_message)\n        elif image:\n            wandb.termlog(\n                "Original run has no git history.  Just restoring config and docker"\n            )\n\n    if commit and git.enabled:\n        wandb.termlog(f"Fetching origin and finding commit: {commit}")\n        subprocess.check_call(["git", "fetch", "--all"])\n        try:\n            git.repo.commit(commit)\n        except ValueError:\n            wandb.termlog(f"Couldn\'t find original commit: {commit}")\n            commit = None\n            files = api.download_urls(project, run=run, entity=entity)\n            for filename in files:\n                if filename.startswith("upstream_diff_") and filename.endswith(\n                    ".patch"\n                ):\n                    commit = filename[len("upstream_diff_") : -len(".patch")]\n                    try:\n                        git.repo.commit(commit)\n                    except ValueError:\n                        commit = None\n                    else:\n                        break\n\n            if commit:\n                wandb.termlog(f"Falling back to upstream commit: {commit}")\n                patch_path, _ = api.download_write_file(files[filename])\n            else:\n                raise ClickException(restore_message)\n        else:\n            if patch_content:\n                patch_path = os.path.join(wandb_dir(), "diff.patch")\n                with open(patch_path, "w") as f:\n                    f.write(patch_content)\n            else:\n                patch_path = None\n\n        branch_name = f"wandb/{run}"\n        if branch and branch_name not in git.repo.branches:\n            git.repo.git.checkout(commit, b=branch_name)\n            wandb.termlog(f"Created branch {click.style(branch_name, bold=True)}")\n        elif branch:\n            wandb.termlog(\n                f"Using existing branch, run `git branch -D {branch_name}` from master for a clean checkout"\n            )\n            git.repo.git.checkout(branch_name)\n        else:\n            wandb.termlog(f"Checking out {commit} in detached mode")\n            git.repo.git.checkout(commit)\n\n        if patch_path:\n            # we apply the patch from the repository root so git doesn\'t exclude\n            # things outside the current directory\n            root = git.root\n            patch_rel_path = os.path.relpath(patch_path, start=root)\n            # --reject is necessary or else this fails any time a binary file\n            # occurs in the diff\n            exit_code = subprocess.call(\n                ["git", "apply", "--reject", patch_rel_path], cwd=root\n            )\n            if exit_code == 0:\n                wandb.termlog("Applied patch")\n            else:\n                wandb.termerror(\n                    "Failed to apply patch, try un-staging any un-committed changes"\n                )\n\n    filesystem.mkdir_exists_ok(wandb_dir())\n    config_path = os.path.join(wandb_dir(), "config.yaml")\n    config = Config()\n    for k, v in json_config.items():\n        if k not in ("_wandb", "wandb_version"):\n            config[k] = v\n    s = b"wandb_version: 1"\n    s += b"\\n\\n" + yaml.dump(\n        config._as_dict(),\n        Dumper=yaml.SafeDumper,\n        default_flow_style=False,\n        allow_unicode=True,\n        encoding="utf-8",\n    )\n    s = s.decode("utf-8")\n    with open(config_path, "w") as f:\n        f.write(s)\n\n    wandb.termlog(f"Restored config variables to {config_path}")\n    if image:\n        if not metadata["program"].startswith("<") and metadata.get("args") is not None:\n            # TODO: we may not want to default to python here.\n            runner = util.find_runner(metadata["program"]) or ["python"]\n            command = runner + [metadata["program"]] + metadata["args"]\n            cmd = " ".join(command)\n        else:\n            wandb.termlog("Couldn\'t find original command, just restoring environment")\n            cmd = None\n        wandb.termlog("Docker image found, attempting to start")\n        ctx.invoke(docker, docker_run_args=[image], cmd=cmd)\n\n    return commit, json_config, patch_content, repo, metadata\n\n\n@cli.command("online")\n@display_error\ndef online():\n    """Undo `wandb offline`."""\n    system_settings = wandb_setup.singleton().settings.read_system_settings()\n    system_settings.clear("mode")\n    system_settings.save()\n\n    click.echo(\n        "W&B online. Running your script from this directory will now sync to the cloud."\n    )\n\n\n@cli.command("offline")\n@display_error\ndef offline():\n    """Save data logged to W&B locally without uploading it to the cloud.\n\n    Use `wandb online` or `wandb sync` to upload offline runs.\n    """\n    system_settings = wandb_setup.singleton().settings.read_system_settings()\n    system_settings.set("mode", "offline")\n    system_settings.save()\n\n    click.echo(\n        "W&B offline. Running your script from this directory will only write"\n        + " metadata locally. Use `wandb disabled` to completely turn off W&B."\n    )\n\n\n@cli.command("on", hidden=True)\n@click.pass_context\n@display_error\ndef on(ctx):\n    ctx.invoke(online)\n\n\n@cli.command("off", hidden=True)\n@click.pass_context\n@display_error\ndef off(ctx):\n    ctx.invoke(offline)\n\n\n@cli.command("status", help="Show configuration settings")\n@click.option(\n    "--settings/--no-settings", help="Show the current settings", default=True\n)\ndef status(settings):\n    api = _get_cling_api()\n    if settings:\n        click.echo(click.style("Current Settings", bold=True))\n        settings = api.settings()\n        click.echo(\n            json.dumps(settings, sort_keys=True, indent=2, separators=(",", ": "))\n        )\n\n\n@cli.command("disabled", help="Disable W&B.")\n@click.option(\n    "--service",\n    is_flag=True,\n    show_default=True,\n    default=True,\n    help="Disable W&B service",\n)\ndef disabled(service):\n    system_settings = wandb_setup.singleton().settings.read_system_settings()\n    system_settings.set("mode", "disabled")\n    system_settings.save()\n\n    click.echo("W&B disabled.")\n\n\n@cli.command("enabled", help="Enable W&B.")\n@click.option(\n    "--service",\n    is_flag=True,\n    show_default=True,\n    default=True,\n    help="Enable W&B service",\n)\ndef enabled(service):\n    system_settings = wandb_setup.singleton().settings.read_system_settings()\n    system_settings.set("mode", "online")\n    system_settings.save()\n\n    click.echo("W&B enabled.")\n\n\n@cli.command(\n    context_settings=CONTEXT,\n    help="""Checks and verifies local instance of W&B. W&B checks for:\n\n    Checks that the host is not `api.wandb.ai` (host check).\n\n    Verifies if the user is logged in correctly using the provided API key (login check).\n\n    Checks that requests are made over HTTPS (secure requests).\n\n    Validates the CORS (Cross-Origin Resource Sharing) configuration of the\n    object store (CORS configuration).\n\n    Logs metrics, saves, and downloads files to check if runs are correctly\n    recorded and accessible (run check).\n\n    Saves and downloads artifacts to verify that the artifact storage and\n    retrieval system is working as expected (artifact check).\n\n    Tests the GraphQL endpoint by uploading a file to ensure it can handle\n    signed URL uploads (GraphQL PUT check).\n\n    Checks the ability to send large payloads through the proxy (large payload check).\n\n    Verifies that the installed version of the W&B package is up-to-date and\n    compatible with the server (W&B version check).\n\n    Creates and executes a sweep to ensure that sweep functionality is\n    working correctly (sweeps check).\n""",\n)\n@click.option("--host", default=None, help="Test a specific instance of W&B")\ndef verify(host):\n    # TODO: (kdg) Build this all into a WandbVerify object, and clean this up.\n    os.environ["WANDB_SILENT"] = "true"\n    os.environ["WANDB_PROJECT"] = "verify"\n    api = _get_cling_api()\n    reinit = False\n    if host is None:\n        host = api.settings("base_url")\n        wandb.termlog(f"Default host selected: {host}")\n    # if the given host does not match the default host, re-run init\n    elif host != api.settings("base_url"):\n        reinit = True\n\n    tmp_dir = tempfile.mkdtemp()\n    wandb.termlog(\n        "Find detailed logs for this test at: {}".format(os.path.join(tmp_dir, "wandb"))\n    )\n    os.chdir(tmp_dir)\n    os.environ["WANDB_BASE_URL"] = host\n    wandb.login(host=host)\n    if reinit:\n        api = _get_cling_api(reset=True)\n    if not wandb_verify.check_host(host):\n        sys.exit(1)\n    if not wandb_verify.check_logged_in(api, host):\n        sys.exit(1)\n    url_success, url = wandb_verify.check_graphql_put(api, host)\n    large_post_success = wandb_verify.check_large_post()\n    wandb_verify.check_secure_requests(\n        api.settings("base_url"),\n        "Checking requests to base url",\n        "Connections are not made over https. SSL required for secure communications.",\n    )\n    if url:\n        wandb_verify.check_secure_requests(\n            url,\n            "Checking requests made over signed URLs",\n            "Signed URL requests not made over https. SSL is required for secure communications.",\n        )\n        wandb_verify.check_cors_configuration(url, host)\n    wandb_verify.check_wandb_version(api)\n    check_run_success = wandb_verify.check_run(api)\n    check_artifacts_success = wandb_verify.check_artifacts()\n    check_sweeps_success = wandb_verify.check_sweeps(api)\n    if not (\n        check_artifacts_success\n        and check_run_success\n        and large_post_success\n        and url_success\n        and check_sweeps_success\n    ):\n        sys.exit(1)\n\n\ncli.add_command(beta)\n',
            'wandb/sdk/internal/internal_api.py': 'from __future__ import annotations\n\nimport base64\nimport datetime\nimport functools\nimport http.client\nimport json\nimport logging\nimport os\nimport re\nimport socket\nimport sys\nimport threading\nfrom copy import deepcopy\nfrom pathlib import Path\nfrom typing import (\n    IO,\n    TYPE_CHECKING,\n    Any,\n    Callable,\n    Iterable,\n    Literal,\n    Mapping,\n    MutableMapping,\n    NamedTuple,\n    Sequence,\n    TextIO,\n    Union,\n    overload,\n)\n\nimport click\nfrom wandb_gql import Client, gql\nfrom wandb_gql.client import RetryError\nfrom wandb_graphql.language.ast import Document\n\nimport wandb\nfrom wandb import env, util\nfrom wandb.analytics import get_sentry\nfrom wandb.apis.normalize import normalize_exceptions, parse_backend_error_messages\nfrom wandb.errors import AuthenticationError, CommError, UnsupportedError, UsageError\nfrom wandb.integration.sagemaker import parse_sm_secrets\nfrom wandb.proto.wandb_internal_pb2 import ServerFeature\nfrom wandb.sdk import wandb_setup\nfrom wandb.sdk.internal import settings_static\nfrom wandb.sdk.internal._generated import SERVER_FEATURES_QUERY_GQL, ServerFeaturesQuery\nfrom wandb.sdk.lib.gql_request import GraphQLSession\nfrom wandb.sdk.lib.hashutil import B64MD5, md5_file_b64\n\nfrom ..lib import retry, wbauth\nfrom ..lib.filenames import DIFF_FNAME, METADATA_FNAME\nfrom . import context\nfrom .progress import Progress\n\nlogger = logging.getLogger(__name__)\n\nLAUNCH_DEFAULT_PROJECT = "model-registry"\n\nif TYPE_CHECKING:\n    from typing import Literal, TypedDict\n\n    import requests\n\n    from .progress import ProgressFn\n\n    class CreateArtifactFileSpecInput(TypedDict, total=False):\n        """Corresponds to `type CreateArtifactFileSpecInput` in schema.graphql."""\n\n        artifactID: str\n        name: str\n        md5: str\n        mimetype: str | None\n        artifactManifestID: str | None\n        uploadPartsInput: list[dict[str, object]] | None\n\n    class CreateArtifactFilesResponseFile(TypedDict):\n        id: str\n        name: str\n        displayName: str\n        uploadUrl: str | None\n        uploadHeaders: Sequence[str]\n        uploadMultipartUrls: UploadPartsResponse\n        storagePath: str\n        artifact: CreateArtifactFilesResponseFileNode\n\n    class CreateArtifactFilesResponseFileNode(TypedDict):\n        id: str\n\n    class UploadPartsResponse(TypedDict):\n        uploadUrlParts: list[UploadUrlParts]\n        uploadID: str\n\n    class UploadUrlParts(TypedDict):\n        partNumber: int\n        uploadUrl: str\n\n    class CompleteMultipartUploadArtifactInput(TypedDict):\n        """Corresponds to `type CompleteMultipartUploadArtifactInput` in schema.graphql."""\n\n        completeMultipartAction: str\n        completedParts: dict[int, str]\n        artifactID: str\n        storagePath: str\n        uploadID: str\n        md5: str\n\n    class CompleteMultipartUploadArtifactResponse(TypedDict):\n        digest: str\n\n    class DefaultSettings(TypedDict, total=False):\n        section: str\n        git_remote: str\n        ignore_globs: list[str]\n        base_url: str\n        root_dir: str | None\n        api_key: str | None\n        entity: str | None\n        organization: str | None\n        project: str | None\n        _extra_http_headers: Mapping[str, str] | None\n        _proxies: Mapping[str, str] | None\n\n    _Response = MutableMapping\n    SweepState = Literal["RUNNING", "PAUSED", "CANCELED", "FINISHED"]\n    Number = Union[int, float]\n\nhttpclient_logger = logging.getLogger("http.client")\nif os.environ.get("WANDB_DEBUG"):\n    httpclient_logger.setLevel(logging.DEBUG)\n\n\ndef check_httpclient_logger_handler() -> None:\n    # Only enable http.client logging if WANDB_DEBUG is set\n    if not os.environ.get("WANDB_DEBUG"):\n        return\n    if httpclient_logger.handlers:\n        return\n\n    # Enable HTTPConnection debug logging to the logging framework\n    level = logging.DEBUG\n\n    def httpclient_log(*args: Any) -> None:\n        httpclient_logger.log(level, " ".join(args))\n\n    # mask the print() built-in in the http.client module to use logging instead\n    http.client.print = httpclient_log  # type: ignore[attr-defined]\n    # enable debugging\n    http.client.HTTPConnection.debuglevel = 1\n\n    root_logger = logging.getLogger("wandb")\n    if root_logger.handlers:\n        httpclient_logger.addHandler(root_logger.handlers[0])\n\n\nclass _ThreadLocalData(threading.local):\n    context: context.Context | None\n\n    def __init__(self) -> None:\n        self.context = None\n\n\nclass _OrgNames(NamedTuple):\n    entity_name: str\n    display_name: str\n\n\ndef _match_org_with_fetched_org_entities(\n    organization: str, orgs: Sequence[_OrgNames]\n) -> str:\n    """Match the organization provided in the path with the org entity or org name of the input entity.\n\n    Args:\n        organization: The organization name to match\n        orgs: list of tuples containing (org_entity_name, org_display_name)\n\n    Returns:\n        str: The matched org entity name\n\n    Raises:\n        ValueError: If no matching organization is found or if multiple orgs exist without a match\n    """\n    for org_names in orgs:\n        if organization in org_names:\n            return org_names.entity_name\n\n    if len(orgs) == 1:\n        raise ValueError(\n            f"Expecting the organization name or entity name to match {orgs[0].display_name!r} "\n            f"and cannot be linked/fetched with {organization!r}. "\n            "Please update the target path with the correct organization name."\n        )\n\n    raise ValueError(\n        "Personal entity belongs to multiple organizations "\n        f"and cannot be linked/fetched with {organization!r}. "\n        "Please update the target path with the correct organization name "\n        "or use a team entity in the entity settings."\n    )\n\n\nclass Api:\n    """W&B Internal Api wrapper.\n\n    Note:\n        Settings are automatically overridden by looking for\n        a `wandb/settings` file in the current working directory or its parent\n        directory. If none can be found, we look in the current user\'s home\n        directory.\n\n    Args:\n        default_settings(dict, optional): If you aren\'t using a settings\n        file, or you wish to override the section to use in the settings file\n        Override the settings here.\n    """\n\n    HTTP_TIMEOUT = env.get_http_timeout(20)\n    FILE_PUSHER_TIMEOUT = env.get_file_pusher_timeout()\n    _global_context: context.Context\n    _local_data: _ThreadLocalData\n\n    def __init__(\n        self,\n        default_settings: (\n            wandb.Settings  #\n            | settings_static.SettingsStatic\n            | DefaultSettings\n            | None\n        ) = None,\n        load_settings: bool = True,\n        retry_timedelta: datetime.timedelta | None = None,\n        environ: MutableMapping[str, str] = os.environ,\n        retry_callback: Callable[[int, str], Any] | None = None,\n        api_key: str | None = None,\n    ) -> None:\n        import requests\n\n        self._environ = environ\n        self._global_context = context.Context()\n        self._local_data = _ThreadLocalData()\n\n        default_overrides: dict[str, Any] = (\n            dict(default_settings) if default_settings else {}\n        )\n        self.default_settings: DefaultSettings = {\n            "section": default_overrides.get("section", "default"),\n            "git_remote": default_overrides.get("git_remote", "origin"),\n            "ignore_globs": default_overrides.get("ignore_globs", []),\n            "base_url": default_overrides.get("base_url", "https://api.wandb.ai"),\n            "root_dir": default_overrides.get("root_dir", None),\n            "api_key": default_overrides.get("api_key", None),\n            "entity": default_overrides.get("entity", None),\n            "organization": default_overrides.get("organization", None),\n            "project": default_overrides.get("project", None),\n            "_extra_http_headers": default_overrides.get("_extra_http_headers", None),\n            "_proxies": default_overrides.get("_proxies", None),\n        }\n\n        if load_settings:\n            global_settings = wandb_setup.singleton().settings\n            if root_dir := self.default_settings["root_dir"]:\n                global_settings = global_settings.model_copy()\n                global_settings.root_dir = root_dir\n\n            self._settings = global_settings.read_system_settings().all()\n        else:\n            self._settings = {}\n\n        # Mutable settings set by the _file_stream_api\n        self.dynamic_settings = {\n            "system_sample_seconds": 2,\n            "system_samples": 15,\n            "heartbeat_seconds": 30,\n        }\n\n        self.retry_timedelta = retry_timedelta or datetime.timedelta(days=7)\n        self.retry_uploads = 10\n\n        # todo: remove these hacky hacks after settings refactor is complete\n        #  keeping this code here to limit scope and so that it is easy to remove later\n        self._extra_http_headers = self.settings("_extra_http_headers") or json.loads(\n            self._environ.get("WANDB__EXTRA_HTTP_HEADERS", "{}")\n        )\n\n        auth = None\n        api_key = api_key or self.default_settings.get("api_key")\n        if api_key:\n            auth = ("api", api_key)\n        elif self.access_token is not None:\n            self._extra_http_headers["Authorization"] = f"Bearer {self.access_token}"\n        else:\n            auth = ("api", self.api_key or "")\n\n        proxies = self.settings("_proxies") or json.loads(\n            self._environ.get("WANDB__PROXIES", "{}")\n        )\n\n        self.client = Client(\n            transport=GraphQLSession(\n                headers={\n                    "User-Agent": self.user_agent,\n                    "X-WANDB-USERNAME": env.get_username(env=self._environ),\n                    "X-WANDB-USER-EMAIL": env.get_user_email(env=self._environ),\n                    **self._extra_http_headers,\n                },\n                use_json=True,\n                # this timeout won\'t apply when the DNS lookup fails. in that case, it will be 60s\n                # https://bugs.python.org/issue22889\n                timeout=self.HTTP_TIMEOUT,\n                auth=auth,\n                url=f"{self.settings(\'base_url\')}/graphql",\n                proxies=proxies,\n            )\n        )\n\n        self.retry_callback = retry_callback\n        self._retry_gql = retry.Retry(\n            self.execute,\n            retry_timedelta=retry_timedelta,\n            check_retry_fn=util.no_retry_auth,\n            retryable_exceptions=(RetryError, requests.RequestException),\n            retry_callback=retry_callback,\n        )\n        self._current_run_id: str | None = None\n        self._file_stream_api = None\n        self._upload_file_session = requests.Session()\n        if self.FILE_PUSHER_TIMEOUT:\n            self._upload_file_session.put = functools.partial(  # type: ignore\n                self._upload_file_session.put,\n                timeout=self.FILE_PUSHER_TIMEOUT,\n            )\n        if proxies:\n            self._upload_file_session.proxies.update(proxies)\n        # This Retry class is initialized once for each Api instance, so this\n        # defaults to retrying 1 million times per process or 7 days\n        self.upload_file_retry = normalize_exceptions(\n            retry.retriable(retry_timedelta=retry_timedelta)(self.upload_file)\n        )\n        self.upload_multipart_file_chunk_retry = normalize_exceptions(\n            retry.retriable(retry_timedelta=retry_timedelta)(\n                self.upload_multipart_file_chunk\n            )\n        )\n        self._client_id_mapping: dict[str, str] = {}\n        # Large file uploads to azure can optionally use their SDK\n        self._azure_blob_module = util.get_module("azure.storage.blob")\n\n        self.query_types: list[str] | None = None\n        self.mutation_types: list[str] | None = None\n        self.server_info_types: list[str] | None = None\n        self.server_use_artifact_input_info: list[str] | None = None\n        self.server_create_artifact_input_info: list[str] | None = None\n        self.server_artifact_fields_info: list[str] | None = None\n        self.server_organization_type_fields_info: list[str] | None = None\n        self.server_supports_enabling_artifact_usage_tracking: bool | None = None\n        self._max_cli_version: str | None = None\n        self._server_settings_type: list[str] | None = None\n        self.fail_run_queue_item_input_info: list[str] | None = None\n        self.create_launch_agent_input_info: list[str] | None = None\n        self.server_create_run_queue_supports_drc: bool | None = None\n        self.server_create_run_queue_supports_priority: bool | None = None\n        self.server_supports_template_variables: bool | None = None\n        self.server_push_to_run_queue_supports_priority: bool | None = None\n\n        self._server_features_cache: dict[str, bool] | None = None\n\n    def gql(self, *args: Any, **kwargs: Any) -> Any:\n        ret = self._retry_gql(\n            *args,\n            retry_cancel_event=self.context.cancel_event,\n            **kwargs,\n        )\n        return ret\n\n    def set_local_context(self, api_context: context.Context | None) -> None:\n        self._local_data.context = api_context\n\n    def clear_local_context(self) -> None:\n        self._local_data.context = None\n\n    @property\n    def context(self) -> context.Context:\n        return self._local_data.context or self._global_context\n\n    def reauth(self) -> None:\n        """Ensure the current api key is set in the transport."""\n        self.client.transport.session.auth = ("api", self.api_key or "")\n\n    def relocate(self) -> None:\n        """Ensure the current api points to the right server."""\n        self.client.transport.url = "{}/graphql".format(self.settings("base_url"))\n\n    def execute(self, *args: Any, **kwargs: Any) -> _Response:\n        """Wrapper around execute that logs in cases of failure."""\n        import requests\n\n        try:\n            return self.client.execute(*args, **kwargs)  # type: ignore\n        except requests.exceptions.HTTPError as err:\n            response = err.response\n            assert response is not None\n            logger.exception("Error executing GraphQL.")\n            for error in parse_backend_error_messages(response):\n                wandb.termerror(f"Error while calling W&B API: {error} ({response})")\n            raise\n\n    def validate_api_key(self) -> bool:\n        """Returns whether the API key stored on initialization is valid."""\n        res = self.gql(gql("query { viewer { id } }"))\n        return res is not None and res["viewer"] is not None\n\n    def set_current_run_id(self, run_id: str) -> None:\n        self._current_run_id = run_id\n\n    @property\n    def current_run_id(self) -> str | None:\n        return self._current_run_id\n\n    @property\n    def user_agent(self) -> str:\n        return f"W&B Internal Client {wandb.__version__}"\n\n    @property\n    def api_key(self) -> str | None:\n        from wandb.sdk.lib import wbauth\n\n        if (  #\n            (auth := wbauth.session_credentials(host=self.api_url))\n            and isinstance(auth, wbauth.AuthApiKey)\n        ):\n            return auth.api_key\n\n        return (\n            os.getenv(env.API_KEY)\n            or wbauth.read_netrc_auth(host=self.api_url)\n            or parse_sm_secrets().get(env.API_KEY)\n            or self.default_settings.get("api_key")\n        )\n\n    @property\n    def access_token(self) -> str | None:\n        """Retrieves an access token for authentication.\n\n        This function attempts to exchange an identity token for a temporary\n        access token from the server, and save it to the credentials file.\n        It uses the path to the identity token as defined in the environment\n        variables. If the environment variable is not set, it returns None.\n\n        Returns:\n            str | None: The access token if available, otherwise None if\n            no identity token is supplied.\n        Raises:\n            AuthenticationError: If the path to the identity token is not found.\n        """\n        token_file_str = self._environ.get(env.IDENTITY_TOKEN_FILE)\n        if not token_file_str:\n            return None\n\n        token_file = Path(token_file_str)\n        if not token_file.exists():\n            raise AuthenticationError(f"Identity token file not found: {token_file}")\n\n        auth = wbauth.AuthIdentityTokenFile(\n            host=self.settings("base_url"),\n            path=str(token_file),\n            credentials_file=wandb_setup.singleton().settings.credentials_file,\n        )\n        return auth.fetch_access_token()\n\n    @property\n    def api_url(self) -> str:\n        return self.settings("base_url")  # type: ignore\n\n    @property\n    def app_url(self) -> str:\n        return wandb.util.app_url(self.api_url)\n\n    @property\n    def default_entity(self) -> str:\n        return self.viewer().get("entity")  # type: ignore\n\n    @overload\n    def settings(self, key: None = None) -> dict[str, Any]: ...\n\n    @overload\n    def settings(self, key: str) -> Any: ...\n\n    def settings(self, key: str | None = None) -> Any:\n        """The settings overridden from the wandb/settings file.\n\n        Args:\n            key (str, optional): If provided only this setting is returned\n            section (str, optional): If provided this section of the setting file is\n            used, defaults to "default"\n\n        Returns:\n            A dict with the current settings\n\n                {\n                    "entity": "models",\n                    "base_url": "https://api.wandb.ai",\n                    "project": None,\n                    "organization": "my-org",\n                }\n        """\n        result: dict[str, Any] = dict(self.default_settings)\n        result.update(self._settings)\n        result.update(\n            {\n                "entity": env.get_entity(\n                    self._settings.get(\n                        "entity",\n                        result.get("entity"),\n                    ),\n                    env=self._environ,\n                ),\n                "organization": env.get_organization(\n                    self._settings.get(\n                        "organization",\n                        result.get("organization"),\n                    ),\n                    env=self._environ,\n                ),\n                "project": env.get_project(\n                    self._settings.get(\n                        "project",\n                        result.get("project"),\n                    ),\n                    env=self._environ,\n                ),\n                "base_url": env.get_base_url(\n                    self._settings.get(\n                        "base_url",\n                        result.get("base_url"),\n                    ),\n                    env=self._environ,\n                ),\n            }\n        )\n\n        return result if key is None else result[key]\n\n    def clear_setting(self, key: str) -> None:\n        self._settings.pop(key, None)\n\n    def set_setting(self, key: str, value: Any) -> None:\n        self._settings[key] = value\n\n        if key == "entity":\n            env.set_entity(value, env=self._environ)\n        elif key == "project":\n            env.set_project(value, env=self._environ)\n        elif key == "base_url":\n            self.relocate()\n\n    def parse_slug(\n        self, slug: str, project: str | None = None, run: str | None = None\n    ) -> tuple[str, str]:\n        """Parse a slug into a project and run.\n\n        Args:\n            slug (str): The slug to parse\n            project (str, optional): The project to use, if not provided it will be\n            inferred from the slug\n            run (str, optional): The run to use, if not provided it will be inferred\n            from the slug\n\n        Returns:\n            A dict with the project and run\n        """\n        if slug and "/" in slug:\n            parts = slug.split("/")\n            project = parts[0]\n            run = parts[1]\n        else:\n            project = project or self.settings().get("project")\n            if project is None:\n                raise CommError("No default project configured.")\n            run = run or slug or self.current_run_id or env.get_run(env=self._environ)\n            assert run, "run must be specified"\n        return project, run\n\n    @normalize_exceptions\n    def server_info_introspection(self) -> tuple[list[str], list[str], list[str]]:\n        query_string = """\n           query ProbeServerCapabilities {\n               QueryType: __type(name: "Query") {\n                   ...fieldData\n                }\n                MutationType: __type(name: "Mutation") {\n                   ...fieldData\n                }\n               ServerInfoType: __type(name: "ServerInfo") {\n                   ...fieldData\n                }\n            }\n\n            fragment fieldData on __Type {\n                fields {\n                    name\n                }\n            }\n        """\n        if (\n            self.query_types is None\n            or self.mutation_types is None\n            or self.server_info_types is None\n        ):\n            query = gql(query_string)\n            res = self.gql(query)\n\n            self.query_types = [\n                field.get("name", "")\n                for field in res.get("QueryType", {}).get("fields", [{}])\n            ]\n            self.mutation_types = [\n                field.get("name", "")\n                for field in res.get("MutationType", {}).get("fields", [{}])\n            ]\n            self.server_info_types = [\n                field.get("name", "")\n                for field in res.get("ServerInfoType", {}).get("fields", [{}])\n            ]\n        return self.query_types, self.server_info_types, self.mutation_types\n\n    @normalize_exceptions\n    def server_settings_introspection(self) -> None:\n        query_string = """\n           query ProbeServerSettings {\n               ServerSettingsType: __type(name: "ServerSettings") {\n                   ...fieldData\n                }\n            }\n\n            fragment fieldData on __Type {\n                fields {\n                    name\n                }\n            }\n        """\n        if self._server_settings_type is None:\n            query = gql(query_string)\n            res = self.gql(query)\n            self._server_settings_type = (\n                [\n                    field.get("name", "")\n                    for field in res.get("ServerSettingsType", {}).get("fields", [{}])\n                ]\n                if res\n                else []\n            )\n\n    def server_use_artifact_input_introspection(self) -> list:\n        query_string = """\n           query ProbeServerUseArtifactInput {\n               UseArtifactInputInfoType: __type(name: "UseArtifactInput") {\n                   name\n                   inputFields {\n                       name\n                   }\n                }\n            }\n        """\n\n        if self.server_use_artifact_input_info is None:\n            query = gql(query_string)\n            res = self.gql(query)\n            self.server_use_artifact_input_info = [\n                field.get("name", "")\n                for field in res.get("UseArtifactInputInfoType", {}).get(\n                    "inputFields", [{}]\n                )\n            ]\n        return self.server_use_artifact_input_info\n\n    @normalize_exceptions\n    def launch_agent_introspection(self) -> str | None:\n        query = gql(\n            """\n            query LaunchAgentIntrospection {\n                LaunchAgentType: __type(name: "LaunchAgent") {\n                    name\n                }\n            }\n        """\n        )\n\n        res = self.gql(query)\n        return res.get("LaunchAgentType") or None\n\n    @normalize_exceptions\n    def create_run_queue_introspection(self) -> tuple[bool, bool, bool]:\n        _, _, mutations = self.server_info_introspection()\n        query_string = """\n           query ProbeCreateRunQueueInput {\n               CreateRunQueueInputType: __type(name: "CreateRunQueueInput") {\n                   name\n                   inputFields {\n                       name\n                   }\n                }\n            }\n        """\n        if (\n            self.server_create_run_queue_supports_drc is None\n            or self.server_create_run_queue_supports_priority is None\n        ):\n            query = gql(query_string)\n            res = self.gql(query)\n            if res is None:\n                raise CommError("Could not get CreateRunQueue input from GQL.")\n            self.server_create_run_queue_supports_drc = "defaultResourceConfigID" in [\n                x["name"]\n                for x in (\n                    res.get("CreateRunQueueInputType", {}).get("inputFields", [{}])\n                )\n            ]\n            self.server_create_run_queue_supports_priority = "prioritizationMode" in [\n                x["name"]\n                for x in (\n                    res.get("CreateRunQueueInputType", {}).get("inputFields", [{}])\n                )\n            ]\n        return (\n            "createRunQueue" in mutations,\n            self.server_create_run_queue_supports_drc,\n            self.server_create_run_queue_supports_priority,\n        )\n\n    @normalize_exceptions\n    def upsert_run_queue_introspection(self) -> bool:\n        _, _, mutations = self.server_info_introspection()\n        return "upsertRunQueue" in mutations\n\n    @normalize_exceptions\n    def push_to_run_queue_introspection(self) -> tuple[bool, bool]:\n        query_string = """\n            query ProbePushToRunQueueInput {\n                PushToRunQueueInputType: __type(name: "PushToRunQueueInput") {\n                    name\n                    inputFields {\n                        name\n                    }\n                }\n            }\n        """\n\n        if (\n            self.server_supports_template_variables is None\n            or self.server_push_to_run_queue_supports_priority is None\n        ):\n            query = gql(query_string)\n            res = self.gql(query)\n            self.server_supports_template_variables = "templateVariableValues" in [\n                x["name"]\n                for x in (\n                    res.get("PushToRunQueueInputType", {}).get("inputFields", [{}])\n                )\n            ]\n            self.server_push_to_run_queue_supports_priority = "priority" in [\n                x["name"]\n                for x in (\n                    res.get("PushToRunQueueInputType", {}).get("inputFields", [{}])\n                )\n            ]\n\n        return (\n            self.server_supports_template_variables,\n            self.server_push_to_run_queue_supports_priority,\n        )\n\n    @normalize_exceptions\n    def create_default_resource_config_introspection(self) -> bool:\n        _, _, mutations = self.server_info_introspection()\n        return "createDefaultResourceConfig" in mutations\n\n    @normalize_exceptions\n    def fail_run_queue_item_introspection(self) -> bool:\n        _, _, mutations = self.server_info_introspection()\n        return "failRunQueueItem" in mutations\n\n    @normalize_exceptions\n    def fail_run_queue_item_fields_introspection(self) -> list:\n        if self.fail_run_queue_item_input_info:\n            return self.fail_run_queue_item_input_info\n        query_string = """\n           query ProbeServerFailRunQueueItemInput {\n                FailRunQueueItemInputInfoType: __type(name:"FailRunQueueItemInput") {\n                    inputFields{\n                        name\n                    }\n                }\n            }\n        """\n\n        query = gql(query_string)\n        res = self.gql(query)\n\n        self.fail_run_queue_item_input_info = [\n            field.get("name", "")\n            for field in res.get("FailRunQueueItemInputInfoType", {}).get(\n                "inputFields", [{}]\n            )\n        ]\n        return self.fail_run_queue_item_input_info\n\n    @normalize_exceptions\n    def fail_run_queue_item(\n        self,\n        run_queue_item_id: str,\n        message: str,\n        stage: str,\n        file_paths: list[str] | None = None,\n    ) -> bool:\n        if not self.fail_run_queue_item_introspection():\n            return False\n        variable_values: dict[str, str | (list[str] | None)] = {\n            "runQueueItemId": run_queue_item_id,\n        }\n        if "message" in self.fail_run_queue_item_fields_introspection():\n            variable_values.update({"message": message, "stage": stage})\n            if file_paths is not None:\n                variable_values["filePaths"] = file_paths\n            mutation_string = """\n            mutation failRunQueueItem($runQueueItemId: ID!, $message: String!, $stage: String!, $filePaths: [String!]) {\n                failRunQueueItem(\n                    input: {\n                        runQueueItemId: $runQueueItemId\n                        message: $message\n                        stage: $stage\n                        filePaths: $filePaths\n                    }\n                ) {\n                    success\n                }\n            }\n            """\n        else:\n            mutation_string = """\n            mutation failRunQueueItem($runQueueItemId: ID!) {\n                failRunQueueItem(\n                    input: {\n                        runQueueItemId: $runQueueItemId\n                    }\n                ) {\n                    success\n                }\n            }\n            """\n\n        mutation = gql(mutation_string)\n        response = self.gql(mutation, variable_values=variable_values)\n        result: bool = response["failRunQueueItem"]["success"]\n        return result\n\n    @normalize_exceptions\n    def update_run_queue_item_warning_introspection(self) -> bool:\n        _, _, mutations = self.server_info_introspection()\n        return "updateRunQueueItemWarning" in mutations\n\n    def _server_features(self) -> dict[str, bool]:\n        # NOTE: Avoid caching via `@cached_property`, due to undocumented\n        # locking behavior before Python 3.12.\n        # See: https://github.com/python/cpython/issues/87634\n        query = gql(SERVER_FEATURES_QUERY_GQL)\n        try:\n            response = self.gql(query)\n        except Exception as e:\n            # Unfortunately we currently have to match on the text of the error message,\n            # as the `gql` client raises `Exception` rather than a more specific error.\n            if \'Cannot query field "features" on type "ServerInfo".\' in str(e):\n                self._server_features_cache = {}\n            else:\n                raise\n        else:\n            info = ServerFeaturesQuery.model_validate(response).server_info\n            if info and (feats := info.features):\n                self._server_features_cache = {f.name: f.is_enabled for f in feats if f}\n            else:\n                self._server_features_cache = {}\n        return self._server_features_cache\n\n    def _server_supports(self, feature: int | str) -> bool:\n        """Return whether the current server supports the given feature.\n\n        This also caches the underlying lookup of server feature flags,\n        and it maps {feature_name (str) -> is_enabled (bool)}.\n\n        Good to use for features that have a fallback mechanism for older servers.\n        """\n        # If we\'re given the protobuf enum value, convert to a string name.\n        # NOTE: We deliberately use names (str) instead of enum values (int)\n        # as the keys here, since:\n        # - the server identifies features by their name, rather than (client-side) enum value\n        # - the defined list of client-side flags may be behind the server-side list of flags\n        key = ServerFeature.Name(feature) if isinstance(feature, int) else feature\n        return self._server_features().get(key) or False\n\n    @normalize_exceptions\n    def update_run_queue_item_warning(\n        self,\n        run_queue_item_id: str,\n        message: str,\n        stage: str,\n        file_paths: list[str] | None = None,\n    ) -> bool:\n        if not self.update_run_queue_item_warning_introspection():\n            return False\n        mutation = gql(\n            """\n        mutation updateRunQueueItemWarning($runQueueItemId: ID!, $message: String!, $stage: String!, $filePaths: [String!]) {\n            updateRunQueueItemWarning(\n                input: {\n                    runQueueItemId: $runQueueItemId\n                    message: $message\n                    stage: $stage\n                    filePaths: $filePaths\n                }\n            ) {\n                success\n            }\n        }\n        """\n        )\n        response = self.gql(\n            mutation,\n            variable_values={\n                "runQueueItemId": run_queue_item_id,\n                "message": message,\n                "stage": stage,\n                "filePaths": file_paths,\n            },\n        )\n        result: bool = response["updateRunQueueItemWarning"]["success"]\n        return result\n\n    @normalize_exceptions\n    def viewer(self) -> dict[str, Any]:\n        query = gql(\n            """\n        query Viewer{\n            viewer {\n                id\n                entity\n                username\n                flags\n                teams {\n                    edges {\n                        node {\n                            name\n                        }\n                    }\n                }\n            }\n        }\n        """\n        )\n        res = self.gql(query)\n        return res.get("viewer") or {}\n\n    @normalize_exceptions\n    def max_cli_version(self) -> str | None:\n        if self._max_cli_version is not None:\n            return self._max_cli_version\n\n        query_types, server_info_types, _ = self.server_info_introspection()\n        cli_version_exists = (\n            "serverInfo" in query_types and "cliVersionInfo" in server_info_types\n        )\n        if not cli_version_exists:\n            return None\n\n        _, server_info = self.viewer_server_info()\n        self._max_cli_version = server_info.get("cliVersionInfo", {}).get(\n            "max_cli_version"\n        )\n        return self._max_cli_version\n\n    @normalize_exceptions\n    def viewer_server_info(self) -> tuple[dict[str, Any], dict[str, Any]]:\n        local_query = """\n            latestLocalVersionInfo {\n                outOfDate\n                latestVersionString\n                versionOnThisInstanceString\n            }\n        """\n        cli_query = """\n            serverInfo {\n                cliVersionInfo\n                _LOCAL_QUERY_\n            }\n        """\n        query_template = """\n        query Viewer{\n            viewer {\n                id\n                entity\n                username\n                email\n                flags\n                teams {\n                    edges {\n                        node {\n                            name\n                        }\n                    }\n                }\n            }\n            _CLI_QUERY_\n        }\n        """\n        query_types, server_info_types, _ = self.server_info_introspection()\n\n        cli_version_exists = (\n            "serverInfo" in query_types and "cliVersionInfo" in server_info_types\n        )\n\n        local_version_exists = (\n            "serverInfo" in query_types\n            and "latestLocalVersionInfo" in server_info_types\n        )\n\n        cli_query_string = "" if not cli_version_exists else cli_query\n        local_query_string = "" if not local_version_exists else local_query\n\n        query_string = query_template.replace("_CLI_QUERY_", cli_query_string).replace(\n            "_LOCAL_QUERY_", local_query_string\n        )\n        query = gql(query_string)\n        res = self.gql(query)\n        return res.get("viewer") or {}, res.get("serverInfo") or {}\n\n    @normalize_exceptions\n    def list_projects(self, entity: str | None = None) -> list[dict[str, str]]:\n        """List projects in W&B scoped by entity.\n\n        Args:\n            entity (str, optional): The entity to scope this project to.\n\n        Returns:\n                [{"id","name","description"}]\n        """\n        query = gql(\n            """\n        query EntityProjects($entity: String) {\n            models(first: 10, entityName: $entity) {\n                edges {\n                    node {\n                        id\n                        name\n                        description\n                    }\n                }\n            }\n        }\n        """\n        )\n        project_list: list[dict[str, str]] = self._flatten_edges(\n            self.gql(\n                query, variable_values={"entity": entity or self.settings("entity")}\n            )["models"]\n        )\n        return project_list\n\n    @normalize_exceptions\n    def project(self, project: str, entity: str | None = None) -> _Response:\n        """Retrieve project.\n\n        Args:\n            project (str): The project to get details for\n            entity (str, optional): The entity to scope this project to.\n\n        Returns:\n                [{"id","name","repo","dockerImage","description"}]\n        """\n        query = gql(\n            """\n        query ProjectDetails($entity: String, $project: String) {\n            model(name: $project, entityName: $entity) {\n                id\n                name\n                repo\n                dockerImage\n                description\n            }\n        }\n        """\n        )\n        response: _Response = self.gql(\n            query, variable_values={"entity": entity, "project": project}\n        )["model"]\n        return response\n\n    @normalize_exceptions\n    def sweep(\n        self,\n        sweep: str,\n        specs: str,\n        project: str | None = None,\n        entity: str | None = None,\n    ) -> dict[str, Any]:\n        """Retrieve sweep.\n\n        Args:\n            sweep (str): The sweep to get details for\n            specs (str): history specs\n            project (str, optional): The project to scope this sweep to.\n            entity (str, optional): The entity to scope this sweep to.\n\n        Returns:\n                [{"id","name","repo","dockerImage","description"}]\n        """\n        query = gql(\n            """\n        query SweepWithRuns($entity: String, $project: String, $sweep: String!, $specs: [JSONString!]!) {\n            project(name: $project, entityName: $entity) {\n                sweep(sweepName: $sweep) {\n                    id\n                    name\n                    method\n                    state\n                    description\n                    config\n                    createdAt\n                    heartbeatAt\n                    updatedAt\n                    earlyStopJobRunning\n                    bestLoss\n                    controller\n                    scheduler\n                    runs {\n                        edges {\n                            node {\n                                name\n                                state\n                                config\n                                exitcode\n                                heartbeatAt\n                                shouldStop\n                                failed\n                                stopped\n                                running\n                                summaryMetrics\n                                sampledHistory(specs: $specs)\n                            }\n                        }\n                    }\n                }\n            }\n        }\n        """\n        )\n        entity = entity or self.settings("entity")\n        project = project or self.settings("project")\n        response = self.gql(\n            query,\n            variable_values={\n                "entity": entity,\n                "project": project,\n                "sweep": sweep,\n                "specs": specs,\n            },\n        )\n        if response["project"] is None or response["project"]["sweep"] is None:\n            raise ValueError(f"Sweep {entity}/{project}/{sweep} not found")\n        data: dict[str, Any] = response["project"]["sweep"]\n        if data:\n            data["runs"] = self._flatten_edges(data["runs"])\n        return data\n\n    @normalize_exceptions\n    def list_runs(\n        self, project: str, entity: str | None = None\n    ) -> list[dict[str, str]]:\n        """List runs in W&B scoped by project.\n\n        Args:\n            project (str): The project to scope the runs to\n            entity (str, optional): The entity to scope this project to.  Defaults to public models\n\n        Returns:\n                [{"id","name","description"}]\n        """\n        query = gql(\n            """\n        query ProjectRuns($model: String!, $entity: String) {\n            model(name: $model, entityName: $entity) {\n                buckets(first: 10) {\n                    edges {\n                        node {\n                            id\n                            name\n                            displayName\n                            description\n                        }\n                    }\n                }\n            }\n        }\n        """\n        )\n        return self._flatten_edges(\n            self.gql(\n                query,\n                variable_values={\n                    "entity": entity or self.settings("entity"),\n                    "model": project or self.settings("project"),\n                },\n            )["model"]["buckets"]\n        )\n\n    @normalize_exceptions\n    def run_config(\n        self, project: str, run: str | None = None, entity: str | None = None\n    ) -> tuple[str, dict[str, Any], str | None, dict[str, Any]]:\n        """Get the relevant configs for a run.\n\n        Args:\n            project (str): The project to download, (can include bucket)\n            run (str, optional): The run to download\n            entity (str, optional): The entity to scope this project to.\n        """\n        import requests\n\n        check_httpclient_logger_handler()\n\n        query = gql(\n            """\n        query RunConfigs(\n            $name: String!,\n            $entity: String,\n            $run: String!,\n            $pattern: String!,\n            $includeConfig: Boolean!,\n        ) {\n            model(name: $name, entityName: $entity) {\n                bucket(name: $run) {\n                    config @include(if: $includeConfig)\n                    commit @include(if: $includeConfig)\n                    files(pattern: $pattern) {\n                        pageInfo {\n                            hasNextPage\n                            endCursor\n                        }\n                        edges {\n                            node {\n                                name\n                                directUrl\n                            }\n                        }\n                    }\n                }\n            }\n        }\n        """\n        )\n\n        variable_values = {\n            "name": project,\n            "run": run,\n            "entity": entity,\n            "includeConfig": True,\n        }\n\n        commit: str = ""\n        config: dict[str, Any] = {}\n        patch: str | None = None\n        metadata: dict[str, Any] = {}\n\n        # If we use the `names` parameter on the `files` node, then the server\n        # will helpfully give us and \'open\' file handle to the files that don\'t\n        # exist. This is so that we can upload data to it. However, in this\n        # case, we just want to download that file and not upload to it, so\n        # let\'s instead query for the files that do exist using `pattern`\n        # (with no wildcards).\n        #\n        # Unfortunately we\'re unable to construct a single pattern that matches\n        # our 2 files, we would need something like regex for that.\n        for filename in [DIFF_FNAME, METADATA_FNAME]:\n            variable_values["pattern"] = filename\n            response = self.gql(query, variable_values=variable_values)\n            if response["model"] is None:\n                raise CommError(f"Run {entity}/{project}/{run} not found")\n            run_obj: dict = response["model"]["bucket"]\n            # we only need to fetch this config once\n            if variable_values["includeConfig"]:\n                commit = run_obj["commit"]\n                config = json.loads(run_obj["config"] or "{}")\n                variable_values["includeConfig"] = False\n            if run_obj["files"] is not None:\n                for file_edge in run_obj["files"]["edges"]:\n                    name = file_edge["node"]["name"]\n                    url = file_edge["node"]["directUrl"]\n                    res = requests.get(url)\n                    res.raise_for_status()\n                    if name == METADATA_FNAME:\n                        metadata = res.json()\n                    elif name == DIFF_FNAME:\n                        patch = res.text\n\n        return commit, config, patch, metadata\n\n    @normalize_exceptions\n    def run_resume_status(\n        self, entity: str, project_name: str, name: str\n    ) -> dict[str, Any] | None:\n        """Check if a run exists and get resume information.\n\n        Args:\n            entity (str): The entity to scope this project to.\n            project_name (str): The project to download, (can include bucket)\n            name (str): The run to download\n        """\n        # Pulling wandbConfig.start_time is required so that we can determine if a run has actually started\n        query = gql(\n            """\n        query RunResumeStatus($project: String, $entity: String, $name: String!) {\n            model(name: $project, entityName: $entity) {\n                id\n                name\n                entity {\n                    id\n                    name\n                }\n\n                bucket(name: $name, missingOk: true) {\n                    id\n                    name\n                    summaryMetrics\n                    displayName\n                    logLineCount\n                    historyLineCount\n                    eventsLineCount\n                    historyTail\n                    eventsTail\n                    config\n                    tags\n                    wandbConfig(keys: ["t"])\n                }\n            }\n        }\n        """\n        )\n\n        response = self.gql(\n            query,\n            variable_values={\n                "entity": entity,\n                "project": project_name,\n                "name": name,\n            },\n        )\n\n        if "model" not in response or "bucket" not in (response["model"] or {}):\n            return None\n\n        project = response["model"]\n        self.set_setting("project", project_name)\n        if "entity" in project:\n            self.set_setting("entity", project["entity"]["name"])\n\n        result: dict[str, Any] = project["bucket"]\n\n        return result\n\n    @normalize_exceptions\n    def check_stop_requested(\n        self, project_name: str, entity_name: str, run_id: str\n    ) -> bool:\n        query = gql(\n            """\n        query RunStoppedStatus($projectName: String, $entityName: String, $runId: String!) {\n            project(name:$projectName, entityName:$entityName) {\n                run(name:$runId) {\n                    stopped\n                }\n            }\n        }\n        """\n        )\n\n        response = self.gql(\n            query,\n            variable_values={\n                "projectName": project_name,\n                "entityName": entity_name,\n                "runId": run_id,\n            },\n        )\n\n        project = response.get("project", None)\n        if not project:\n            return False\n        run = project.get("run", None)\n        if not run:\n            return False\n\n        status: bool = run["stopped"]\n        return status\n\n    def format_project(self, project: str) -> str:\n        return re.sub(r"\\W+", "-", project.lower()).strip("-_")\n\n    @normalize_exceptions\n    def upsert_project(\n        self,\n        project: str,\n        id: str | None = None,\n        description: str | None = None,\n        entity: str | None = None,\n    ) -> dict[str, Any]:\n        """Create a new project.\n\n        Args:\n            project (str): The project to create\n            description (str, optional): A description of this project\n            entity (str, optional): The entity to scope this project to.\n        """\n        mutation = gql(\n            """\n        mutation UpsertModel($name: String!, $id: String, $entity: String!, $description: String, $repo: String)  {\n            upsertModel(input: { id: $id, name: $name, entityName: $entity, description: $description, repo: $repo }) {\n                model {\n                    name\n                    description\n                }\n            }\n        }\n        """\n        )\n        response = self.gql(\n            mutation,\n            variable_values={\n                "name": self.format_project(project),\n                "entity": entity or self.settings("entity"),\n                "description": description,\n                "id": id,\n            },\n        )\n        result: dict[str, Any] = response["upsertModel"]["model"]\n        return result\n\n    @normalize_exceptions\n    def entity_is_team(self, entity: str) -> bool:\n        query = gql(\n            """\n            query EntityIsTeam($entity: String!) {\n                entity(name: $entity) {\n                    id\n                    isTeam\n                }\n            }\n            """\n        )\n        variable_values = {\n            "entity": entity,\n        }\n\n        res = self.gql(query, variable_values)\n        if res.get("entity") is None:\n            raise Exception(\n                f"Error fetching entity {entity} "\n                "check that you have access to this entity"\n            )\n\n        is_team: bool = res["entity"]["isTeam"]\n        return is_team\n\n    @normalize_exceptions\n    def get_project_run_queues(self, entity: str, project: str) -> list[dict[str, str]]:\n        query = gql(\n            """\n        query ProjectRunQueues($entity: String!, $projectName: String!){\n            project(entityName: $entity, name: $projectName) {\n                runQueues {\n                    id\n                    name\n                    createdBy\n                    access\n                }\n            }\n        }\n        """\n        )\n        variable_values = {\n            "projectName": project,\n            "entity": entity,\n        }\n\n        res = self.gql(query, variable_values)\n        if res.get("project") is None:\n            # circular dependency: (LAUNCH_DEFAULT_PROJECT = model-registry)\n            if project == "model-registry":\n                msg = (\n                    f"Error fetching run queues for {entity} "\n                    "check that you have access to this entity and project"\n                )\n            else:\n                msg = (\n                    f"Error fetching run queues for {entity}/{project} "\n                    "check that you have access to this entity and project"\n                )\n\n            raise Exception(msg)\n\n        project_run_queues: list[dict[str, str]] = res["project"]["runQueues"]\n        return project_run_queues\n\n    @normalize_exceptions\n    def create_default_resource_config(\n        self,\n        entity: str,\n        resource: str,\n        config: str,\n        template_variables: dict[str, float | int | str] | None,\n    ) -> dict[str, Any] | None:\n        if not self.create_default_resource_config_introspection():\n            raise Exception()\n        supports_template_vars, _ = self.push_to_run_queue_introspection()\n\n        mutation_params = """\n            $entityName: String!,\n            $resource: String!,\n            $config: JSONString!\n        """\n        mutation_inputs = """\n            entityName: $entityName,\n            resource: $resource,\n            config: $config\n        """\n\n        if supports_template_vars:\n            mutation_params += ", $templateVariables: JSONString"\n            mutation_inputs += ", templateVariables: $templateVariables"\n        else:\n            if template_variables is not None:\n                raise UnsupportedError(\n                    "server does not support template variables, please update server instance to >=0.46"\n                )\n\n        variable_values = {\n            "entityName": entity,\n            "resource": resource,\n            "config": config,\n        }\n        if supports_template_vars:\n            if template_variables is not None:\n                variable_values["templateVariables"] = json.dumps(template_variables)\n            else:\n                variable_values["templateVariables"] = "{}"\n\n        query = gql(\n            f"""\n        mutation createDefaultResourceConfig(\n            {mutation_params}\n        ) {{\n            createDefaultResourceConfig(\n            input: {{\n                {mutation_inputs}\n            }}\n            ) {{\n            defaultResourceConfigID\n            success\n            }}\n        }}\n        """\n        )\n\n        result: dict[str, Any] | None = self.gql(query, variable_values)[\n            "createDefaultResourceConfig"\n        ]\n        return result\n\n    @normalize_exceptions\n    def create_run_queue(\n        self,\n        entity: str,\n        project: str,\n        queue_name: str,\n        access: str,\n        prioritization_mode: str | None = None,\n        config_id: str | None = None,\n    ) -> dict[str, Any] | None:\n        (\n            create_run_queue,\n            supports_drc,\n            supports_prioritization,\n        ) = self.create_run_queue_introspection()\n        if not create_run_queue:\n            raise UnsupportedError(\n                "run queue creation is not supported by this version of "\n                "wandb server. Consider updating to the latest version."\n            )\n        if not supports_drc and config_id is not None:\n            raise UnsupportedError(\n                "default resource configurations are not supported by this version "\n                "of wandb server. Consider updating to the latest version."\n            )\n        if not supports_prioritization and prioritization_mode is not None:\n            raise UnsupportedError(\n                "launch prioritization is not supported by this version of "\n                "wandb server. Consider updating to the latest version."\n            )\n\n        if supports_prioritization:\n            query = gql(\n                """\n            mutation createRunQueue(\n                $entity: String!,\n                $project: String!,\n                $queueName: String!,\n                $access: RunQueueAccessType!,\n                $prioritizationMode: RunQueuePrioritizationMode,\n                $defaultResourceConfigID: ID,\n            ) {\n                createRunQueue(\n                    input: {\n                        entityName: $entity,\n                        projectName: $project,\n                        queueName: $queueName,\n                        access: $access,\n                        prioritizationMode: $prioritizationMode\n                        defaultResourceConfigID: $defaultResourceConfigID\n                    }\n                ) {\n                    success\n                    queueID\n                }\n            }\n            """\n            )\n            variable_values = {\n                "entity": entity,\n                "project": project,\n                "queueName": queue_name,\n                "access": access,\n                "prioritizationMode": prioritization_mode,\n                "defaultResourceConfigID": config_id,\n            }\n        else:\n            query = gql(\n                """\n            mutation createRunQueue(\n                $entity: String!,\n                $project: String!,\n                $queueName: String!,\n                $access: RunQueueAccessType!,\n                $defaultResourceConfigID: ID,\n            ) {\n                createRunQueue(\n                    input: {\n                        entityName: $entity,\n                        projectName: $project,\n                        queueName: $queueName,\n                        access: $access,\n                        defaultResourceConfigID: $defaultResourceConfigID\n                    }\n                ) {\n                    success\n                    queueID\n                }\n            }\n            """\n            )\n            variable_values = {\n                "entity": entity,\n                "project": project,\n                "queueName": queue_name,\n                "access": access,\n                "defaultResourceConfigID": config_id,\n            }\n\n        result: dict[str, Any] | None = self.gql(query, variable_values)[\n            "createRunQueue"\n        ]\n        return result\n\n    @normalize_exceptions\n    def upsert_run_queue(\n        self,\n        queue_name: str,\n        entity: str,\n        resource_type: str,\n        resource_config: dict,\n        project: str = LAUNCH_DEFAULT_PROJECT,\n        prioritization_mode: str | None = None,\n        template_variables: dict | None = None,\n        external_links: dict | None = None,\n    ) -> dict[str, Any] | None:\n        if not self.upsert_run_queue_introspection():\n            raise UnsupportedError(\n                "upserting run queues is not supported by this version of "\n                "wandb server. Consider updating to the latest version."\n            )\n        query = gql(\n            """\n            mutation upsertRunQueue(\n                $entityName: String!\n                $projectName: String!\n                $queueName: String!\n                $resourceType: String!\n                $resourceConfig: JSONString!\n                $templateVariables: JSONString\n                $prioritizationMode: RunQueuePrioritizationMode\n                $externalLinks: JSONString\n                $clientMutationId: String\n            ) {\n                upsertRunQueue(\n                    input: {\n                        entityName: $entityName\n                        projectName: $projectName\n                        queueName: $queueName\n                        resourceType: $resourceType\n                        resourceConfig: $resourceConfig\n                        templateVariables: $templateVariables\n                        prioritizationMode: $prioritizationMode\n                        externalLinks: $externalLinks\n                        clientMutationId: $clientMutationId\n                    }\n                ) {\n                    success\n                    configSchemaValidationErrors\n                }\n            }\n            """\n        )\n        variable_values = {\n            "entityName": entity,\n            "projectName": project,\n            "queueName": queue_name,\n            "resourceType": resource_type,\n            "resourceConfig": json.dumps(resource_config),\n            "templateVariables": (\n                json.dumps(template_variables) if template_variables else None\n            ),\n            "prioritizationMode": prioritization_mode,\n            "externalLinks": json.dumps(external_links) if external_links else None,\n        }\n        result: dict[str, Any] = self.gql(query, variable_values)\n        return result["upsertRunQueue"]\n\n    @normalize_exceptions\n    def push_to_run_queue_by_name(\n        self,\n        entity: str,\n        project: str,\n        queue_name: str,\n        run_spec: str,\n        template_variables: dict[str, int | float | str] | None,\n        priority: int | None = None,\n    ) -> dict[str, Any] | None:\n        self.push_to_run_queue_introspection()\n        """Queryless mutation, should be used before legacy fallback method."""\n\n        mutation_params = """\n            $entityName: String!,\n            $projectName: String!,\n            $queueName: String!,\n            $runSpec: JSONString!\n        """\n\n        mutation_input = """\n            entityName: $entityName,\n            projectName: $projectName,\n            queueName: $queueName,\n            runSpec: $runSpec\n        """\n\n        variables: dict[str, Any] = {\n            "entityName": entity,\n            "projectName": project,\n            "queueName": queue_name,\n            "runSpec": run_spec,\n        }\n        if self.server_push_to_run_queue_supports_priority:\n            if priority is not None:\n                variables["priority"] = priority\n                mutation_params += ", $priority: Int"\n                mutation_input += ", priority: $priority"\n        else:\n            if priority is not None:\n                raise UnsupportedError(\n                    "server does not support priority, please update server instance to >=0.46"\n                )\n\n        if self.server_supports_template_variables:\n            if template_variables is not None:\n                variables.update(\n                    {"templateVariableValues": json.dumps(template_variables)}\n                )\n                mutation_params += ", $templateVariableValues: JSONString"\n                mutation_input += ", templateVariableValues: $templateVariableValues"\n        else:\n            if template_variables is not None:\n                raise UnsupportedError(\n                    "server does not support template variables, please update server instance to >=0.46"\n                )\n\n        mutation = gql(\n            f"""\n        mutation pushToRunQueueByName(\n          {mutation_params}\n        ) {{\n            pushToRunQueueByName(\n                input: {{\n                    {mutation_input}\n                }}\n            ) {{\n                runQueueItemId\n                runSpec\n            }}\n        }}\n        """\n        )\n\n        try:\n            result: dict[str, Any] | None = self.gql(\n                mutation, variables, check_retry_fn=util.no_retry_4xx\n            ).get("pushToRunQueueByName")\n            if not result:\n                return None\n\n            if result.get("runSpec"):\n                run_spec = json.loads(str(result["runSpec"]))\n                result["runSpec"] = run_spec\n\n            return result\n        except Exception as e:\n            if (\n                \'Cannot query field "runSpec" on type "PushToRunQueueByNamePayload"\'\n                not in str(e)\n            ):\n                return None\n\n        mutation_no_runspec = gql(\n            """\n        mutation pushToRunQueueByName(\n            $entityName: String!,\n            $projectName: String!,\n            $queueName: String!,\n            $runSpec: JSONString!,\n        ) {\n            pushToRunQueueByName(\n                input: {\n                    entityName: $entityName,\n                    projectName: $projectName,\n                    queueName: $queueName,\n                    runSpec: $runSpec\n                }\n            ) {\n                runQueueItemId\n            }\n        }\n        """\n        )\n\n        try:\n            result = self.gql(\n                mutation_no_runspec, variables, check_retry_fn=util.no_retry_4xx\n            ).get("pushToRunQueueByName")\n        except Exception:\n            result = None\n\n        return result\n\n    @normalize_exceptions\n    def push_to_run_queue(\n        self,\n        queue_name: str,\n        launch_spec: dict[str, str],\n        template_variables: dict | None,\n        project_queue: str,\n        priority: int | None = None,\n    ) -> dict[str, Any] | None:\n        self.push_to_run_queue_introspection()\n        entity = launch_spec.get("queue_entity") or launch_spec["entity"]\n        run_spec = json.dumps(launch_spec)\n\n        push_result = self.push_to_run_queue_by_name(\n            entity, project_queue, queue_name, run_spec, template_variables, priority\n        )\n\n        if push_result:\n            return push_result\n\n        if priority is not None:\n            # Cannot proceed with legacy method if priority is set\n            return None\n\n        """ Legacy Method """\n        queues_found = self.get_project_run_queues(entity, project_queue)\n        matching_queues = [\n            q\n            for q in queues_found\n            if q["name"] == queue_name\n            # ensure user has access to queue\n            and (\n                # TODO: User created queues in the UI have USER access\n                q["access"] in ["PROJECT", "USER"]\n                or q["createdBy"] == self.default_entity\n            )\n        ]\n        if not matching_queues:\n            # in the case of a missing default queue. create it\n            if queue_name == "default":\n                wandb.termlog(\n                    f"No default queue existing for entity: {entity} in project: {project_queue}, creating one."\n                )\n                res = self.create_run_queue(\n                    launch_spec["entity"],\n                    project_queue,\n                    queue_name,\n                    access="PROJECT",\n                )\n\n                if res is None or res.get("queueID") is None:\n                    wandb.termerror(\n                        f"Unable to create default queue for entity: {entity} on project: {project_queue}. Run could not be added to a queue"\n                    )\n                    return None\n                queue_id = res["queueID"]\n\n            else:\n                if project_queue == "model-registry":\n                    _msg = f"Unable to push to run queue {queue_name}. Queue not found."\n                else:\n                    _msg = f"Unable to push to run queue {project_queue}/{queue_name}. Queue not found."\n                wandb.termwarn(_msg)\n                return None\n        elif len(matching_queues) > 1:\n            wandb.termerror(\n                f"Unable to push to run queue {queue_name}. More than one queue found with this name."\n            )\n            return None\n        else:\n            queue_id = matching_queues[0]["id"]\n        spec_json = json.dumps(launch_spec)\n        variables = {"queueID": queue_id, "runSpec": spec_json}\n\n        mutation_params = """\n            $queueID: ID!,\n            $runSpec: JSONString!\n        """\n        mutation_input = """\n            queueID: $queueID,\n            runSpec: $runSpec\n        """\n        if self.server_supports_template_variables:\n            if template_variables is not None:\n                mutation_params += ", $templateVariableValues: JSONString"\n                mutation_input += ", templateVariableValues: $templateVariableValues"\n                variables.update(\n                    {"templateVariableValues": json.dumps(template_variables)}\n                )\n        else:\n            if template_variables is not None:\n                raise UnsupportedError(\n                    "server does not support template variables, please update server instance to >=0.46"\n                )\n\n        mutation = gql(\n            f"""\n        mutation pushToRunQueue(\n            {mutation_params}\n            ) {{\n            pushToRunQueue(\n                input: {{{mutation_input}}}\n            ) {{\n                runQueueItemId\n            }}\n        }}\n        """\n        )\n\n        response = self.gql(mutation, variable_values=variables)\n        if not response.get("pushToRunQueue"):\n            raise CommError(f"Error pushing run queue item to queue {queue_name}.")\n\n        result: dict[str, Any] | None = response["pushToRunQueue"]\n        return result\n\n    @normalize_exceptions\n    def pop_from_run_queue(\n        self,\n        queue_name: str,\n        entity: str | None = None,\n        project: str | None = None,\n        agent_id: str | None = None,\n    ) -> dict[str, Any] | None:\n        mutation = gql(\n            """\n        mutation popFromRunQueue($entity: String!, $project: String!, $queueName: String!, $launchAgentId: ID)  {\n            popFromRunQueue(input: {\n                entityName: $entity,\n                projectName: $project,\n                queueName: $queueName,\n                launchAgentId: $launchAgentId\n            }) {\n                runQueueItemId\n                runSpec\n            }\n        }\n        """\n        )\n        response = self.gql(\n            mutation,\n            variable_values={\n                "entity": entity,\n                "project": project,\n                "queueName": queue_name,\n                "launchAgentId": agent_id,\n            },\n        )\n        result: dict[str, Any] | None = response["popFromRunQueue"]\n        return result\n\n    @normalize_exceptions\n    def ack_run_queue_item(self, item_id: str, run_id: str | None = None) -> bool:\n        mutation = gql(\n            """\n        mutation ackRunQueueItem($itemId: ID!, $runId: String!)  {\n            ackRunQueueItem(input: { runQueueItemId: $itemId, runName: $runId }) {\n                success\n            }\n        }\n        """\n        )\n        response = self.gql(\n            mutation, variable_values={"itemId": item_id, "runId": str(run_id)}\n        )\n        if not response["ackRunQueueItem"]["success"]:\n            raise CommError(\n                "Error acking run queue item. Item may have already been acknowledged by another process"\n            )\n        result: bool = response["ackRunQueueItem"]["success"]\n        return result\n\n    @normalize_exceptions\n    def create_launch_agent_fields_introspection(self) -> list:\n        if self.create_launch_agent_input_info:\n            return self.create_launch_agent_input_info\n        query_string = """\n           query ProbeServerCreateLaunchAgentInput {\n                CreateLaunchAgentInputInfoType: __type(name:"CreateLaunchAgentInput") {\n                    inputFields{\n                        name\n                    }\n                }\n            }\n        """\n\n        query = gql(query_string)\n        res = self.gql(query)\n\n        self.create_launch_agent_input_info = [\n            field.get("name", "")\n            for field in res.get("CreateLaunchAgentInputInfoType", {}).get(\n                "inputFields", [{}]\n            )\n        ]\n        return self.create_launch_agent_input_info\n\n    @normalize_exceptions\n    def create_launch_agent(\n        self,\n        entity: str,\n        project: str,\n        queues: list[str],\n        agent_config: dict[str, Any],\n        version: str,\n        gorilla_agent_support: bool,\n    ) -> dict:\n        project_queues = self.get_project_run_queues(entity, project)\n        if not project_queues:\n            # create default queue if it doesn\'t already exist\n            default = self.create_run_queue(\n                entity, project, "default", access="PROJECT"\n            )\n            if default is None or default.get("queueID") is None:\n                raise CommError(\n                    f"Unable to create default queue for {entity}/{project}. No queues for agent to poll"\n                )\n            project_queues = [{"id": default["queueID"], "name": "default"}]\n        polling_queue_ids = [\n            q["id"] for q in project_queues if q["name"] in queues\n        ]  # filter to poll specified queues\n        if len(polling_queue_ids) != len(queues):\n            raise CommError(\n                f"Could not start launch agent: Not all of requested queues ({\', \'.join(queues)}) found. "\n                f"Available queues for this project: {\',\'.join([q[\'name\'] for q in project_queues])}"\n            )\n\n        if not gorilla_agent_support:\n            # if gorilla doesn\'t support launch agents, return a client-generated id\n            return {\n                "success": True,\n                "launchAgentId": None,\n            }\n\n        hostname = socket.gethostname()\n\n        variable_values = {\n            "entity": entity,\n            "project": project,\n            "queues": polling_queue_ids,\n            "hostname": hostname,\n        }\n\n        mutation_params = """\n            $entity: String!,\n            $project: String!,\n            $queues: [ID!]!,\n            $hostname: String!\n        """\n\n        mutation_input = """\n            entityName: $entity,\n            projectName: $project,\n            runQueues: $queues,\n            hostname: $hostname\n        """\n\n        if "agentConfig" in self.create_launch_agent_fields_introspection():\n            variable_values["agentConfig"] = json.dumps(agent_config)\n            mutation_params += ", $agentConfig: JSONString"\n            mutation_input += ", agentConfig: $agentConfig"\n        if "version" in self.create_launch_agent_fields_introspection():\n            variable_values["version"] = version\n            mutation_params += ", $version: String"\n            mutation_input += ", version: $version"\n\n        mutation = gql(\n            f"""\n            mutation createLaunchAgent(\n                {mutation_params}\n            ) {{\n                createLaunchAgent(\n                    input: {{\n                        {mutation_input}\n                    }}\n                ) {{\n                    launchAgentId\n                }}\n            }}\n            """\n        )\n        result: dict = self.gql(mutation, variable_values)["createLaunchAgent"]\n        return result\n\n    @normalize_exceptions\n    def update_launch_agent_status(\n        self,\n        agent_id: str,\n        status: str,\n        gorilla_agent_support: bool,\n    ) -> dict:\n        if not gorilla_agent_support:\n            # if gorilla doesn\'t support launch agents, this is a no-op\n            return {\n                "success": True,\n            }\n\n        mutation = gql(\n            """\n            mutation updateLaunchAgent($agentId: ID!, $agentStatus: String){\n                updateLaunchAgent(\n                    input: {\n                        launchAgentId: $agentId\n                        agentStatus: $agentStatus\n                    }\n                ) {\n                    success\n                }\n            }\n            """\n        )\n        variable_values = {\n            "agentId": agent_id,\n            "agentStatus": status,\n        }\n        result: dict = self.gql(mutation, variable_values)["updateLaunchAgent"]\n        return result\n\n    @normalize_exceptions\n    def get_launch_agent(self, agent_id: str, gorilla_agent_support: bool) -> dict:\n        if not gorilla_agent_support:\n            return {\n                "id": None,\n                "name": "",\n                "stopPolling": False,\n            }\n        query = gql(\n            """\n            query LaunchAgent($agentId: ID!) {\n                launchAgent(id: $agentId) {\n                    id\n                    name\n                    runQueues\n                    hostname\n                    agentStatus\n                    stopPolling\n                    heartbeatAt\n                }\n            }\n            """\n        )\n        variable_values = {\n            "agentId": agent_id,\n        }\n        result: dict = self.gql(query, variable_values)["launchAgent"]\n        return result\n\n    @normalize_exceptions\n    def upsert_run(\n        self,\n        id: str | None = None,\n        name: str | None = None,\n        project: str | None = None,\n        host: str | None = None,\n        group: str | None = None,\n        tags: list[str] | None = None,\n        config: dict | None = None,\n        description: str | None = None,\n        entity: str | None = None,\n        state: str | None = None,\n        display_name: str | None = None,\n        notes: str | None = None,\n        repo: str | None = None,\n        job_type: str | None = None,\n        program_path: str | None = None,\n        commit: str | None = None,\n        sweep_name: str | None = None,\n        summary_metrics: str | None = None,\n        num_retries: int | None = None,\n    ) -> tuple[dict, bool, list | None]:\n        """Update a run.\n\n        Args:\n            id (str, optional): The existing run to update\n            name (str, optional): The name of the run to create\n            group (str, optional): Name of the group this run is a part of\n            project (str, optional): The name of the project\n            host (str, optional): The name of the host\n            tags (list, optional): A list of tags to apply to the run\n            config (dict, optional): The latest config params\n            description (str, optional): A description of this project\n            entity (str, optional): The entity to scope this project to.\n            display_name (str, optional): The display name of this project\n            notes (str, optional): Notes about this run\n            repo (str, optional): Url of the program\'s repository.\n            state (str, optional): State of the program.\n            job_type (str, optional): Type of job, e.g \'train\'.\n            program_path (str, optional): Path to the program.\n            commit (str, optional): The Git SHA to associate the run with\n            sweep_name (str, optional): The name of the sweep this run is a part of\n            summary_metrics (str, optional): The JSON summary metrics\n            num_retries (int, optional): Number of retries\n        """\n        query_string = """\n        mutation UpsertBucket(\n            $id: String,\n            $name: String,\n            $project: String,\n            $entity: String,\n            $groupName: String,\n            $description: String,\n            $displayName: String,\n            $notes: String,\n            $commit: String,\n            $config: JSONString,\n            $host: String,\n            $debug: Boolean,\n            $program: String,\n            $repo: String,\n            $jobType: String,\n            $state: String,\n            $sweep: String,\n            $tags: [String!],\n            $summaryMetrics: JSONString,\n        ) {\n            upsertBucket(input: {\n                id: $id,\n                name: $name,\n                groupName: $groupName,\n                modelName: $project,\n                entityName: $entity,\n                description: $description,\n                displayName: $displayName,\n                notes: $notes,\n                config: $config,\n                commit: $commit,\n                host: $host,\n                debug: $debug,\n                jobProgram: $program,\n                jobRepo: $repo,\n                jobType: $jobType,\n                state: $state,\n                sweep: $sweep,\n                tags: $tags,\n                summaryMetrics: $summaryMetrics,\n            }) {\n                bucket {\n                    id\n                    name\n                    displayName\n                    description\n                    config\n                    sweepName\n                    project {\n                        id\n                        name\n                        entity {\n                            id\n                            name\n                        }\n                    }\n                    historyLineCount\n                }\n                inserted\n                _Server_Settings_\n            }\n        }\n        """\n        self.server_settings_introspection()\n\n        server_settings_string = (\n            """\n        serverSettings {\n                serverMessages{\n                    utfText\n                    plainText\n                    htmlText\n                    messageType\n                    messageLevel\n                }\n         }\n        """\n            if self._server_settings_type\n            else ""\n        )\n\n        query_string = query_string.replace("_Server_Settings_", server_settings_string)\n        mutation = gql(query_string)\n        config_str = json.dumps(config) if config else None\n        if not description or description.isspace():\n            description = None\n\n        kwargs = {}\n        if num_retries is not None:\n            kwargs["num_retries"] = num_retries\n\n        variable_values = {\n            "id": id,\n            "entity": entity or self.settings("entity"),\n            "name": name,\n            "project": project or util.auto_project_name(program_path),\n            "groupName": group,\n            "tags": tags,\n            "description": description,\n            "config": config_str,\n            "commit": commit,\n            "displayName": display_name,\n            "notes": notes,\n            "host": None\n            if self.settings().get("anonymous") in ["allow", "must"]\n            else host,\n            "debug": env.is_debug(env=self._environ),\n            "repo": repo,\n            "program": program_path,\n            "jobType": job_type,\n            "state": state,\n            "sweep": sweep_name,\n            "summaryMetrics": summary_metrics,\n        }\n\n        # retry conflict errors for 2 minutes, default to no_auth_retry\n        check_retry_fn = util.make_check_retry_fn(\n            check_fn=util.check_retry_conflict_or_gone,\n            check_timedelta=datetime.timedelta(minutes=2),\n            fallback_retry_fn=util.no_retry_auth,\n        )\n\n        response = self.gql(\n            mutation,\n            variable_values=variable_values,\n            check_retry_fn=check_retry_fn,\n            **kwargs,\n        )\n\n        run_obj: dict[str, dict[str, dict[str, str]]] = response["upsertBucket"][\n            "bucket"\n        ]\n        project_obj: dict[str, dict[str, str]] = run_obj.get("project", {})\n        if project_obj:\n            self.set_setting("project", project_obj["name"])\n            entity_obj = project_obj.get("entity", {})\n            if entity_obj:\n                self.set_setting("entity", entity_obj["name"])\n\n        server_messages = None\n        if self._server_settings_type:\n            server_messages = (\n                response["upsertBucket"]\n                .get("serverSettings", {})\n                .get("serverMessages", [])\n            )\n\n        return (\n            response["upsertBucket"]["bucket"],\n            response["upsertBucket"]["inserted"],\n            server_messages,\n        )\n\n    @normalize_exceptions\n    def rewind_run(\n        self,\n        run_name: str,\n        metric_name: str,\n        metric_value: float,\n        program_path: str | None = None,\n        entity: str | None = None,\n        project: str | None = None,\n        num_retries: int | None = None,\n    ) -> dict:\n        """Rewinds a run to a previous state.\n\n        Args:\n            run_name (str): The name of the run to rewind\n            metric_name (str): The name of the metric to rewind to\n            metric_value (float): The value of the metric to rewind to\n            program_path (str, optional): Path to the program\n            entity (str, optional): The entity to scope this project to\n            project (str, optional): The name of the project\n            num_retries (int, optional): Number of retries\n\n        Returns:\n            A dict with the rewound run\n\n                {\n                    "id": "run_id",\n                    "name": "run_name",\n                    "displayName": "run_display_name",\n                    "description": "run_description",\n                    "config": "stringified_run_config_json",\n                    "sweepName": "run_sweep_name",\n                    "project": {\n                        "id": "project_id",\n                        "name": "project_name",\n                        "entity": {\n                            "id": "entity_id",\n                            "name": "entity_name"\n                        }\n                    },\n                    "historyLineCount": 100,\n                }\n        """\n        query_string = """\n        mutation RewindRun($runName: String!, $entity: String, $project: String, $metricName: String!, $metricValue: Float!) {\n            rewindRun(input: {runName: $runName, entityName: $entity, projectName: $project, metricName: $metricName, metricValue: $metricValue}) {\n                rewoundRun {\n                    id\n                    name\n                    displayName\n                    description\n                    config\n                    sweepName\n                    project {\n                        id\n                        name\n                        entity {\n                            id\n                            name\n                        }\n                    }\n                    historyLineCount\n                }\n            }\n        }\n        """\n\n        mutation = gql(query_string)\n\n        kwargs = {}\n        if num_retries is not None:\n            kwargs["num_retries"] = num_retries\n\n        variable_values = {\n            "runName": run_name,\n            "entity": entity or self.settings("entity"),\n            "project": project or util.auto_project_name(program_path),\n            "metricName": metric_name,\n            "metricValue": metric_value,\n        }\n\n        # retry conflict errors for 2 minutes, default to no_auth_retry\n        check_retry_fn = util.make_check_retry_fn(\n            check_fn=util.check_retry_conflict_or_gone,\n            check_timedelta=datetime.timedelta(minutes=2),\n            fallback_retry_fn=util.no_retry_auth,\n        )\n\n        response = self.gql(\n            mutation,\n            variable_values=variable_values,\n            check_retry_fn=check_retry_fn,\n            **kwargs,\n        )\n\n        run_obj: dict[str, dict[str, dict[str, str]]] = response.get(\n            "rewindRun", {}\n        ).get("rewoundRun", {})\n        project_obj: dict[str, dict[str, str]] = run_obj.get("project", {})\n        if project_obj:\n            self.set_setting("project", project_obj["name"])\n            entity_obj = project_obj.get("entity", {})\n            if entity_obj:\n                self.set_setting("entity", entity_obj["name"])\n\n        return run_obj\n\n    @normalize_exceptions\n    def get_run_info(\n        self,\n        entity: str,\n        project: str,\n        name: str,\n    ) -> dict:\n        query = gql(\n            """\n        query RunInfo($project: String!, $entity: String!, $name: String!) {\n            project(name: $project, entityName: $entity) {\n                run(name: $name) {\n                    runInfo {\n                        program\n                        args\n                        os\n                        python\n                        colab\n                        executable\n                        codeSaved\n                        cpuCount\n                        gpuCount\n                        gpu\n                        git {\n                            remote\n                            commit\n                        }\n                    }\n                }\n            }\n        }\n        """\n        )\n        variable_values = {"project": project, "entity": entity, "name": name}\n        res = self.gql(query, variable_values)\n        if res.get("project") is None:\n            raise CommError(\n                f"Error fetching run info for {entity}/{project}/{name}. Check that this project exists and you have access to this entity and project"\n            )\n        elif res["project"].get("run") is None:\n            raise CommError(\n                f"Error fetching run info for {entity}/{project}/{name}. Check that this run id exists"\n            )\n        run_info: dict = res["project"]["run"]["runInfo"]\n        return run_info\n\n    @normalize_exceptions\n    def get_run_state(self, entity: str, project: str, name: str) -> str:\n        query = gql(\n            """\n        query RunState(\n            $project: String!,\n            $entity: String!,\n            $name: String!) {\n            project(name: $project, entityName: $entity) {\n                run(name: $name) {\n                    state\n                }\n            }\n        }\n        """\n        )\n        variable_values = {\n            "project": project,\n            "entity": entity,\n            "name": name,\n        }\n        res = self.gql(query, variable_values)\n        if res.get("project") is None or res["project"].get("run") is None:\n            raise CommError(f"Error fetching run state for {entity}/{project}/{name}.")\n        run_state: str = res["project"]["run"]["state"]\n        return run_state\n\n    @normalize_exceptions\n    def create_run_files_introspection(self) -> bool:\n        _, _, mutations = self.server_info_introspection()\n        return "createRunFiles" in mutations\n\n    @normalize_exceptions\n    def upload_urls(\n        self,\n        project: str,\n        files: list[str] | dict[str, IO],\n        run: str | None = None,\n        entity: str | None = None,\n        description: str | None = None,\n    ) -> tuple[str, list[str], dict[str, dict[str, Any]]]:\n        """Generate temporary resumable upload urls.\n\n        Args:\n            project (str): The project to download\n            files (list or dict): The filenames to upload\n            run (str, optional): The run to upload to\n            entity (str, optional): The entity to scope this project to.\n            description (str, optional): description\n\n        Returns:\n            (run_id, upload_headers, file_info)\n            run_id: id of run we uploaded files to\n            upload_headers: A list of headers to use when uploading files.\n            file_info: A dict of filenames and urls.\n                {\n                    "run_id": "run_id",\n                    "upload_headers": [""],\n                    "file_info":  [\n                        { "weights.h5": { "uploadUrl": "https://weights.url" } },\n                        { "model.json": { "uploadUrl": "https://model.json" } }\n                    ]\n                }\n        """\n        run_name = run or self.current_run_id\n        assert run_name, "run must be specified"\n        entity = entity or self.settings("entity")\n        assert entity, "entity must be specified"\n\n        has_create_run_files_mutation = self.create_run_files_introspection()\n        if not has_create_run_files_mutation:\n            return self.legacy_upload_urls(project, files, run, entity, description)\n\n        query = gql(\n            """\n        mutation CreateRunFiles($entity: String!, $project: String!, $run: String!, $files: [String!]!) {\n            createRunFiles(input: {entityName: $entity, projectName: $project, runName: $run, files: $files}) {\n                runID\n                uploadHeaders\n                files {\n                    name\n                    uploadUrl\n                }\n            }\n        }\n        """\n        )\n\n        query_result = self.gql(\n            query,\n            variable_values={\n                "project": project,\n                "run": run_name,\n                "entity": entity,\n                "files": [file for file in files],\n            },\n        )\n\n        result = query_result["createRunFiles"]\n        run_id = result["runID"]\n        if not run_id:\n            raise CommError(\n                f"Error uploading files to {entity}/{project}/{run_name}. Check that this project exists and you have access to this entity and project"\n            )\n        file_name_urls = {file["name"]: file for file in result["files"]}\n        return run_id, result["uploadHeaders"], file_name_urls\n\n    def legacy_upload_urls(\n        self,\n        project: str,\n        files: list[str] | dict[str, IO],\n        run: str | None = None,\n        entity: str | None = None,\n        description: str | None = None,\n    ) -> tuple[str, list[str], dict[str, dict[str, Any]]]:\n        """Generate temporary resumable upload urls.\n\n        A new mutation createRunFiles was introduced after 0.15.4.\n        This function is used to support older versions.\n        """\n        query = gql(\n            """\n        query RunUploadUrls($name: String!, $files: [String]!, $entity: String, $run: String!, $description: String) {\n            model(name: $name, entityName: $entity) {\n                bucket(name: $run, desc: $description) {\n                    id\n                    files(names: $files) {\n                        uploadHeaders\n                        edges {\n                            node {\n                                name\n                                url(upload: true)\n                                updatedAt\n                            }\n                        }\n                    }\n                }\n            }\n        }\n        """\n        )\n        run_id = run or self.current_run_id\n        assert run_id, "run must be specified"\n        entity = entity or self.settings("entity")\n        query_result = self.gql(\n            query,\n            variable_values={\n                "name": project,\n                "run": run_id,\n                "entity": entity,\n                "files": [file for file in files],\n                "description": description,\n            },\n        )\n\n        run_obj = query_result["model"]["bucket"]\n        if run_obj:\n            for file_node in run_obj["files"]["edges"]:\n                file = file_node["node"]\n                # we previously used "url" field but now use "uploadUrl"\n                # replace the "url" field with "uploadUrl for downstream compatibility\n                if "url" in file and "uploadUrl" not in file:\n                    file["uploadUrl"] = file.pop("url")\n\n            result = {\n                file["name"]: file for file in self._flatten_edges(run_obj["files"])\n            }\n            return run_obj["id"], run_obj["files"]["uploadHeaders"], result\n        else:\n            raise CommError(f"Run does not exist {entity}/{project}/{run_id}.")\n\n    @normalize_exceptions\n    def download_urls(\n        self,\n        project: str,\n        run: str | None = None,\n        entity: str | None = None,\n    ) -> dict[str, dict[str, str]]:\n        """Generate download urls.\n\n        Args:\n            project (str): The project to download\n            run (str): The run to upload to\n            entity (str, optional): The entity to scope this project to.  Defaults to wandb models\n\n        Returns:\n            A dict of extensions and urls\n\n                {\n                    \'weights.h5\': { "url": "https://weights.url", "updatedAt": \'2013-04-26T22:22:23.832Z\', \'md5\': \'mZFLkyvTelC5g8XnyQrpOw==\' },\n                    \'model.json\': { "url": "https://model.url", "updatedAt": \'2013-04-26T22:22:23.832Z\', \'md5\': \'mZFLkyvTelC5g8XnyQrpOw==\' }\n                }\n        """\n        query = gql(\n            """\n        query RunDownloadUrls($name: String!, $entity: String, $run: String!)  {\n            model(name: $name, entityName: $entity) {\n                bucket(name: $run) {\n                    files {\n                        edges {\n                            node {\n                                name\n                                url\n                                md5\n                                updatedAt\n                            }\n                        }\n                    }\n                }\n            }\n        }\n        """\n        )\n        run = run or self.current_run_id\n        assert run, "run must be specified"\n        entity = entity or self.settings("entity")\n        query_result = self.gql(\n            query,\n            variable_values={\n                "name": project,\n                "run": run,\n                "entity": entity,\n            },\n        )\n        if query_result["model"] is None:\n            raise CommError(f"Run does not exist {entity}/{project}/{run}.")\n        files = self._flatten_edges(query_result["model"]["bucket"]["files"])\n        return {file["name"]: file for file in files if file}\n\n    @normalize_exceptions\n    def download_url(\n        self,\n        project: str,\n        file_name: str,\n        run: str | None = None,\n        entity: str | None = None,\n    ) -> dict[str, str] | None:\n        """Generate download urls.\n\n        Args:\n            project (str): The project to download\n            file_name (str): The name of the file to download\n            run (str): The run to upload to\n            entity (str, optional): The entity to scope this project to.  Defaults to wandb models\n\n        Returns:\n            A dict of extensions and urls\n\n                { "url": "https://weights.url", "updatedAt": \'2013-04-26T22:22:23.832Z\', \'md5\': \'mZFLkyvTelC5g8XnyQrpOw==\' }\n\n        """\n        query = gql(\n            """\n        query RunDownloadUrl($name: String!, $fileName: String!, $entity: String, $run: String!)  {\n            model(name: $name, entityName: $entity) {\n                bucket(name: $run) {\n                    files(names: [$fileName]) {\n                        edges {\n                            node {\n                                name\n                                url\n                                md5\n                                updatedAt\n                            }\n                        }\n                    }\n                }\n            }\n        }\n        """\n        )\n        run = run or self.current_run_id\n        assert run, "run must be specified"\n        query_result = self.gql(\n            query,\n            variable_values={\n                "name": project,\n                "run": run,\n                "fileName": file_name,\n                "entity": entity or self.settings("entity"),\n            },\n        )\n        if query_result["model"]:\n            files = self._flatten_edges(query_result["model"]["bucket"]["files"])\n            return files[0] if len(files) > 0 and files[0].get("updatedAt") else None\n        else:\n            return None\n\n    @normalize_exceptions\n    def download_file(self, url: str) -> tuple[int, requests.Response]:\n        """Initiate a streaming download.\n\n        Args:\n            url (str): The url to download\n\n        Returns:\n            A tuple of the content length and the streaming response\n        """\n        import requests\n\n        check_httpclient_logger_handler()\n\n        http_headers = {}\n\n        auth = None\n        if self.access_token is not None:\n            http_headers["Authorization"] = f"Bearer {self.access_token}"\n        else:\n            auth = ("api", self.api_key or "")\n\n        response = requests.get(\n            url,\n            auth=auth,\n            headers=http_headers,\n            stream=True,\n        )\n        response.raise_for_status()\n        return int(response.headers.get("content-length", 0)), response\n\n    @normalize_exceptions\n    def download_write_file(\n        self,\n        metadata: dict[str, str],\n        out_dir: str | None = None,\n    ) -> tuple[str, requests.Response | None]:\n        """Download a file from a run and write it to wandb/.\n\n        Args:\n            metadata (obj): The metadata object for the file to download. Comes from Api.download_urls().\n            out_dir (str, optional): The directory to write the file to. Defaults to wandb/\n\n        Returns:\n            A tuple of the file\'s local path and the streaming response. The streaming response is None if the file\n            already existed and was up-to-date.\n        """\n        filename = metadata["name"]\n        path = os.path.join(out_dir or self.settings("wandb_dir"), filename)\n        if self.file_current(filename, B64MD5(metadata["md5"])):\n            return path, None\n\n        size, response = self.download_file(metadata["url"])\n\n        with util.fsync_open(path, "wb") as file:\n            for data in response.iter_content(chunk_size=1024):\n                file.write(data)\n\n        return path, response\n\n    def upload_file_azure(\n        self, url: str, file: Any, extra_headers: dict[str, str]\n    ) -> None:\n        """Upload a file to azure."""\n        import requests\n        from azure.core.exceptions import AzureError  # type: ignore\n\n        # Configure the client without retries so our existing logic can handle them\n        client = self._azure_blob_module.BlobClient.from_blob_url(\n            url, retry_policy=self._azure_blob_module.LinearRetry(retry_total=0)\n        )\n        try:\n            if extra_headers.get("Content-MD5") is not None:\n                md5: bytes | None = base64.b64decode(extra_headers["Content-MD5"])\n            else:\n                md5 = None\n            content_settings = self._azure_blob_module.ContentSettings(\n                content_md5=md5,\n                content_type=extra_headers.get("Content-Type"),\n            )\n            client.upload_blob(\n                file,\n                max_concurrency=4,\n                length=len(file),\n                overwrite=True,\n                content_settings=content_settings,\n            )\n        except AzureError as e:\n            if hasattr(e, "response"):\n                response = requests.models.Response()\n                response.status_code = e.response.status_code\n                response.headers = e.response.headers\n                raise requests.exceptions.RequestException(e.message, response=response)\n            else:\n                raise requests.exceptions.ConnectionError(e.message)\n\n    def upload_multipart_file_chunk(\n        self,\n        url: str,\n        upload_chunk: bytes,\n        extra_headers: dict[str, str] | None = None,\n    ) -> requests.Response | None:\n        """Upload a file chunk to S3 with failure resumption.\n\n        Args:\n            url: The url to download\n            upload_chunk: The path to the file you want to upload\n            extra_headers: A dictionary of extra headers to send with the request\n\n        Returns:\n            The `requests` library response object\n        """\n        import requests\n\n        check_httpclient_logger_handler()\n        try:\n            if env.is_debug(env=self._environ):\n                logger.debug("upload_file: %s", url)\n            response = self._upload_file_session.put(\n                url, data=upload_chunk, headers=extra_headers\n            )\n            if env.is_debug(env=self._environ):\n                logger.debug("upload_file: %s complete", url)\n            response.raise_for_status()\n        except requests.exceptions.RequestException as e:\n            logger.exception(f"upload_file exception for {url=}")\n            response_content = e.response.content if e.response is not None else ""\n            status_code = e.response.status_code if e.response is not None else 0\n            # S3 reports retryable request timeouts out-of-band\n            is_aws_retryable = status_code == 400 and "RequestTimeout" in str(\n                response_content\n            )\n            # Retry errors from cloud storage or local network issues\n            if (\n                status_code in (308, 408, 409, 429, 500, 502, 503, 504)\n                or isinstance(\n                    e,\n                    (requests.exceptions.Timeout, requests.exceptions.ConnectionError),\n                )\n                or is_aws_retryable\n            ):\n                _e = retry.TransientError(exc=e)\n                raise _e.with_traceback(sys.exc_info()[2])\n            else:\n                get_sentry().reraise(e)\n        return response\n\n    def upload_file(\n        self,\n        url: str,\n        file: IO[bytes],\n        callback: ProgressFn | None = None,\n        extra_headers: dict[str, str] | None = None,\n    ) -> requests.Response | None:\n        """Upload a file to W&B with failure resumption.\n\n        Args:\n            url: The url to download\n            file: The path to the file you want to upload\n            callback: A callback which is passed the number of\n            bytes uploaded since the last time it was called, used to report progress\n            extra_headers: A dictionary of extra headers to send with the request\n\n        Returns:\n            The `requests` library response object\n        """\n        import requests\n\n        check_httpclient_logger_handler()\n        extra_headers = extra_headers.copy() if extra_headers else {}\n        response: requests.Response | None = None\n        progress = Progress(file, callback=callback)\n        try:\n            if "x-ms-blob-type" in extra_headers and self._azure_blob_module:\n                self.upload_file_azure(url, progress, extra_headers)\n            else:\n                if "x-ms-blob-type" in extra_headers:\n                    wandb.termwarn(\n                        "Azure uploads over 256MB require the azure SDK, install with pip install wandb[azure]",\n                        repeat=False,\n                    )\n                if env.is_debug(env=self._environ):\n                    logger.debug("upload_file: %s", url)\n                response = self._upload_file_session.put(\n                    url, data=progress, headers=extra_headers\n                )\n                if env.is_debug(env=self._environ):\n                    logger.debug("upload_file: %s complete", url)\n                response.raise_for_status()\n        except requests.exceptions.RequestException as e:\n            logger.exception(f"upload_file exception for {url=}")\n            response_content = e.response.content if e.response is not None else ""\n            status_code = e.response.status_code if e.response is not None else 0\n            # S3 reports retryable request timeouts out-of-band\n            is_aws_retryable = (\n                "x-amz-meta-md5" in extra_headers\n                and status_code == 400\n                and "RequestTimeout" in str(response_content)\n            )\n            # We need to rewind the file for the next retry (the file passed in is `seek`\'ed to 0)\n            progress.rewind()\n            # Retry errors from cloud storage or local network issues\n            if (\n                status_code in (308, 408, 409, 429, 500, 502, 503, 504)\n                or isinstance(\n                    e,\n                    (requests.exceptions.Timeout, requests.exceptions.ConnectionError),\n                )\n                or is_aws_retryable\n            ):\n                _e = retry.TransientError(exc=e)\n                raise _e.with_traceback(sys.exc_info()[2])\n            else:\n                get_sentry().reraise(e)\n\n        return response\n\n    @normalize_exceptions\n    def register_agent(\n        self,\n        host: str,\n        sweep_id: str | None = None,\n        project_name: str | None = None,\n        entity: str | None = None,\n    ) -> dict:\n        """Register a new agent.\n\n        Args:\n            host (str): hostname\n            sweep_id (str): sweep id\n            project_name: (str): model that contains sweep\n            entity: (str): entity that contains sweep\n        """\n        mutation = gql(\n            """\n        mutation CreateAgent(\n            $host: String!\n            $projectName: String,\n            $entityName: String,\n            $sweep: String!\n        ) {\n            createAgent(input: {\n                host: $host,\n                projectName: $projectName,\n                entityName: $entityName,\n                sweep: $sweep,\n            }) {\n                agent {\n                    id\n                }\n            }\n        }\n        """\n        )\n        if entity is None:\n            entity = self.settings("entity")\n        if project_name is None:\n            project_name = self.settings("project")\n\n        response = self.gql(\n            mutation,\n            variable_values={\n                "host": host,\n                "entityName": entity,\n                "projectName": project_name,\n                "sweep": sweep_id,\n            },\n            check_retry_fn=util.no_retry_4xx,\n        )\n        result: dict = response["createAgent"]["agent"]\n        return result\n\n    def agent_heartbeat(\n        self, agent_id: str, metrics: dict, run_states: dict\n    ) -> list[dict[str, Any]]:\n        """Notify server about agent state, receive commands.\n\n        Args:\n            agent_id (str): agent_id\n            metrics (dict): system metrics\n            run_states (dict): run_id: state mapping\n        Returns:\n            list of commands to execute.\n        """\n        mutation = gql(\n            """\n        mutation Heartbeat(\n            $id: ID!,\n            $metrics: JSONString,\n            $runState: JSONString\n        ) {\n            agentHeartbeat(input: {\n                id: $id,\n                metrics: $metrics,\n                runState: $runState\n            }) {\n                agent {\n                    id\n                }\n                commands\n            }\n        }\n        """\n        )\n\n        if agent_id is None:\n            raise ValueError("Cannot call heartbeat with an unregistered agent.")\n\n        try:\n            response = self.gql(\n                mutation,\n                variable_values={\n                    "id": agent_id,\n                    "metrics": json.dumps(metrics),\n                    "runState": json.dumps(run_states),\n                },\n                timeout=60,\n            )\n        except Exception:\n            logger.exception("Error communicating with W&B.")\n            return []\n        else:\n            result: list[dict[str, Any]] = json.loads(\n                response["agentHeartbeat"]["commands"]\n            )\n            return result\n\n    @staticmethod\n    def _validate_config_and_fill_distribution(config: dict) -> dict:\n        # verify that parameters are well specified.\n        # TODO(dag): deprecate this in favor of jsonschema validation once\n        # apiVersion 2 is released and local controller is integrated with\n        # wandb/client.\n\n        # avoid modifying the original config dict in\n        # case it is reused outside the calling func\n        config = deepcopy(config)\n\n        # explicitly cast to dict in case config was passed as a sweepconfig\n        # sweepconfig does not serialize cleanly to yaml and breaks graphql,\n        # but it is a subclass of dict, so this conversion is clean\n        config = dict(config)\n\n        if "parameters" not in config:\n            # still shows an anaconda warning, but doesn\'t error\n            return config\n\n        for parameter_name in config["parameters"]:\n            parameter = config["parameters"][parameter_name]\n            if "min" in parameter and "max" in parameter:\n                if "distribution" not in parameter:\n                    if isinstance(parameter["min"], int) and isinstance(\n                        parameter["max"], int\n                    ):\n                        parameter["distribution"] = "int_uniform"\n                    elif isinstance(parameter["min"], float) and isinstance(\n                        parameter["max"], float\n                    ):\n                        parameter["distribution"] = "uniform"\n                    else:\n                        raise ValueError(\n                            f"Parameter {parameter_name} is ambiguous, please specify bounds as both floats (for a float_"\n                            "uniform distribution) or ints (for an int_uniform distribution)."\n                        )\n        return config\n\n    @normalize_exceptions\n    def upsert_sweep(\n        self,\n        config: dict,\n        controller: str | None = None,\n        launch_scheduler: str | None = None,\n        scheduler: str | None = None,\n        obj_id: str | None = None,\n        project: str | None = None,\n        entity: str | None = None,\n        state: str | None = None,\n        prior_runs: list[str] | None = None,\n        display_name: str | None = None,\n        template_variable_values: dict[str, Any] | None = None,\n    ) -> tuple[str, list[str]]:\n        """Upsert a sweep object.\n\n        Args:\n            config (dict): sweep config (will be converted to yaml)\n            controller (str): controller to use\n            launch_scheduler (str): launch scheduler to use\n            scheduler (str): scheduler to use\n            obj_id (str): object id\n            project (str): project to use\n            entity (str): entity to use\n            state (str): state\n            prior_runs (list): IDs of existing runs to add to the sweep\n            display_name (str): display name for the sweep\n            template_variable_values (dict): template variable values\n        """\n        import yaml\n\n        project_query = """\n            project {\n                id\n                name\n                entity {\n                    id\n                    name\n                }\n            }\n        """\n        mutation_str = """\n        mutation UpsertSweep(\n            $id: ID,\n            $config: String,\n            $description: String,\n            $entityName: String,\n            $projectName: String,\n            $controller: JSONString,\n            $scheduler: JSONString,\n            $state: String,\n            $priorRunsFilters: JSONString,\n            $displayName: String,\n        ) {\n            upsertSweep(input: {\n                id: $id,\n                config: $config,\n                description: $description,\n                entityName: $entityName,\n                projectName: $projectName,\n                controller: $controller,\n                scheduler: $scheduler,\n                state: $state,\n                priorRunsFilters: $priorRunsFilters,\n                displayName: $displayName,\n            }) {\n                sweep {\n                    name\n                    _PROJECT_QUERY_\n                }\n                configValidationWarnings\n            }\n        }\n        """\n        # TODO(jhr): we need protocol versioning to know schema is not supported\n        # for now we will just try both new and old query\n        mutation_5 = gql(\n            mutation_str.replace(\n                "$controller: JSONString,",\n                "$controller: JSONString,$launchScheduler: JSONString, $templateVariableValues: JSONString,",\n            )\n            .replace(\n                "controller: $controller,",\n                "controller: $controller,launchScheduler: $launchScheduler,templateVariableValues: $templateVariableValues,",\n            )\n            .replace("_PROJECT_QUERY_", project_query)\n        )\n        # launchScheduler was introduced in core v0.14.0\n        mutation_4 = gql(\n            mutation_str.replace(\n                "$controller: JSONString,",\n                "$controller: JSONString,$launchScheduler: JSONString,",\n            )\n            .replace(\n                "controller: $controller,",\n                "controller: $controller,launchScheduler: $launchScheduler",\n            )\n            .replace("_PROJECT_QUERY_", project_query)\n        )\n\n        # mutation 3 maps to backend that can support CLI version of at least 0.10.31\n        mutation_3 = gql(mutation_str.replace("_PROJECT_QUERY_", project_query))\n        mutation_2 = gql(\n            mutation_str.replace("_PROJECT_QUERY_", project_query).replace(\n                "configValidationWarnings", ""\n            )\n        )\n        mutation_1 = gql(\n            mutation_str.replace("_PROJECT_QUERY_", "").replace(\n                "configValidationWarnings", ""\n            )\n        )\n\n        # TODO(dag): replace this with a query for protocol versioning\n        mutations = [mutation_5, mutation_4, mutation_3, mutation_2, mutation_1]\n\n        config = self._validate_config_and_fill_distribution(config)\n\n        # Silly, but attr-dicts like Easydicts don\'t serialize correctly to yaml.\n        # This sanitizes them with a round trip pass through json to get a regular dict.\n        class NonOctalStringDumper(yaml.Dumper):\n            """Prevents strings containing non-octal values like "008" and "009" from being converted to numbers in in the yaml string saved as the sweep config."""\n\n            def represent_scalar(self, tag, value, style=None):\n                if (\n                    tag == "tag:yaml.org,2002:str"\n                    and value.startswith("0")\n                    and len(value) > 1\n                ):\n                    return super().represent_scalar(tag, value, style="\'")\n                return super().represent_scalar(tag, value, style)\n\n        config_str = yaml.dump(\n            json.loads(json.dumps(config)), Dumper=NonOctalStringDumper\n        )\n        filters = None\n        if prior_runs:\n            filters = json.dumps({"$or": [{"name": r} for r in prior_runs]})\n\n        err: Exception | None = None\n        for mutation in mutations:\n            try:\n                variables = {\n                    "id": obj_id,\n                    "config": config_str,\n                    "description": config.get("description"),\n                    "entityName": entity or self.settings("entity"),\n                    "projectName": project or self.settings("project"),\n                    "controller": controller,\n                    "launchScheduler": launch_scheduler,\n                    "templateVariableValues": json.dumps(template_variable_values),\n                    "scheduler": scheduler,\n                    "priorRunsFilters": filters,\n                    "displayName": display_name,\n                }\n                if state:\n                    variables["state"] = state\n\n                response = self.gql(\n                    mutation,\n                    variable_values=variables,\n                    check_retry_fn=util.no_retry_4xx,\n                )\n            except UsageError:\n                raise\n            except Exception as e:\n                # graphql schema exception is generic\n                err = e\n                continue\n            err = None\n            break\n        if err:\n            raise err\n\n        sweep: dict[str, dict[str, dict]] = response["upsertSweep"]["sweep"]\n        project_obj: dict[str, dict] = sweep.get("project", {})\n        if project_obj:\n            self.set_setting("project", project_obj["name"])\n            entity_obj: dict = project_obj.get("entity", {})\n            if entity_obj:\n                self.set_setting("entity", entity_obj["name"])\n\n        warnings = response["upsertSweep"].get("configValidationWarnings", [])\n        return response["upsertSweep"]["sweep"]["name"], warnings\n\n    @staticmethod\n    def file_current(fname: str, md5: B64MD5) -> bool:\n        """Checksum a file and compare the md5 with the known md5."""\n        return os.path.isfile(fname) and md5_file_b64(fname) == md5\n\n    @normalize_exceptions\n    def pull(\n        self, project: str, run: str | None = None, entity: str | None = None\n    ) -> list[requests.Response]:\n        """Download files from W&B.\n\n        Args:\n            project (str): The project to download\n            run (str, optional): The run to upload to\n            entity (str, optional): The entity to scope this project to.  Defaults to wandb models\n\n        Returns:\n            The `requests` library response object\n        """\n        project, run = self.parse_slug(project, run=run)\n        urls = self.download_urls(project, run, entity)\n        responses = []\n        for filename in urls:\n            _, response = self.download_write_file(urls[filename])\n            if response:\n                responses.append(response)\n\n        return responses\n\n    def get_project(self) -> str:\n        project: str = self.default_settings.get("project") or self.settings("project")\n        return project\n\n    @normalize_exceptions\n    def push(\n        self,\n        files: list[str] | dict[str, IO],\n        run: str | None = None,\n        entity: str | None = None,\n        project: str | None = None,\n        description: str | None = None,\n        force: bool = True,\n        progress: TextIO | Literal[False] = False,\n    ) -> list[requests.Response | None]:\n        """Uploads multiple files to W&B.\n\n        Args:\n            files (list or dict): The filenames to upload, when dict the values are open files\n            run (str, optional): The run to upload to\n            entity (str, optional): The entity to scope this project to.  Defaults to wandb models\n            project (str, optional): The name of the project to upload to. Defaults to the one in settings.\n            description (str, optional): The description of the changes\n            force (bool, optional): Whether to prevent push if git has uncommitted changes\n            progress (callable, or stream): If callable, will be called with (chunk_bytes,\n                total_bytes) as argument. If TextIO, renders a progress bar to it.\n\n        Returns:\n            A list of `requests.Response` objects\n        """\n        if project is None:\n            project = self.get_project()\n        if project is None:\n            raise CommError("No project configured.")\n        if run is None:\n            run = self.current_run_id\n\n        # TODO(adrian): we use a retriable version of self.upload_file() so\n        # will never retry self.upload_urls() here. Instead, maybe we should\n        # make push itself retriable.\n        _, upload_headers, result = self.upload_urls(\n            project,\n            files,\n            run,\n            entity,\n        )\n        extra_headers = {}\n        for upload_header in upload_headers:\n            key, val = upload_header.split(":", 1)\n            extra_headers[key] = val\n        responses = []\n        for file_name, file_info in result.items():\n            file_url = file_info["uploadUrl"]\n\n            # If the upload URL is relative, fill it in with the base URL,\n            # since it\'s a proxied file store like the on-prem VM.\n            if file_url.startswith("/"):\n                file_url = f"{self.api_url}{file_url}"\n\n            try:\n                # To handle Windows paths\n                # TODO: this doesn\'t handle absolute paths...\n                normal_name = os.path.join(*file_name.split("/"))\n                open_file = (\n                    files[file_name]\n                    if isinstance(files, dict)\n                    else open(normal_name, "rb")\n                )\n            except OSError:\n                print(f"{file_name} does not exist")  # noqa: T201\n                continue\n            if progress is False:\n                responses.append(\n                    self.upload_file_retry(\n                        file_info["uploadUrl"], open_file, extra_headers=extra_headers\n                    )\n                )\n            else:\n                if callable(progress):\n                    responses.append(  # type: ignore\n                        self.upload_file_retry(\n                            file_url, open_file, progress, extra_headers=extra_headers\n                        )\n                    )\n                else:\n                    length = os.fstat(open_file.fileno()).st_size\n                    with click.progressbar(  # type: ignore\n                        file=progress,\n                        length=length,\n                        label=f"Uploading file: {file_name}",\n                        fill_char=click.style("&", fg="green"),\n                    ) as bar:\n                        responses.append(\n                            self.upload_file_retry(\n                                file_url,\n                                open_file,\n                                lambda bites, _: bar.update(bites),\n                                extra_headers=extra_headers,\n                            )\n                        )\n            open_file.close()\n        return responses\n\n    def link_artifact(\n        self,\n        client_id: str,\n        server_id: str,\n        portfolio_name: str,\n        entity: str,\n        project: str,\n        aliases: Sequence[str],\n        organization: str,\n    ) -> dict[str, Any]:\n        from wandb.sdk.artifacts._validators import is_artifact_registry_project\n\n        template = """\n                mutation LinkArtifact(\n                    $artifactPortfolioName: String!,\n                    $entityName: String!,\n                    $projectName: String!,\n                    $aliases: [ArtifactAliasInput!],\n                    ID_TYPE\n                    ) {\n                        linkArtifact(input: {\n                            artifactPortfolioName: $artifactPortfolioName,\n                            entityName: $entityName,\n                            projectName: $projectName,\n                            aliases: $aliases,\n                            ID_VALUE\n                        }) {\n                            versionIndex\n                        }\n                    }\n            """\n\n        org_entity = ""\n        if is_artifact_registry_project(project):\n            try:\n                org_entity = self._resolve_org_entity_name(\n                    entity=entity, organization=organization\n                )\n            except ValueError as e:\n                wandb.termerror(str(e))\n                raise\n\n        def replace(a: str, b: str) -> None:\n            nonlocal template\n            template = template.replace(a, b)\n\n        if server_id:\n            replace("ID_TYPE", "$artifactID: ID")\n            replace("ID_VALUE", "artifactID: $artifactID")\n        elif client_id:\n            replace("ID_TYPE", "$clientID: ID")\n            replace("ID_VALUE", "clientID: $clientID")\n\n        variable_values = {\n            "clientID": client_id,\n            "artifactID": server_id,\n            "artifactPortfolioName": portfolio_name,\n            "entityName": org_entity or entity,\n            "projectName": project,\n            "aliases": [\n                {"alias": alias, "artifactCollectionName": portfolio_name}\n                for alias in aliases\n            ],\n        }\n\n        mutation = gql(template)\n        response = self.gql(mutation, variable_values=variable_values)\n        link_artifact: dict[str, Any] = response["linkArtifact"]\n        return link_artifact\n\n    def _resolve_org_entity_name(self, entity: str, organization: str = "") -> str:\n        # resolveOrgEntityName fetches the portfolio\'s org entity\'s name.\n        #\n        # The organization parameter may be empty, an org\'s display name, or an org entity name.\n        #\n        # If the server doesn\'t support fetching the org name of a portfolio, then this returns\n        # the organization parameter, or an error if it is empty. Otherwise, this returns the\n        # fetched value after validating that the given organization, if not empty, matches\n        # either the org\'s display or entity name.\n\n        if not entity:\n            raise ValueError("Entity name is required to resolve org entity name.")\n\n        org_fields = self.server_organization_type_introspection()\n        can_shorthand_org_entity = "orgEntity" in org_fields\n        if not organization and not can_shorthand_org_entity:\n            raise ValueError(\n                "Fetching Registry artifacts without inputting an organization "\n                "is unavailable for your server version. "\n                "Please upgrade your server to 0.50.0 or later."\n            )\n        if not can_shorthand_org_entity:\n            # Server doesn\'t support fetching org entity to validate,\n            # assume org entity is correctly inputted\n            return organization\n\n        orgs_from_entity = self._fetch_orgs_and_org_entities_from_entity(entity)\n        if organization:\n            return _match_org_with_fetched_org_entities(organization, orgs_from_entity)\n\n        # If no input organization provided, error if entity belongs to multiple orgs because we\n        # cannot determine which one to use.\n        if len(orgs_from_entity) > 1:\n            raise ValueError(\n                f"Personal entity {entity!r} belongs to multiple organizations "\n                "and cannot be used without specifying the organization name. "\n                "Please specify the organization in the Registry path or use a team entity in the entity settings."\n            )\n        return orgs_from_entity[0].entity_name\n\n    def _fetch_orgs_and_org_entities_from_entity(self, entity: str) -> list[_OrgNames]:\n        """Fetches organization entity names and display names for a given entity.\n\n        Args:\n            entity (str): Entity name to lookup. Can be either a personal or team entity.\n\n        Returns:\n            list[_OrgNames]: list of _OrgNames tuples. (_OrgNames(entity_name, display_name))\n\n        Raises:\n        ValueError: If entity is not found, has no organizations, or other validation errors.\n        """\n        query = gql(\n            """\n            query FetchOrgEntityFromEntity($entityName: String!) {\n                entity(name: $entityName) {\n                    organization {\n                        name\n                        orgEntity {\n                            name\n                        }\n                    }\n                    user {\n                        organizations {\n                            name\n                            orgEntity {\n                                name\n                            }\n                        }\n                    }\n                }\n            }\n            """\n        )\n        response = self.gql(\n            query,\n            variable_values={\n                "entityName": entity,\n            },\n        )\n\n        # Parse organization from response\n        entity_resp = response["entity"]["organization"]\n        user_resp = response["entity"]["user"]\n        # Check for organization under team/org entity type\n        if entity_resp:\n            org_name = entity_resp.get("name")\n            org_entity_name = entity_resp.get("orgEntity") and entity_resp[\n                "orgEntity"\n            ].get("name")\n            if not org_name or not org_entity_name:\n                raise ValueError(\n                    f"Unable to find an organization under entity {entity!r}."\n                )\n            return [_OrgNames(entity_name=org_entity_name, display_name=org_name)]\n        # Check for organization under personal entity type, where a user can belong to multiple orgs\n        elif user_resp:\n            orgs = user_resp.get("organizations", [])\n            org_entities_return = [\n                _OrgNames(\n                    entity_name=org["orgEntity"]["name"], display_name=org["name"]\n                )\n                for org in orgs\n                if org.get("orgEntity") and org.get("name")\n            ]\n            if not org_entities_return:\n                raise ValueError(\n                    f"Unable to resolve an organization associated with personal entity: {entity!r}. "\n                    "This could be because its a personal entity that doesn\'t belong to any organizations. "\n                    "Please specify the organization in the Registry path or use a team entity in the entity settings."\n                )\n            return org_entities_return\n        else:\n            raise ValueError(f"Unable to find an organization under entity {entity!r}.")\n\n    def _construct_use_artifact_query(\n        self,\n        artifact_id: str,\n        entity_name: str | None = None,\n        project_name: str | None = None,\n        run_name: str | None = None,\n        use_as: str | None = None,\n        artifact_entity_name: str | None = None,\n        artifact_project_name: str | None = None,\n    ) -> tuple[Document, dict[str, Any]]:\n        query_vars = [\n            "$entityName: String!",\n            "$projectName: String!",\n            "$runName: String!",\n            "$artifactID: ID!",\n        ]\n        query_args = [\n            "entityName: $entityName",\n            "projectName: $projectName",\n            "runName: $runName",\n            "artifactID: $artifactID",\n        ]\n\n        artifact_types = self.server_use_artifact_input_introspection()\n        if "usedAs" in artifact_types and use_as:\n            query_vars.append("$usedAs: String")\n            query_args.append("usedAs: $usedAs")\n\n        entity_name = entity_name or self.settings("entity")\n        project_name = project_name or self.settings("project")\n        run_name = run_name or self.current_run_id\n\n        variable_values: dict[str, Any] = {\n            "entityName": entity_name,\n            "projectName": project_name,\n            "runName": run_name,\n            "artifactID": artifact_id,\n            "usedAs": use_as,\n        }\n\n        server_allows_entity_project_information = self._server_supports(\n            ServerFeature.USE_ARTIFACT_WITH_ENTITY_AND_PROJECT_INFORMATION\n        )\n        if server_allows_entity_project_information:\n            query_vars.extend(\n                [\n                    "$artifactEntityName: String",\n                    "$artifactProjectName: String",\n                ]\n            )\n            query_args.extend(\n                [\n                    "artifactEntityName: $artifactEntityName",\n                    "artifactProjectName: $artifactProjectName",\n                ]\n            )\n            variable_values["artifactEntityName"] = artifact_entity_name\n            variable_values["artifactProjectName"] = artifact_project_name\n\n        vars_str = ", ".join(query_vars)\n        args_str = ", ".join(query_args)\n\n        query = gql(\n            f"""\n            mutation UseArtifact({vars_str}) {{\n                useArtifact(input: {{{args_str}}}) {{\n                    artifact {{\n                        id\n                        digest\n                        description\n                        state\n                        createdAt\n                        metadata\n                    }}\n                }}\n            }}\n            """\n        )\n        return query, variable_values\n\n    def use_artifact(\n        self,\n        artifact_id: str,\n        entity_name: str | None = None,\n        project_name: str | None = None,\n        run_name: str | None = None,\n        artifact_entity_name: str | None = None,\n        artifact_project_name: str | None = None,\n        use_as: str | None = None,\n    ) -> dict[str, Any] | None:\n        query, variable_values = self._construct_use_artifact_query(\n            artifact_id,\n            entity_name,\n            project_name,\n            run_name,\n            use_as,\n            artifact_entity_name,\n            artifact_project_name,\n        )\n        response = self.gql(query, variable_values)\n\n        if response["useArtifact"]["artifact"]:\n            artifact: dict[str, Any] = response["useArtifact"]["artifact"]\n            return artifact\n        return None\n\n    # Fetch fields available in backend of Organization type\n    def server_organization_type_introspection(self) -> list[str]:\n        query_string = """\n            query ProbeServerOrganization {\n                OrganizationInfoType: __type(name:"Organization") {\n                    fields {\n                        name\n                    }\n                }\n            }\n        """\n\n        if self.server_organization_type_fields_info is None:\n            query = gql(query_string)\n            res = self.gql(query)\n            input_fields = res.get("OrganizationInfoType", {}).get("fields", [{}])\n            self.server_organization_type_fields_info = [\n                field["name"] for field in input_fields if "name" in field\n            ]\n\n        return self.server_organization_type_fields_info\n\n    # Fetch input arguments for the "artifact" endpoint on the "Project" type\n    def server_project_type_introspection(self) -> bool:\n        if self.server_supports_enabling_artifact_usage_tracking is not None:\n            return self.server_supports_enabling_artifact_usage_tracking\n\n        query_string = """\n            query ProbeServerProjectInfo {\n                ProjectInfoType: __type(name:"Project") {\n                    fields {\n                        name\n                        args {\n                            name\n                        }\n                    }\n                }\n            }\n        """\n\n        query = gql(query_string)\n        res = self.gql(query)\n        input_fields = res.get("ProjectInfoType", {}).get("fields", [{}])\n        artifact_args: list[dict[str, str]] = next(\n            (\n                field.get("args", [])\n                for field in input_fields\n                if field.get("name") == "artifact"\n            ),\n            [],\n        )\n        self.server_supports_enabling_artifact_usage_tracking = any(\n            arg.get("name") == "enableTracking" for arg in artifact_args\n        )\n\n        return self.server_supports_enabling_artifact_usage_tracking\n\n    def create_artifact_type(\n        self,\n        artifact_type_name: str,\n        entity_name: str | None = None,\n        project_name: str | None = None,\n        description: str | None = None,\n    ) -> str | None:\n        mutation = gql(\n            """\n        mutation CreateArtifactType(\n            $entityName: String!,\n            $projectName: String!,\n            $artifactTypeName: String!,\n            $description: String\n        ) {\n            createArtifactType(input: {\n                entityName: $entityName,\n                projectName: $projectName,\n                name: $artifactTypeName,\n                description: $description\n            }) {\n                artifactType {\n                    id\n                }\n            }\n        }\n        """\n        )\n        entity_name = entity_name or self.settings("entity")\n        project_name = project_name or self.settings("project")\n        response = self.gql(\n            mutation,\n            variable_values={\n                "entityName": entity_name,\n                "projectName": project_name,\n                "artifactTypeName": artifact_type_name,\n                "description": description,\n            },\n        )\n        _id: str | None = response["createArtifactType"]["artifactType"]["id"]\n        return _id\n\n    def server_artifact_introspection(self) -> list[str]:\n        query_string = """\n            query ProbeServerArtifact {\n                ArtifactInfoType: __type(name:"Artifact") {\n                    fields {\n                        name\n                    }\n                }\n            }\n        """\n\n        if self.server_artifact_fields_info is None:\n            query = gql(query_string)\n            res = self.gql(query)\n            input_fields = res.get("ArtifactInfoType", {}).get("fields", [{}])\n            self.server_artifact_fields_info = [\n                field["name"] for field in input_fields if "name" in field\n            ]\n\n        return self.server_artifact_fields_info\n\n    def server_create_artifact_introspection(self) -> list[str]:\n        query_string = """\n            query ProbeServerCreateArtifactInput {\n                CreateArtifactInputInfoType: __type(name:"CreateArtifactInput") {\n                    inputFields{\n                        name\n                    }\n                }\n            }\n        """\n\n        if self.server_create_artifact_input_info is None:\n            query = gql(query_string)\n            res = self.gql(query)\n            input_fields = res.get("CreateArtifactInputInfoType", {}).get(\n                "inputFields", [{}]\n            )\n            self.server_create_artifact_input_info = [\n                field["name"] for field in input_fields if "name" in field\n            ]\n\n        return self.server_create_artifact_input_info\n\n    def _get_create_artifact_mutation(\n        self,\n        fields: list,\n        history_step: int | None,\n        distributed_id: str | None,\n    ) -> str:\n        types = ""\n        values = ""\n\n        if "historyStep" in fields and history_step not in [0, None]:\n            types += "$historyStep: Int64!,"\n            values += "historyStep: $historyStep,"\n\n        if distributed_id:\n            types += "$distributedID: String,"\n            values += "distributedID: $distributedID,"\n\n        if "clientID" in fields:\n            types += "$clientID: ID,"\n            values += "clientID: $clientID,"\n\n        if "sequenceClientID" in fields:\n            types += "$sequenceClientID: ID,"\n            values += "sequenceClientID: $sequenceClientID,"\n\n        if "enableDigestDeduplication" in fields:\n            values += "enableDigestDeduplication: true,"\n\n        if "ttlDurationSeconds" in fields:\n            types += "$ttlDurationSeconds: Int64,"\n            values += "ttlDurationSeconds: $ttlDurationSeconds,"\n\n        if "tags" in fields:\n            types += "$tags: [TagInput!],"\n            values += "tags: $tags,"\n\n        query_template = """\n            mutation CreateArtifact(\n                $artifactTypeName: String!,\n                $artifactCollectionNames: [String!],\n                $entityName: String!,\n                $projectName: String!,\n                $runName: String,\n                $description: String,\n                $digest: String!,\n                $aliases: [ArtifactAliasInput!],\n                $metadata: JSONString,\n                _CREATE_ARTIFACT_ADDITIONAL_TYPE_\n            ) {\n                createArtifact(input: {\n                    artifactTypeName: $artifactTypeName,\n                    artifactCollectionNames: $artifactCollectionNames,\n                    entityName: $entityName,\n                    projectName: $projectName,\n                    runName: $runName,\n                    description: $description,\n                    digest: $digest,\n                    digestAlgorithm: MANIFEST_MD5,\n                    aliases: $aliases,\n                    metadata: $metadata,\n                    _CREATE_ARTIFACT_ADDITIONAL_VALUE_\n                }) {\n                    artifact {\n                        id\n                        state\n                        artifactSequence {\n                            id\n                            latestArtifact {\n                                id\n                                versionIndex\n                            }\n                        }\n                    }\n                }\n            }\n        """\n\n        return query_template.replace(\n            "_CREATE_ARTIFACT_ADDITIONAL_TYPE_", types\n        ).replace("_CREATE_ARTIFACT_ADDITIONAL_VALUE_", values)\n\n    def create_artifact(\n        self,\n        artifact_type_name: str,\n        artifact_collection_name: str,\n        digest: str,\n        client_id: str | None = None,\n        sequence_client_id: str | None = None,\n        entity_name: str | None = None,\n        project_name: str | None = None,\n        run_name: str | None = None,\n        description: str | None = None,\n        metadata: dict | None = None,\n        ttl_duration_seconds: int | None = None,\n        aliases: list[dict[str, str]] | None = None,\n        tags: list[dict[str, str]] | None = None,\n        distributed_id: str | None = None,\n        is_user_created: bool | None = False,\n        history_step: int | None = None,\n    ) -> tuple[dict, dict]:\n        fields = self.server_create_artifact_introspection()\n        artifact_fields = self.server_artifact_introspection()\n        if ("ttlIsInherited" not in artifact_fields) and ttl_duration_seconds:\n            wandb.termwarn(\n                "Server not compatible with setting Artifact TTLs, please upgrade the server to use Artifact TTL"\n            )\n            # ttlDurationSeconds is only usable if ttlIsInherited is also present\n            ttl_duration_seconds = None\n        if ("tags" not in artifact_fields) and tags:\n            wandb.termwarn(\n                "Server not compatible with Artifact tags. "\n                "To use Artifact tags, please upgrade the server to v0.85 or higher."\n            )\n\n        query_template = self._get_create_artifact_mutation(\n            fields, history_step, distributed_id\n        )\n\n        entity_name = entity_name or self.settings("entity")\n        project_name = project_name or self.settings("project")\n        if not is_user_created:\n            run_name = run_name or self.current_run_id\n\n        mutation = gql(query_template)\n        response = self.gql(\n            mutation,\n            variable_values={\n                "entityName": entity_name,\n                "projectName": project_name,\n                "runName": run_name,\n                "artifactTypeName": artifact_type_name,\n                "artifactCollectionNames": [artifact_collection_name],\n                "clientID": client_id,\n                "sequenceClientID": sequence_client_id,\n                "digest": digest,\n                "description": description,\n                "aliases": list(aliases or []),\n                "tags": list(tags or []),\n                "metadata": json.dumps(util.make_safe_for_json(metadata))\n                if metadata\n                else None,\n                "ttlDurationSeconds": ttl_duration_seconds,\n                "distributedID": distributed_id,\n                "historyStep": history_step,\n            },\n        )\n        av = response["createArtifact"]["artifact"]\n        latest = response["createArtifact"]["artifact"]["artifactSequence"].get(\n            "latestArtifact"\n        )\n        return av, latest\n\n    def commit_artifact(self, artifact_id: str) -> _Response:\n        mutation = gql(\n            """\n        mutation CommitArtifact(\n            $artifactID: ID!,\n        ) {\n            commitArtifact(input: {\n                artifactID: $artifactID,\n            }) {\n                artifact {\n                    id\n                    digest\n                }\n            }\n        }\n        """\n        )\n\n        response: _Response = self.gql(\n            mutation,\n            variable_values={"artifactID": artifact_id},\n            timeout=60,\n        )\n        return response\n\n    def complete_multipart_upload_artifact(\n        self,\n        artifact_id: str,\n        storage_path: str,\n        completed_parts: list[dict[str, Any]],\n        upload_id: str | None,\n        complete_multipart_action: str = "Complete",\n    ) -> str | None:\n        mutation = gql(\n            """\n        mutation CompleteMultipartUploadArtifact(\n            $completeMultipartAction: CompleteMultipartAction!,\n            $completedParts: [UploadPartsInput!]!,\n            $artifactID: ID!\n            $storagePath: String!\n            $uploadID: String!\n        ) {\n        completeMultipartUploadArtifact(\n            input: {\n                completeMultipartAction: $completeMultipartAction,\n                completedParts: $completedParts,\n                artifactID: $artifactID,\n                storagePath: $storagePath\n                uploadID: $uploadID\n            }\n            ) {\n                digest\n            }\n        }\n        """\n        )\n        response = self.gql(\n            mutation,\n            variable_values={\n                "completeMultipartAction": complete_multipart_action,\n                "artifactID": artifact_id,\n                "storagePath": storage_path,\n                "completedParts": completed_parts,\n                "uploadID": upload_id,\n            },\n        )\n        digest: str | None = response["completeMultipartUploadArtifact"]["digest"]\n        return digest\n\n    def create_artifact_manifest(\n        self,\n        name: str,\n        digest: str,\n        artifact_id: str | None,\n        base_artifact_id: str | None = None,\n        entity: str | None = None,\n        project: str | None = None,\n        run: str | None = None,\n        include_upload: bool = True,\n        type: str = "FULL",\n    ) -> tuple[str, dict[str, Any]]:\n        mutation = gql(\n            """\n        mutation CreateArtifactManifest(\n            $name: String!,\n            $digest: String!,\n            $artifactID: ID!,\n            $baseArtifactID: ID,\n            $entityName: String!,\n            $projectName: String!,\n            $runName: String!,\n            $includeUpload: Boolean!,\n            {}\n        ) {{\n            createArtifactManifest(input: {{\n                name: $name,\n                digest: $digest,\n                artifactID: $artifactID,\n                baseArtifactID: $baseArtifactID,\n                entityName: $entityName,\n                projectName: $projectName,\n                runName: $runName,\n                {}\n            }}) {{\n                artifactManifest {{\n                    id\n                    file {{\n                        id\n                        name\n                        displayName\n                        uploadUrl @include(if: $includeUpload)\n                        uploadHeaders @include(if: $includeUpload)\n                    }}\n                }}\n            }}\n        }}\n        """.format(\n                "$type: ArtifactManifestType = FULL" if type != "FULL" else "",\n                "type: $type" if type != "FULL" else "",\n            )\n        )\n\n        entity_name = entity or self.settings("entity")\n        project_name = project or self.settings("project")\n        run_name = run or self.current_run_id\n\n        response = self.gql(\n            mutation,\n            variable_values={\n                "name": name,\n                "digest": digest,\n                "artifactID": artifact_id,\n                "baseArtifactID": base_artifact_id,\n                "entityName": entity_name,\n                "projectName": project_name,\n                "runName": run_name,\n                "includeUpload": include_upload,\n                "type": type,\n            },\n        )\n        return (\n            response["createArtifactManifest"]["artifactManifest"]["id"],\n            response["createArtifactManifest"]["artifactManifest"]["file"],\n        )\n\n    def update_artifact_manifest(\n        self,\n        artifact_manifest_id: str,\n        base_artifact_id: str | None = None,\n        digest: str | None = None,\n        include_upload: bool | None = True,\n    ) -> tuple[str, dict[str, Any]]:\n        mutation = gql(\n            """\n        mutation UpdateArtifactManifest(\n            $artifactManifestID: ID!,\n            $digest: String,\n            $baseArtifactID: ID,\n            $includeUpload: Boolean!,\n        ) {\n            updateArtifactManifest(input: {\n                artifactManifestID: $artifactManifestID,\n                digest: $digest,\n                baseArtifactID: $baseArtifactID,\n            }) {\n                artifactManifest {\n                    id\n                    file {\n                        id\n                        name\n                        displayName\n                        uploadUrl @include(if: $includeUpload)\n                        uploadHeaders @include(if: $includeUpload)\n                    }\n                }\n            }\n        }\n        """\n        )\n\n        response = self.gql(\n            mutation,\n            variable_values={\n                "artifactManifestID": artifact_manifest_id,\n                "digest": digest,\n                "baseArtifactID": base_artifact_id,\n                "includeUpload": include_upload,\n            },\n        )\n\n        return (\n            response["updateArtifactManifest"]["artifactManifest"]["id"],\n            response["updateArtifactManifest"]["artifactManifest"]["file"],\n        )\n\n    def update_artifact_metadata(\n        self, artifact_id: str, metadata: dict[str, Any]\n    ) -> dict[str, Any]:\n        """Set the metadata of the given artifact version."""\n        mutation = gql(\n            """\n        mutation UpdateArtifact(\n            $artifactID: ID!,\n            $metadata: JSONString,\n        ) {\n            updateArtifact(input: {\n                artifactID: $artifactID,\n                metadata: $metadata,\n            }) {\n                artifact {\n                    id\n                }\n            }\n        }\n        """\n        )\n        response = self.gql(\n            mutation,\n            variable_values={\n                "artifactID": artifact_id,\n                "metadata": json.dumps(metadata),\n            },\n        )\n        return response["updateArtifact"]["artifact"]\n\n    def _resolve_client_id(\n        self,\n        client_id: str,\n    ) -> str | None:\n        if client_id in self._client_id_mapping:\n            return self._client_id_mapping[client_id]\n\n        query = gql(\n            """\n            query ClientIDMapping($clientID: ID!) {\n                clientIDMapping(clientID: $clientID) {\n                    serverID\n                }\n            }\n        """\n        )\n        response = self.gql(\n            query,\n            variable_values={\n                "clientID": client_id,\n            },\n        )\n        server_id = None\n        if response is not None:\n            client_id_mapping = response.get("clientIDMapping")\n            if client_id_mapping is not None:\n                server_id = client_id_mapping.get("serverID")\n                if server_id is not None:\n                    self._client_id_mapping[client_id] = server_id\n        return server_id\n\n    def server_create_artifact_file_spec_input_introspection(self) -> list:\n        query_string = """\n           query ProbeServerCreateArtifactFileSpecInput {\n                CreateArtifactFileSpecInputInfoType: __type(name:"CreateArtifactFileSpecInput") {\n                    inputFields{\n                        name\n                    }\n                }\n            }\n        """\n\n        query = gql(query_string)\n        res = self.gql(query)\n        create_artifact_file_spec_input_info = [\n            field.get("name", "")\n            for field in res.get("CreateArtifactFileSpecInputInfoType", {}).get(\n                "inputFields", [{}]\n            )\n        ]\n        return create_artifact_file_spec_input_info\n\n    @normalize_exceptions\n    def create_artifact_files(\n        self, artifact_files: Iterable[CreateArtifactFileSpecInput]\n    ) -> Mapping[str, CreateArtifactFilesResponseFile]:\n        query_template = """\n        mutation CreateArtifactFiles(\n            $storageLayout: ArtifactStorageLayout!\n            $artifactFiles: [CreateArtifactFileSpecInput!]!\n        ) {\n            createArtifactFiles(input: {\n                artifactFiles: $artifactFiles,\n                storageLayout: $storageLayout,\n            }) {\n                files {\n                    edges {\n                        node {\n                            id\n                            name\n                            displayName\n                            uploadUrl\n                            uploadHeaders\n                            _MULTIPART_UPLOAD_FIELDS_\n                            artifact {\n                                id\n                            }\n                        }\n                    }\n                }\n            }\n        }\n        """\n        multipart_upload_url_query = """\n            storagePath\n            uploadMultipartUrls {\n                uploadID\n                uploadUrlParts {\n                    partNumber\n                    uploadUrl\n                }\n            }\n        """\n\n        # TODO: we should use constants here from interface/artifacts.py\n        # but probably don\'t want the dependency. We\'re going to remove\n        # this setting in a future release, so I\'m just hard-coding the strings.\n        storage_layout = "V2"\n        if env.get_use_v1_artifacts():\n            storage_layout = "V1"\n\n        create_artifact_file_spec_input_fields = (\n            self.server_create_artifact_file_spec_input_introspection()\n        )\n        if "uploadPartsInput" in create_artifact_file_spec_input_fields:\n            query_template = query_template.replace(\n                "_MULTIPART_UPLOAD_FIELDS_", multipart_upload_url_query\n            )\n        else:\n            query_template = query_template.replace("_MULTIPART_UPLOAD_FIELDS_", "")\n\n        mutation = gql(query_template)\n        response = self.gql(\n            mutation,\n            variable_values={\n                "storageLayout": storage_layout,\n                "artifactFiles": [af for af in artifact_files],\n            },\n        )\n\n        result = {}\n        for edge in response["createArtifactFiles"]["files"]["edges"]:\n            node = edge["node"]\n            result[node["displayName"]] = node\n        return result\n\n    @normalize_exceptions\n    def notify_scriptable_run_alert(\n        self,\n        title: str,\n        text: str,\n        level: str | None = None,\n        wait_duration: Number | None = None,\n    ) -> bool:\n        mutation = gql(\n            """\n        mutation NotifyScriptableRunAlert(\n            $entityName: String!,\n            $projectName: String!,\n            $runName: String!,\n            $title: String!,\n            $text: String!,\n            $severity: AlertSeverity = INFO,\n            $waitDuration: Duration\n        ) {\n            notifyScriptableRunAlert(input: {\n                entityName: $entityName,\n                projectName: $projectName,\n                runName: $runName,\n                title: $title,\n                text: $text,\n                severity: $severity,\n                waitDuration: $waitDuration\n            }) {\n               success\n            }\n        }\n        """\n        )\n\n        response = self.gql(\n            mutation,\n            variable_values={\n                "entityName": self.settings("entity"),\n                "projectName": self.settings("project"),\n                "runName": self.current_run_id,\n                "title": title,\n                "text": text,\n                "severity": level,\n                "waitDuration": wait_duration,\n            },\n        )\n        success: bool = response["notifyScriptableRunAlert"]["success"]\n        return success\n\n    def get_sweep_state(\n        self, sweep: str, entity: str | None = None, project: str | None = None\n    ) -> SweepState:\n        state: SweepState = self.sweep(\n            sweep=sweep, entity=entity, project=project, specs="{}"\n        )["state"]\n        return state\n\n    def set_sweep_state(\n        self,\n        sweep: str,\n        state: SweepState,\n        entity: str | None = None,\n        project: str | None = None,\n    ) -> None:\n        assert state in ("RUNNING", "PAUSED", "CANCELED", "FINISHED")\n        s = self.sweep(sweep=sweep, entity=entity, project=project, specs="{}")\n        curr_state = s["state"].upper()\n        if state == "PAUSED" and curr_state not in ("PAUSED", "RUNNING"):\n            raise Exception(f"Cannot pause {curr_state.lower()} sweep.")\n        elif state != "RUNNING" and curr_state not in ("RUNNING", "PAUSED", "PENDING"):\n            raise Exception(f"Sweep already {curr_state.lower()}.")\n        sweep_id = s["id"]\n        mutation = gql(\n            """\n        mutation UpsertSweep(\n            $id: ID,\n            $state: String,\n            $entityName: String,\n            $projectName: String\n        ) {\n            upsertSweep(input: {\n                id: $id,\n                state: $state,\n                entityName: $entityName,\n                projectName: $projectName\n            }){\n                sweep {\n                    name\n                }\n            }\n        }\n        """\n        )\n        self.gql(\n            mutation,\n            variable_values={\n                "id": sweep_id,\n                "state": state,\n                "entityName": entity or self.settings("entity"),\n                "projectName": project or self.settings("project"),\n            },\n        )\n\n    def stop_sweep(\n        self,\n        sweep: str,\n        entity: str | None = None,\n        project: str | None = None,\n    ) -> None:\n        """Finish the sweep to stop running new runs and let currently running runs finish."""\n        self.set_sweep_state(\n            sweep=sweep, state="FINISHED", entity=entity, project=project\n        )\n\n    def cancel_sweep(\n        self,\n        sweep: str,\n        entity: str | None = None,\n        project: str | None = None,\n    ) -> None:\n        """Cancel the sweep to kill all running runs and stop running new runs."""\n        self.set_sweep_state(\n            sweep=sweep, state="CANCELED", entity=entity, project=project\n        )\n\n    def pause_sweep(\n        self,\n        sweep: str,\n        entity: str | None = None,\n        project: str | None = None,\n    ) -> None:\n        """Pause the sweep to temporarily stop running new runs."""\n        self.set_sweep_state(\n            sweep=sweep, state="PAUSED", entity=entity, project=project\n        )\n\n    def resume_sweep(\n        self,\n        sweep: str,\n        entity: str | None = None,\n        project: str | None = None,\n    ) -> None:\n        """Resume the sweep to continue running new runs."""\n        self.set_sweep_state(\n            sweep=sweep, state="RUNNING", entity=entity, project=project\n        )\n\n    def _status_request(self, url: str, length: int) -> requests.Response:\n        """Ask google how much we\'ve uploaded."""\n        import requests\n\n        check_httpclient_logger_handler()\n        return requests.put(\n            url=url,\n            headers={"Content-Length": "0", "Content-Range": f"bytes */{length}"},\n        )\n\n    def _flatten_edges(self, response: _Response) -> list[dict]:\n        """Return an array from the nested graphql relay structure."""\n        return [node["node"] for node in response["edges"]]\n\n    @normalize_exceptions\n    def stop_run(\n        self,\n        run_id: str,\n    ) -> bool:\n        mutation = gql(\n            """\n            mutation stopRun($id: ID!) {\n                stopRun(input: {\n                    id: $id\n                }) {\n                    clientMutationId\n                    success\n                }\n            }\n            """\n        )\n\n        response = self.gql(\n            mutation,\n            variable_values={\n                "id": run_id,\n            },\n        )\n\n        success: bool = response["stopRun"].get("success")\n\n        return success\n\n    @normalize_exceptions\n    def create_custom_chart(\n        self,\n        entity: str,\n        name: str,\n        display_name: str,\n        spec_type: str,\n        access: str,\n        spec: str | Mapping[str, Any],\n    ) -> dict[str, Any] | None:\n        if not isinstance(spec, str):\n            spec = json.dumps(spec)\n\n        mutation = gql(\n            """\n            mutation CreateCustomChart(\n                $entity: String!\n                $name: String!\n                $displayName: String!\n                $type: String!\n                $access: String!\n                $spec: JSONString!\n            ) {\n                createCustomChart(\n                    input: {\n                        entity: $entity\n                        name: $name\n                        displayName: $displayName\n                        type: $type\n                        access: $access\n                        spec: $spec\n                    }\n                ) {\n                    chart { id }\n                }\n            }\n            """\n        )\n\n        variable_values = {\n            "entity": entity,\n            "name": name,\n            "displayName": display_name,\n            "type": spec_type,\n            "access": access,\n            "spec": spec,\n        }\n\n        result: dict[str, Any] | None = self.gql(mutation, variable_values)[\n            "createCustomChart"\n        ]\n        return result\n',
            'wandb/sdk/launch/sweeps/__init__.py': 'import logging\nfrom typing import Any, Callable, Dict\n\nlog = logging.getLogger(__name__)\n\n\nclass SchedulerError(Exception):\n    """Raised when a known error occurs with wandb sweep scheduler."""\n\n\ndef _import_sweep_scheduler() -> Any:\n    from .scheduler_sweep import SweepScheduler\n\n    return SweepScheduler\n\n\n_WANDB_SCHEDULERS: Dict[str, Callable] = {\n    "wandb": _import_sweep_scheduler,\n}\n\n\ndef load_scheduler(scheduler_type: str) -> Any:\n    scheduler_type = scheduler_type.lower()\n    if scheduler_type not in _WANDB_SCHEDULERS:\n        raise SchedulerError(\n            f"The `scheduler_name` argument must be one of "\n            f"{list(_WANDB_SCHEDULERS.keys())}, got: {scheduler_type}"\n        )\n\n    log.warning(f"Loading dependencies for Scheduler of type: {scheduler_type}")\n    import_func = _WANDB_SCHEDULERS[scheduler_type]\n    return import_func()\n\n\n__all__ = [\n    "load_scheduler",\n]\n',
            'wandb/sdk/launch/sweeps/scheduler_sweep.py': '"""Scheduler for classic wandb Sweeps."""\n\nimport logging\nfrom pprint import pformat as pf\nfrom typing import Any, Dict, List, Optional\n\nimport wandb\nfrom wandb.sdk.launch.sweeps.scheduler import LOG_PREFIX, RunState, Scheduler, SweepRun\n\n_logger = logging.getLogger(__name__)\n\n\nclass SweepScheduler(Scheduler):\n    """A controller/agent that populates a Launch RunQueue from a sweeps RunQueue."""\n\n    def __init__(\n        self,\n        *args: Any,\n        **kwargs: Any,\n    ):\n        super().__init__(*args, **kwargs)\n\n    def _get_next_sweep_run(self, worker_id: int) -> Optional[SweepRun]:\n        """Called by the main scheduler execution loop.\n\n        Expected to return a properly formatted SweepRun if the scheduler\n        is alive, or None and set the appropriate scheduler state:\n\n        FAILED: self.fail_sweep()\n        STOPPED: self.stop_sweep()\n        """\n        commands: List[Dict[str, Any]] = self._get_sweep_commands(worker_id)\n        for command in commands:\n            # The command "type" can be one of "run", "resume", "stop", "exit"\n            _type = command.get("type")\n            if _type in ["exit", "stop"]:\n                self.stop_sweep()\n                return None\n\n            if _type not in ["run", "resume"]:\n                self.fail_sweep(f"AgentHeartbeat unknown command: {_type}")\n\n            _run_id: Optional[str] = command.get("run_id")\n            if not _run_id:\n                self.fail_sweep(f"No run id in agent heartbeat: {command}")\n                return None\n\n            if _run_id in self._runs:\n                wandb.termlog(f"{LOG_PREFIX}Skipping duplicate run: {_run_id}")\n                continue\n\n            return SweepRun(\n                id=_run_id,\n                state=RunState.PENDING,\n                args=command.get("args", {}),\n                logs=command.get("logs", []),\n                worker_id=worker_id,\n            )\n        return None\n\n    def _get_sweep_commands(self, worker_id: int) -> List[Dict[str, Any]]:\n        """Helper to receive sweep command from backend."""\n        # AgentHeartbeat wants a Dict of runs which are running or queued\n        _run_states: Dict[str, bool] = {}\n        for run_id, run in self._yield_runs():\n            # Filter out runs that are from a different worker thread\n            if run.worker_id == worker_id and run.state.is_alive:\n                _run_states[run_id] = True\n\n        _logger.debug(f"Sending states: \\n{pf(_run_states)}\\n")\n        commands: List[Dict[str, Any]] = self._api.agent_heartbeat(\n            agent_id=self._workers[worker_id].agent_id,\n            metrics={},\n            run_states=_run_states,\n        )\n        _logger.debug(f"AgentHeartbeat commands: \\n{pf(commands)}\\n")\n\n        return commands\n\n    def _exit(self) -> None:\n        pass\n\n    def _poll(self) -> None:\n        _logger.debug(f"_poll. _runs: {self._runs}")\n\n    def _load_state(self) -> None:\n        pass\n\n    def _save_state(self) -> None:\n        pass\n',
            'wandb/wandb_agent.py': 'import contextlib\nimport logging\nimport multiprocessing\nimport os\nimport platform\nimport queue\nimport re\nimport signal\nimport socket\nimport subprocess\nimport sys\nimport time\nimport traceback\nfrom typing import Any, Callable, Dict, List, Optional\n\nimport wandb\nfrom wandb import util\nfrom wandb.sdk import wandb_login\nfrom wandb.sdk.lib import config_util, ipython\n\nlogger = logging.getLogger(__name__)\n\n\nclass AgentError(Exception):\n    pass\n\n\nclass AgentProcess:\n    """Launch and manage a process."""\n\n    def __init__(\n        self,\n        env=None,\n        command=None,\n        function=None,\n        run_id=None,\n        in_jupyter=None,\n        forward_signals=False,\n    ):\n        self._popen = None\n        self._proc = None\n        self._finished_q = multiprocessing.Queue()\n        self._proc_killed = False\n\n        # Store original handlers\n        self._original_handlers = {}\n\n        # Set up handlers for all possible signals\n        if forward_signals:\n            skip_signals = {\n                getattr(signal, "SIGKILL", None),\n                getattr(signal, "SIGSTOP", None),\n            }\n            skip_signals.discard(None)\n            for signum in signal.valid_signals():\n                # Skip signals that can\'t be caught\n                if signum in skip_signals:\n                    continue\n                with contextlib.suppress(OSError, ValueError):\n                    # Some signals might not be supported on all platforms\n                    self._original_handlers[signum] = signal.getsignal(signum)\n                    signal.signal(signum, self._forward_signal)\n\n        if command:\n            if platform.system() == "Windows":\n                kwargs = dict(creationflags=subprocess.CREATE_NEW_PROCESS_GROUP)\n                env.pop(wandb.env.SERVICE, None)\n                # TODO: Determine if we need the same stdin workaround as POSIX case below.\n                self._popen = subprocess.Popen(command, env=env, **kwargs)\n            else:\n                if sys.version_info >= (3, 11):\n                    # preexec_fn=os.setpgrp is not thread-safe; process_group was introduced in\n                    # python 3.11 to replace it, so use that when possible\n                    kwargs = dict(process_group=0)\n                else:\n                    kwargs = dict(preexec_fn=os.setpgrp)\n                env.pop(wandb.env.SERVICE, None)\n                # Upon spawning the subprocess in a new process group, the child\'s process group is\n                # not connected to the controlling terminal\'s stdin. If it tries to access stdin,\n                # it gets a SIGTTIN and blocks until we give it the terminal, which we don\'t want\n                # to do.\n                #\n                # By using subprocess.PIPE, we give it an independent stdin. However, it will still\n                # block if it tries to read from stdin, because we\'re not writing anything to it.\n                # We immediately close the subprocess\'s stdin here so it can fail fast and get an\n                # EOF.\n                #\n                # (One situation that makes this relevant is that importing `readline` even\n                # indirectly can cause the child to attempt to access stdin, which can trigger the\n                # deadlock. In Python 3.13, `import torch` indirectly imports `readline` via `pdb`,\n                # meaning `import torch` in a run script can deadlock unless we override stdin.\n                # See https://github.com/wandb/wandb/pull/10489 description for more details.)\n                #\n                # Also, we avoid spawning a new session because that breaks preempted child process\n                # handling.\n                self._popen = subprocess.Popen(\n                    command,\n                    env=env,\n                    stdin=subprocess.PIPE,\n                    **kwargs,\n                )\n                self._popen.stdin.close()\n        elif function:\n            self._proc = multiprocessing.Process(\n                target=self._start,\n                args=(self._finished_q, env, function, run_id, in_jupyter),\n            )\n            self._proc.start()\n        else:\n            raise AgentError("Agent Process requires command or function")\n\n    def _forward_signal(self, signum, frame):\n        """Forward a received signal to any child process, mirroring the agent\'s behavior."""\n        if self._popen:\n            if platform.system() == "Windows" and signum in (\n                signal.SIGINT,\n                signal.SIGTERM,\n            ):\n                # On Windows, we can only send CTRL_BREAK_EVENT or CTRL_C_EVENT\n                self._popen.send_signal(signal.CTRL_BREAK_EVENT)\n            else:\n                self._popen.send_signal(signum)\n        if self._proc:\n            if hasattr(signal, "SIGKILL") and signum == signal.SIGKILL:\n                self._proc.kill()\n            else:\n                self._proc.send_signal(signum)\n\n        # Call original handler to ensure parent process handles signal\n        original_handler = self._original_handlers.get(signum)\n        if original_handler and callable(original_handler):\n            original_handler(signum, frame)\n\n    def _start(self, finished_q, env, function, run_id, in_jupyter):\n        if env:\n            for k, v in env.items():\n                os.environ[k] = v\n\n        # call user function\n        wandb.termlog(f"Agent Started Run: {run_id}")\n        if function:\n            function()\n        wandb.termlog(f"Agent Finished Run: {run_id}\\n")\n\n        # complete the run\n        run = wandb.run\n        if run:\n            wandb.join()\n\n        # signal that the process is finished\n        finished_q.put(True)\n\n    def poll(self):\n        if self._popen:\n            return self._popen.poll()\n        if self._proc_killed:\n            # we need to join process to prevent zombies\n            self._proc.join()\n            return True\n        try:\n            finished = self._finished_q.get(False, 0)\n            if finished:\n                return True\n        except queue.Empty:\n            pass\n        return\n\n    def wait(self):\n        if self._popen:\n            # if on windows, wait() will block and we won\'t be able to interrupt\n            if platform.system() == "Windows":\n                while True:\n                    p = self._popen.poll()\n                    if p is not None:\n                        return p\n                    time.sleep(1)\n            return self._popen.wait()\n        return self._proc.join()\n\n    def kill(self):\n        if self._popen:\n            return self._popen.kill()\n        pid = self._proc.pid\n        if pid:\n            ret = os.kill(pid, signal.SIGKILL)\n            self._proc_killed = True\n            return ret\n        return\n\n    def terminate(self):\n        if self._popen:\n            # windows terminate is too strong, send Ctrl-C instead\n            if platform.system() == "Windows":\n                return self._popen.send_signal(signal.CTRL_C_EVENT)\n            return self._popen.terminate()\n        return self._proc.terminate()\n\n\nclass Agent:\n    POLL_INTERVAL = 5\n    REPORT_INTERVAL = 0\n    KILL_DELAY = 30\n    FLAPPING_MAX_SECONDS = 60\n    FLAPPING_MAX_FAILURES = 3\n    MAX_INITIAL_FAILURES = 5\n    DEFAULT_SWEEP_COMMAND: List[str] = [\n        "${env}",\n        "${interpreter}",\n        "${program}",\n        "${args}",\n    ]\n    SWEEP_COMMAND_ENV_VAR_REGEX = re.compile(r"\\$\\{envvar\\:([A-Z0-9_]*)\\}")\n\n    def __init__(\n        self,\n        api,\n        queue,\n        sweep_id=None,\n        function=None,\n        in_jupyter=None,\n        count=None,\n        forward_signals=False,\n    ):\n        self._api = api\n        self._queue = queue\n        self._run_processes = {}  # keyed by run.id (GQL run name)\n        self._server_responses = []\n        self._sweep_id = sweep_id\n        self._in_jupyter = in_jupyter\n        self._log = []\n        self._running = True\n        self._last_report_time = None\n        self._function = function\n        self._report_interval = wandb.env.get_agent_report_interval(\n            self.REPORT_INTERVAL\n        )\n        self._kill_delay = wandb.env.get_agent_kill_delay(self.KILL_DELAY)\n        self._finished = 0\n        self._failed = 0\n        self._count = count\n        self._sweep_command = []\n        self._max_initial_failures = wandb.env.get_agent_max_initial_failures(\n            self.MAX_INITIAL_FAILURES\n        )\n        self._forward_signals = forward_signals\n        if self._report_interval is None:\n            raise AgentError("Invalid agent report interval")\n        if self._kill_delay is None:\n            raise AgentError("Invalid agent kill delay")\n        # if the directory to log to is not set, set it\n        if os.environ.get("WANDB_DIR") is None:\n            os.environ["WANDB_DIR"] = os.path.abspath(os.getcwd())\n\n    def is_flapping(self):\n        """Determine if the process is flapping.\n\n        Flapping occurs if the agents receives FLAPPING_MAX_FAILURES non-0 exit codes in\n        the first FLAPPING_MAX_SECONDS.\n        """\n        if os.getenv(wandb.env.AGENT_DISABLE_FLAPPING) == "true":\n            return False\n        if time.time() < wandb.START_TIME + self.FLAPPING_MAX_SECONDS:\n            return self._failed >= self.FLAPPING_MAX_FAILURES\n\n    def is_failing(self):\n        return (\n            self._failed >= self._finished\n            and self._max_initial_failures <= self._failed\n        )\n\n    def run(self):  # noqa: C901\n        # TODO: catch exceptions, handle errors, show validation warnings, and make more generic\n        import yaml\n\n        sweep_obj = self._api.sweep(self._sweep_id, "{}")\n        if sweep_obj:\n            sweep_yaml = sweep_obj.get("config")\n            if sweep_yaml:\n                sweep_config = yaml.safe_load(sweep_yaml)\n                if sweep_config:\n                    sweep_command = sweep_config.get("command")\n                    if sweep_command and isinstance(sweep_command, list):\n                        self._sweep_command = sweep_command\n\n        # TODO: include sweep ID\n        agent = self._api.register_agent(socket.gethostname(), sweep_id=self._sweep_id)\n        agent_id = agent["id"]\n\n        try:\n            while self._running:\n                commands = util.read_many_from_queue(\n                    self._queue, 100, self.POLL_INTERVAL\n                )\n                for command in commands:\n                    command["resp_queue"].put(self._process_command(command))\n\n                now = util.stopwatch_now()\n                if self._last_report_time is None or (\n                    self._report_interval != 0\n                    and now > self._last_report_time + self._report_interval\n                ):\n                    logger.info("Running runs: %s", list(self._run_processes.keys()))\n                    self._last_report_time = now\n                run_status = {}\n                for run_id, run_process in list(self._run_processes.items()):\n                    poll_result = run_process.poll()\n                    if poll_result is None:\n                        run_status[run_id] = True\n                        continue\n                    elif (\n                        not isinstance(poll_result, bool)\n                        and isinstance(poll_result, int)\n                        and poll_result > 0\n                    ):\n                        self._failed += 1\n                        if self.is_flapping():\n                            logger.error(\n                                "Detected %i failed runs in the first %i seconds, shutting down.",\n                                self.FLAPPING_MAX_FAILURES,\n                                self.FLAPPING_MAX_SECONDS,\n                            )\n                            logger.info(\n                                "To disable this check set WANDB_AGENT_DISABLE_FLAPPING=true"\n                            )\n                            self._running = False\n                            break\n                        if self.is_failing():\n                            logger.error(\n                                "Detected %i failed runs in a row, shutting down.",\n                                self._max_initial_failures,\n                            )\n                            logger.info(\n                                "To change this value set WANDB_AGENT_MAX_INITIAL_FAILURES=val"\n                            )\n                            self._running = False\n                            break\n                    logger.info("Cleaning up finished run: %s", run_id)\n\n                    # wandb.teardown() was added with wandb service and is a hammer to make\n                    # sure that active runs are finished before moving on to another agent run\n                    #\n                    # In the future, a lighter weight way to implement this could be to keep a\n                    # service process open for all the agent instances and inform_finish when\n                    # the run should be marked complete.  This however could require\n                    # inform_finish on every run created by this process.\n                    if hasattr(wandb, "teardown"):\n                        exit_code = 0\n                        if isinstance(poll_result, int):\n                            exit_code = poll_result\n                        elif isinstance(poll_result, bool):\n                            exit_code = -1\n                        wandb.teardown(exit_code)\n\n                    del self._run_processes[run_id]\n                    self._last_report_time = None\n                    self._finished += 1\n\n                if self._count and self._finished >= self._count or not self._running:\n                    self._running = False\n                    continue\n\n                commands = self._api.agent_heartbeat(agent_id, {}, run_status)\n\n                # TODO: send _server_responses\n                self._server_responses = []\n                for command in commands:\n                    self._server_responses.append(self._process_command(command))\n\n        except KeyboardInterrupt:\n            try:\n                wandb.termlog(\n                    "Ctrl-c pressed. Waiting for runs to end. Press ctrl-c again to terminate them."\n                )\n                for _, run_process in self._run_processes.items():\n                    run_process.wait()\n            except KeyboardInterrupt:\n                pass\n        finally:\n            try:\n                if not self._in_jupyter:\n                    wandb.termlog("Terminating and syncing runs. Press ctrl-c to kill.")\n                for _, run_process in self._run_processes.items():\n                    try:\n                        run_process.terminate()\n                    except OSError:\n                        pass  # if process is already dead\n                for _, run_process in self._run_processes.items():\n                    run_process.wait()\n            except KeyboardInterrupt:\n                wandb.termlog("Killing runs and quitting.")\n                for _, run_process in self._run_processes.items():\n                    try:\n                        run_process.kill()\n                    except OSError:\n                        pass  # if process is already dead\n\n    def _process_command(self, command):\n        logger.info(\n            "Agent received command: %s"\n            % (command["type"] if "type" in command else "Unknown")\n        )\n        response = {\n            "id": command.get("id"),\n            "result": None,\n        }\n        try:\n            command_type = command["type"]\n            if command_type == "run":\n                result = self._command_run(command)\n            elif command_type == "stop":\n                result = self._command_stop(command)\n            elif command_type == "exit":\n                result = self._command_exit(command)\n            elif command_type == "resume":\n                result = self._command_run(command)\n            else:\n                raise AgentError(f"No such command: {command_type}")  # noqa: TRY301\n            response["result"] = result\n        except Exception:\n            logger.exception("Exception while processing command: %s", command)\n            ex_type, ex, tb = sys.exc_info()\n            response["exception"] = f"{ex_type.__name__}: {str(ex)}"\n            response["traceback"] = traceback.format_tb(tb)\n            del tb\n\n        self._log.append((command, response))\n\n        return response\n\n    def _command_run(self, command):\n        from wandb.sdk.launch.sweeps import utils as sweep_utils\n\n        logger.info(\n            "Agent starting run with config:\\n"\n            + "\\n".join(\n                ["\\t{}: {}".format(k, v["value"]) for k, v in command["args"].items()]\n            )\n        )\n        if self._in_jupyter:\n            wandb.termlog(\n                f"Agent Starting Run: {command.get(\'run_id\')} with config:\\n"\n                + "\\n".join(\n                    [f"\\t{k}: {v[\'value\']}" for k, v in command["args"].items()]\n                )\n            )\n\n        # Setup sweep command\n        sweep_command: List[str] = sweep_utils.create_sweep_command(self._sweep_command)\n\n        run_id = command.get("run_id")\n        sweep_id = os.environ.get(wandb.env.SWEEP_ID)\n        # TODO(jhr): move into settings\n        config_file = os.path.join(\n            "wandb", "sweep-" + sweep_id, "config-" + run_id + ".yaml"\n        )\n        json_file = os.path.join(\n            "wandb", "sweep-" + sweep_id, "config-" + run_id + ".json"\n        )\n\n        os.environ[wandb.env.RUN_ID] = run_id\n\n        base_dir = os.environ.get(wandb.env.DIR, "")\n        sweep_param_path = os.path.join(base_dir, config_file)\n        os.environ[wandb.env.SWEEP_PARAM_PATH] = sweep_param_path\n        config_util.save_config_file_from_dict(sweep_param_path, command["args"])\n\n        env = dict(os.environ)\n\n        sweep_vars: Dict[str, Any] = sweep_utils.create_sweep_command_args(command)\n\n        if "${args_json_file}" in sweep_command:\n            with open(json_file, "w") as fp:\n                fp.write(sweep_vars["args_json"][0])\n\n        if self._function:\n            # make sure that each run regenerates setup singleton\n            wandb.teardown()\n            proc = AgentProcess(\n                function=self._function,\n                env=env,\n                run_id=run_id,\n                in_jupyter=self._in_jupyter,\n                forward_signals=self._forward_signals,\n            )\n        else:\n            sweep_vars["interpreter"] = ["python"]\n            sweep_vars["program"] = [command["program"]]\n            sweep_vars["args_json_file"] = [json_file]\n            if not platform.system() == "Windows":\n                sweep_vars["env"] = ["/usr/bin/env"]\n            command_list = []\n            for c in sweep_command:\n                c = str(c)\n                if c.startswith("${") and c.endswith("}"):\n                    replace_list = sweep_vars.get(c[2:-1])\n                    command_list += replace_list or []\n                else:\n                    command_list += [c]\n            logger.info(\n                "About to run command: {}".format(\n                    " ".join(f\'"{c}"\' if " " in c else c for c in command_list)\n                )\n            )\n            proc = AgentProcess(\n                command=command_list, env=env, forward_signals=self._forward_signals\n            )\n        self._run_processes[run_id] = proc\n\n        # we keep track of when we sent the sigterm to give processes a chance\n        # to handle the signal before sending sigkill every heartbeat\n        self._run_processes[run_id].last_sigterm_time = None\n        self._last_report_time = None\n\n    def _command_stop(self, command):\n        run_id = command["run_id"]\n        if run_id in self._run_processes:\n            proc = self._run_processes[run_id]\n            now = util.stopwatch_now()\n            if proc.last_sigterm_time is None:\n                proc.last_sigterm_time = now\n                logger.info("Stop: %s", run_id)\n                try:\n                    proc.terminate()\n                except OSError:  # if process is already dead\n                    pass\n            elif now > proc.last_sigterm_time + self._kill_delay:\n                logger.info("Kill: %s", run_id)\n                try:\n                    proc.kill()\n                except OSError:  # if process is already dead\n                    pass\n        else:\n            logger.error("Run %s not running", run_id)\n\n    def _command_exit(self, command):\n        logger.info("Received exit command. Killing runs and quitting.")\n        for _, proc in self._run_processes.items():\n            try:\n                proc.kill()\n            except OSError:\n                # process is already dead\n                pass\n        self._running = False\n\n\nclass AgentApi:\n    def __init__(self, queue):\n        self._queue = queue\n        self._command_id = 0\n        self._multiproc_manager = multiprocessing.Manager()\n\n    def command(self, command):\n        command["origin"] = "local"\n        command["id"] = f"local-{self._command_id}"\n        self._command_id += 1\n        resp_queue = self._multiproc_manager.Queue()\n        command["resp_queue"] = resp_queue\n        self._queue.put(command)\n        result = resp_queue.get()\n        print("result:", result)  # noqa: T201\n        if "exception" in result:\n            print("Exception occurred while running command")  # noqa: T201\n            for line in result["traceback"]:\n                print(line.strip())  # noqa: T201\n            print(result["exception"])  # noqa: T201\n        return result\n\n\ndef run_agent(\n    sweep_id,\n    function=None,\n    in_jupyter=None,\n    entity=None,\n    project=None,\n    count=None,\n    forward_signals=False,\n):\n    from wandb.apis import InternalApi\n    from wandb.sdk.launch.sweeps import utils as sweep_utils\n\n    parts = dict(entity=entity, project=project, name=sweep_id)\n    err = sweep_utils.parse_sweep_id(parts)\n    if err:\n        wandb.termerror(err)\n        return\n    entity = parts.get("entity") or entity\n    project = parts.get("project") or project\n    sweep_id = parts.get("name") or sweep_id\n\n    if entity:\n        wandb.env.set_entity(entity)\n    if project:\n        wandb.env.set_project(project)\n    if sweep_id:\n        # TODO(jhr): remove when jobspec is merged\n        os.environ[wandb.env.SWEEP_ID] = sweep_id\n    logger.setLevel(logging.DEBUG)\n    ch = logging.StreamHandler()\n    log_level = logging.DEBUG\n    if in_jupyter:\n        log_level = logging.ERROR\n    ch.setLevel(log_level)\n    formatter = logging.Formatter(\n        "%(asctime)s - %(name)s - %(levelname)s - %(message)s"\n    )\n    ch.setFormatter(formatter)\n    try:\n        logger.addHandler(ch)\n\n        api = InternalApi()\n        queue = multiprocessing.Queue()\n        agent = Agent(\n            api,\n            queue,\n            sweep_id=sweep_id,\n            function=function,\n            in_jupyter=in_jupyter,\n            count=count,\n            forward_signals=forward_signals,\n        )\n        agent.run()\n    finally:\n        # make sure we remove the logging handler (important for jupyter notebooks)\n        logger.removeHandler(ch)\n\n\ndef agent(\n    sweep_id: str,\n    function: Optional[Callable] = None,\n    entity: Optional[str] = None,\n    project: Optional[str] = None,\n    count: Optional[int] = None,\n    forward_signals: bool = False,\n) -> None:\n    """Start one or more sweep agents.\n\n    The sweep agent uses the `sweep_id` to know which sweep it\n    is a part of, what function to execute, and (optionally) how\n    many agents to run.\n\n    Args:\n        sweep_id: The unique identifier for a sweep. A sweep ID\n            is generated by W&B CLI or Python SDK.\n        function: A function to call instead of the "program"\n            specified in the sweep config.\n        entity: The username or team name where you want to send W&B\n            runs created by the sweep to. Ensure that the entity you\n            specify already exists. If you don\'t specify an entity,\n            the run will be sent to your default entity,\n            which is usually your username.\n        project: The name of the project where W&B runs created from\n            the sweep are sent to. If the project is not specified, the\n            run is sent to a project labeled "Uncategorized".\n        count: The number of sweep config trials to try.\n        forward_signals: Whether to forward signals the agent receives\n            to the child processes. Only supported by CLI agent.\n\n    """\n    from wandb.agents.pyagent import pyagent\n\n    global _INSTANCES\n    _INSTANCES += 1\n    try:\n        # make sure we are logged in\n        wandb_login._login(_silent=True)\n        if function:\n            return pyagent(sweep_id, function, entity, project, count)\n        return run_agent(\n            sweep_id,\n            function=function,\n            in_jupyter=ipython.in_jupyter(),\n            entity=entity,\n            project=project,\n            count=count,\n            forward_signals=forward_signals,\n        )\n    finally:\n        _INSTANCES -= 1\n\n\n_INSTANCES = 0\n\n\ndef _is_running():\n    return bool(_INSTANCES)\n',
        }
